client/src/pages/admin/playable-sets.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { 
  Table, 
  TableBody, 
  TableCell, 
  TableHead, 
  TableHeader, 
  TableRow 
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { 
  Loader2, 
  Plus, 
  Edit, 
  RefreshCw,
  Download,
  Search,
  Layers,
  CheckCircle,
  XCircle,
  Clock,
  AlertCircle,
  ScanSearch,
  UserX
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";

interface GameSet {
  id: string;
  sport: string;
  brand: string;
  year: number;
  setName: string;
  league: string | null;
  isActive: boolean;
  cardhedgeSetQuery: string | null;
  cardhedgeCategory: string | null;
  cardsImportedCount: number;
  lastImportAt: string | null;
  marketplaceKeywords: string[];
  createdAt: string;
}

interface ImportRun {
  id: string;
  gameSetId: string;
  status: string;
  startedAt: string;
  finishedAt: string | null;
  pageSize: number;
  pagesFetched: number;
  cardsImported: number;
  error: string | null;
}

interface CardHedgeSearchResult {
  cards: Array<{
    card_id: string;
    description: string;
    player: string;
    set: string;
    number: string;
    image: string;
  }>;
  page: number;
  pages: number;
  total: number;
}

interface SetFormData {
  sport: string;
  brand: string;
  year: number;
  setName: string;
  cardhedgeSetQuery: string;
  cardhedgeCategory: string;
  isActive: boolean;
}

interface SetLookupResult {
  setName: string;
  cardCount: number;
  category: string;
}

const defaultFormData: SetFormData = {
  sport: "baseball",
  brand: "",
  year: new Date().getFullYear(),
  setName: "",
  cardhedgeSetQuery: "",
  cardhedgeCategory: "Baseball",
  isActive: true,
};

const sports = ["baseball", "basketball", "football", "hockey"];
const categories = ["Baseball", "Basketball", "Football", "Hockey"];

export default function AdminPlayableSets() {
  const { toast } = useToast();
  const [showDialog, setShowDialog] = useState(false);
  const [showSearchDialog, setShowSearchDialog] = useState(false);
  const [showSetLookupDialog, setShowSetLookupDialog] = useState(false);
  const [editingSet, setEditingSet] = useState<GameSet | null>(null);
  const [formData, setFormData] = useState<SetFormData>(defaultFormData);
  const [searchQuery, setSearchQuery] = useState("");
  const [searchCategory, setSearchCategory] = useState("Baseball");
  const [selectedSetForImport, setSelectedSetForImport] = useState<GameSet | null>(null);
  const [setLookupQuery, setSetLookupQuery] = useState("");
  const [setLookupResults, setSetLookupResults] = useState<SetLookupResult[]>([]);

  const { data: gameSets, isLoading } = useQuery<GameSet[]>({
    queryKey: ["/api/admin/game-sets"],
    queryFn: async () => {
      const res = await fetch("/api/admin/game-sets", { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch game sets");
      return res.json();
    },
  });

  const searchMutation = useMutation({
    mutationFn: async ({ search, category }: { search: string; category: string }) => {
      const res = await apiRequest("POST", "/api/admin/cardhedge/search", {
        search,
        category,
        page_size: 20,
      });
      return res.json() as Promise<CardHedgeSearchResult>;
    },
    onError: (error: Error) => {
      toast({ title: "Search failed", description: error.message, variant: "destructive" });
    },
  });

  const setLookupMutation = useMutation({
    mutationFn: async ({ search, category }: { search: string; category: string }) => {
      const res = await apiRequest("POST", "/api/admin/cardhedge/search", {
        search,
        category,
        page_size: 100,
      });
      return res.json() as Promise<CardHedgeSearchResult>;
    },
    onSuccess: (data) => {
      const setMap = new Map<string, { count: number; category: string }>();
      data.cards?.forEach((card) => {
        if (card.set) {
          const existing = setMap.get(card.set);
          setMap.set(card.set, {
            count: (existing?.count || 0) + 1,
            category: searchCategory,
          });
        }
      });
      const results: SetLookupResult[] = Array.from(setMap.entries()).map(([setName, info]) => ({
        setName,
        cardCount: info.count,
        category: info.category,
      }));
      results.sort((a, b) => b.cardCount - a.cardCount);
      setSetLookupResults(results);
    },
    onError: (error: Error) => {
      toast({ title: "Lookup failed", description: error.message, variant: "destructive" });
    },
  });

  const createMutation = useMutation({
    mutationFn: async (data: SetFormData) => {
      return apiRequest("POST", "/api/admin/playable-sets", data);
    },
    onSuccess: () => {
      toast({ title: "Set created", description: "The playable set has been created" });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      closeDialog();
    },
    onError: (error: Error) => {
      toast({ title: "Error", description: error.message || "Failed to create set", variant: "destructive" });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<SetFormData> }) => {
      return apiRequest("PUT", `/api/admin/playable-sets/${id}`, data);
    },
    onSuccess: () => {
      toast({ title: "Set updated", description: "The playable set has been updated" });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      closeDialog();
    },
    onError: (error: Error) => {
      toast({ title: "Error", description: error.message || "Failed to update set", variant: "destructive" });
    },
  });

  const importMutation = useMutation({
    mutationFn: async (setId: string) => {
      const res = await apiRequest("POST", `/api/admin/playable-sets/${setId}/import`, {
        page_size: 100,
      });
      return res.json();
    },
    onSuccess: (data) => {
      const playable = data.playableCount ?? data.cardsImported;
      const title = playable === 0 ? "Import Warning" : "Import completed";
      const variant = playable === 0 ? "destructive" : undefined;
      toast({ 
        title,
        description: `Imported ${playable} playable cards (${data.cardsImported} fetched)`,
        variant,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      setSelectedSetForImport(null);
    },
    onError: (error: Error) => {
      toast({ title: "Import failed", description: error.message, variant: "destructive" });
      setSelectedSetForImport(null);
    },
  });

  const [showPurgeConfirm, setShowPurgeConfirm] = useState(false);
  const [purgeTargetSet, setPurgeTargetSet] = useState<GameSet | null>(null);
  const [rescanningSetId, setRescanningSetId] = useState<string | null>(null);
  const [scanningMismatchesSetId, setScanningMismatchesSetId] = useState<string | null>(null);

  const purgeReimportMutation = useMutation({
    mutationFn: async (setId: string) => {
      const res = await apiRequest("POST", `/api/admin/playable-sets/${setId}/purge-reimport`, {
        page_size: 100,
      });
      return res.json();
    },
    onSuccess: (data) => {
      const playable = data.playableCount ?? data.cardsImported;
      const title = playable === 0 ? "Reimport Warning" : "Purge & Reimport completed";
      const variant = playable === 0 ? "destructive" : undefined;
      toast({ 
        title,
        description: `Imported ${playable} playable cards (${data.cardsImported} fetched, ${data.cardsPurged} purged)`,
        variant,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      setShowPurgeConfirm(false);
      setPurgeTargetSet(null);
    },
    onError: (error: Error) => {
      toast({ title: "Purge & Reimport failed", description: error.message, variant: "destructive" });
      setShowPurgeConfirm(false);
      setPurgeTargetSet(null);
    },
  });

  const rescanSilhouettesMutation = useMutation({
    mutationFn: async (setId: string) => {
      setRescanningSetId(setId);
      const res = await apiRequest("POST", `/api/admin/game-sets/${setId}/rescan-silhouettes`, {});
      return res.json();
    },
    onSuccess: (data) => {
      const silhouettes = data.silhouettesFound || 0;
      const scanned = data.scanned || 0;
      toast({ 
        title: "Silhouette Scan Complete",
        description: `Scanned ${scanned} cards, found and blocked ${silhouettes} silhouettes`,
        variant: silhouettes > 0 ? "default" : undefined,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      setRescanningSetId(null);
    },
    onError: (error: Error) => {
      toast({ title: "Rescan failed", description: error.message, variant: "destructive" });
      setRescanningSetId(null);
    },
  });

  const handleRescanSilhouettes = (set: GameSet) => {
    rescanSilhouettesMutation.mutate(set.id);
  };

  const scanMismatchesMutation = useMutation({
    mutationFn: async (setId: string) => {
      setScanningMismatchesSetId(setId);
      const res = await apiRequest("POST", `/api/admin/game-sets/${setId}/detect-player-mismatches`, {
        limit: 100,
        autoQuarantine: true,
      });
      return res.json();
    },
    onSuccess: (data) => {
      const mismatches = data.mismatches || 0;
      const checked = data.checked || 0;
      const quarantined = data.quarantined || 0;
      toast({ 
        title: "Player Mismatch Scan Complete",
        description: mismatches > 0 
          ? `Scanned ${checked} cards, found and quarantined ${quarantined} mismatches`
          : `Scanned ${checked} cards, no mismatches found`,
        variant: mismatches > 0 ? "default" : undefined,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-sets"] });
      setScanningMismatchesSetId(null);
    },
    onError: (error: Error) => {
      toast({ title: "Mismatch scan failed", description: error.message, variant: "destructive" });
      setScanningMismatchesSetId(null);
    },
  });

  const handleScanMismatches = (set: GameSet) => {
    scanMismatchesMutation.mutate(set.id);
  };

  const handlePurgeReimport = (set: GameSet) => {
    setPurgeTargetSet(set);
    setShowPurgeConfirm(true);
  };

  const confirmPurgeReimport = () => {
    if (purgeTargetSet) {
      purgeReimportMutation.mutate(purgeTargetSet.id);
    }
  };

  const closeDialog = () => {
    setShowDialog(false);
    setEditingSet(null);
    setFormData(defaultFormData);
  };

  const openCreateDialog = () => {
    setFormData(defaultFormData);
    setEditingSet(null);
    setShowDialog(true);
  };

  const openEditDialog = (set: GameSet) => {
    setEditingSet(set);
    setFormData({
      sport: set.sport,
      brand: set.brand,
      year: set.year,
      setName: set.setName,
      cardhedgeSetQuery: set.cardhedgeSetQuery || "",
      cardhedgeCategory: set.cardhedgeCategory || "Baseball",
      isActive: set.isActive,
    });
    setShowDialog(true);
  };

  const handleSubmit = () => {
    if (editingSet) {
      updateMutation.mutate({ id: editingSet.id, data: formData });
    } else {
      createMutation.mutate(formData);
    }
  };

  const handleImport = (set: GameSet) => {
    if (!set.cardhedgeSetQuery) {
      toast({ 
        title: "Cannot import", 
        description: "This set has no Card Hedge query configured", 
        variant: "destructive" 
      });
      return;
    }
    setSelectedSetForImport(set);
    importMutation.mutate(set.id);
  };

  const handleSearch = () => {
    if (!searchQuery.trim()) return;
    searchMutation.mutate({ search: searchQuery, category: searchCategory });
  };

  const openSetLookupDialog = () => {
    setSetLookupQuery(`${formData.year} ${formData.brand}`.trim() || `${formData.sport}`);
    setSetLookupResults([]);
    setShowSetLookupDialog(true);
  };

  const handleSetLookup = () => {
    if (!setLookupQuery.trim()) return;
    setLookupMutation.mutate({ search: setLookupQuery, category: formData.cardhedgeCategory });
  };

  const selectSetFromLookup = (setName: string) => {
    setFormData({ ...formData, cardhedgeSetQuery: setName });
    setShowSetLookupDialog(false);
    toast({ title: "Set selected", description: `"${setName}" has been applied` });
  };

  const getStatusBadge = (set: GameSet) => {
    if (set.cardsImportedCount > 0) {
      return <Badge variant="default" className="bg-green-600">{set.cardsImportedCount} cards</Badge>;
    }
    return <Badge variant="secondary">No cards</Badge>;
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold" data-testid="text-page-title">Playable Sets</h1>
          <p className="text-muted-foreground">Manage card sets for gameplay from Card Hedge</p>
        </div>
        <div className="flex gap-2">
          <Button 
            variant="outline" 
            onClick={() => setShowSearchDialog(true)}
            data-testid="button-search-cardhedge"
          >
            <Search className="h-4 w-4 mr-2" />
            Search Card Hedge
          </Button>
          <Button onClick={openCreateDialog} data-testid="button-create-set">
            <Plus className="h-4 w-4 mr-2" />
            Create Set
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Layers className="h-5 w-5" />
            Game Sets
          </CardTitle>
          <CardDescription>
            Configure sets with Card Hedge queries and import cards for gameplay
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Set</TableHead>
                <TableHead>Sport</TableHead>
                <TableHead>Year</TableHead>
                <TableHead>Card Hedge Query</TableHead>
                <TableHead>Cards</TableHead>
                <TableHead>Last Import</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {gameSets?.map((set) => (
                <TableRow key={set.id} data-testid={`row-set-${set.id}`}>
                  <TableCell className="font-medium">
                    {set.brand} {set.setName}
                  </TableCell>
                  <TableCell className="capitalize">{set.sport}</TableCell>
                  <TableCell>{set.year}</TableCell>
                  <TableCell className="max-w-[200px] truncate text-muted-foreground">
                    {set.cardhedgeSetQuery || <span className="text-yellow-600">Not configured</span>}
                  </TableCell>
                  <TableCell>{getStatusBadge(set)}</TableCell>
                  <TableCell className="text-muted-foreground">
                    {set.lastImportAt 
                      ? format(new Date(set.lastImportAt), "MMM d, yyyy h:mm a")
                      : "Never"
                    }
                  </TableCell>
                  <TableCell>
                    {set.isActive 
                      ? <Badge variant="outline" className="text-green-600 border-green-600">Active</Badge>
                      : <Badge variant="outline" className="text-gray-500">Inactive</Badge>
                    }
                  </TableCell>
                  <TableCell>
                    <div className="flex gap-1">
                      <Button 
                        variant="ghost" 
                        size="icon"
                        onClick={() => openEditDialog(set)}
                        data-testid={`button-edit-${set.id}`}
                      >
                        <Edit className="h-4 w-4" />
                      </Button>
                      <Button 
                        variant="ghost" 
                        size="icon"
                        onClick={() => handleImport(set)}
                        disabled={importMutation.isPending && selectedSetForImport?.id === set.id}
                        data-testid={`button-import-${set.id}`}
                        title="Import cards"
                      >
                        {importMutation.isPending && selectedSetForImport?.id === set.id 
                          ? <Loader2 className="h-4 w-4 animate-spin" />
                          : <Download className="h-4 w-4" />
                        }
                      </Button>
                      {set.cardhedgeSetQuery && (
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => handlePurgeReimport(set)}
                          disabled={purgeReimportMutation.isPending && purgeTargetSet?.id === set.id}
                          data-testid={`button-purge-reimport-${set.id}`}
                          title="Purge & Re-import (clean slate)"
                        >
                          {purgeReimportMutation.isPending && purgeTargetSet?.id === set.id 
                            ? <Loader2 className="h-4 w-4 animate-spin" />
                            : <RefreshCw className="h-4 w-4" />
                          }
                        </Button>
                      )}
                      {set.cardsImportedCount > 0 && (
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => handleRescanSilhouettes(set)}
                          disabled={rescanningSetId === set.id}
                          data-testid={`button-rescan-silhouettes-${set.id}`}
                          title="Rescan for silhouette placeholders"
                        >
                          {rescanningSetId === set.id 
                            ? <Loader2 className="h-4 w-4 animate-spin" />
                            : <ScanSearch className="h-4 w-4" />
                          }
                        </Button>
                      )}
                      {set.cardsImportedCount > 0 && (
                        <Button 
                          variant="ghost" 
                          size="icon"
                          onClick={() => handleScanMismatches(set)}
                          disabled={scanningMismatchesSetId === set.id}
                          data-testid={`button-scan-mismatches-${set.id}`}
                          title="Scan for player/image mismatches"
                        >
                          {scanningMismatchesSetId === set.id 
                            ? <Loader2 className="h-4 w-4 animate-spin" />
                            : <UserX className="h-4 w-4" />
                          }
                        </Button>
                      )}
                    </div>
                  </TableCell>
                </TableRow>
              ))}
              {(!gameSets || gameSets.length === 0) && (
                <TableRow>
                  <TableCell colSpan={8} className="text-center text-muted-foreground py-8">
                    No game sets configured. Create one to get started.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      <Dialog open={showDialog} onOpenChange={setShowDialog}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{editingSet ? "Edit Set" : "Create Set"}</DialogTitle>
            <DialogDescription>
              {editingSet 
                ? "Update the playable set configuration"
                : "Create a new playable set for Card Hedge import"
              }
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="sport">Sport</Label>
                <Select 
                  value={formData.sport} 
                  onValueChange={(v) => {
                    const capitalizedCategory = v.charAt(0).toUpperCase() + v.slice(1);
                    setFormData({ ...formData, sport: v, cardhedgeCategory: capitalizedCategory });
                  }}
                >
                  <SelectTrigger data-testid="select-sport">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {sports.map((s) => (
                      <SelectItem key={s} value={s} className="capitalize">{s}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label htmlFor="year">Year</Label>
                <Input 
                  id="year"
                  type="number" 
                  value={formData.year}
                  onChange={(e) => setFormData({ ...formData, year: parseInt(e.target.value) || 0 })}
                  data-testid="input-year"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="brand">Brand</Label>
              <Input 
                id="brand"
                value={formData.brand}
                onChange={(e) => setFormData({ ...formData, brand: e.target.value })}
                placeholder="Topps, Upper Deck, Panini..."
                data-testid="input-brand"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="setName">Set Name</Label>
              <Input 
                id="setName"
                value={formData.setName}
                onChange={(e) => setFormData({ ...formData, setName: e.target.value })}
                placeholder="1987 Topps Baseball"
                data-testid="input-set-name"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="cardhedgeSetQuery">Card Hedge Set Query</Label>
              <div className="flex gap-2">
                <Input 
                  id="cardhedgeSetQuery"
                  value={formData.cardhedgeSetQuery}
                  onChange={(e) => setFormData({ ...formData, cardhedgeSetQuery: e.target.value })}
                  placeholder="Exact set name for Card Hedge API"
                  data-testid="input-cardhedge-query"
                  className="flex-1"
                />
                <Button 
                  type="button" 
                  variant="outline" 
                  onClick={openSetLookupDialog}
                  data-testid="button-lookup-set"
                >
                  <Search className="h-4 w-4" />
                </Button>
              </div>
              <p className="text-xs text-muted-foreground">
                Click the search button to find and select the exact set name
              </p>
            </div>

            <div className="space-y-2">
              <Label htmlFor="cardhedgeCategory">Card Hedge Category</Label>
              <Select 
                value={formData.cardhedgeCategory} 
                onValueChange={(v) => setFormData({ ...formData, cardhedgeCategory: v })}
              >
                <SelectTrigger data-testid="select-category">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {categories.map((c) => (
                    <SelectItem key={c} value={c}>{c}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex items-center gap-2">
              <Switch 
                id="isActive"
                checked={formData.isActive}
                onCheckedChange={(checked) => setFormData({ ...formData, isActive: checked })}
                data-testid="switch-is-active"
              />
              <Label htmlFor="isActive">Active</Label>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={closeDialog}>Cancel</Button>
            <Button 
              onClick={handleSubmit}
              disabled={createMutation.isPending || updateMutation.isPending}
              data-testid="button-submit-set"
            >
              {(createMutation.isPending || updateMutation.isPending) && (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              )}
              {editingSet ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={showSearchDialog} onOpenChange={setShowSearchDialog}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Search Card Hedge</DialogTitle>
            <DialogDescription>
              Find cards and set names from the Card Hedge API
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="flex gap-2">
              <div className="flex-1">
                <Input 
                  placeholder="Search for cards, players, or sets..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && handleSearch()}
                  data-testid="input-search-query"
                />
              </div>
              <Select value={searchCategory} onValueChange={setSearchCategory}>
                <SelectTrigger className="w-[150px]">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {categories.map((c) => (
                    <SelectItem key={c} value={c}>{c}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Button 
                onClick={handleSearch}
                disabled={searchMutation.isPending}
                data-testid="button-search"
              >
                {searchMutation.isPending 
                  ? <Loader2 className="h-4 w-4 animate-spin" />
                  : <Search className="h-4 w-4" />
                }
              </Button>
            </div>

            {searchMutation.data && (
              <div className="space-y-2">
                <p className="text-sm text-muted-foreground">
                  Found {searchMutation.data.total || searchMutation.data.cards?.length || 0} results
                </p>
                <div className="border rounded-md divide-y max-h-[400px] overflow-y-auto">
                  {searchMutation.data.cards?.map((card, i) => (
                    <div key={card.card_id || i} className="p-3 flex gap-3">
                      {card.image && (
                        <img 
                          src={card.image.startsWith("//") ? `https:${card.image}` : card.image}
                          alt={card.description}
                          className="w-16 h-20 object-cover rounded"
                        />
                      )}
                      <div className="flex-1 min-w-0">
                        <p className="font-medium truncate">{card.description}</p>
                        <p className="text-sm text-muted-foreground">{card.player}</p>
                        <p className="text-xs text-muted-foreground">Set: {card.set}</p>
                        <p className="text-xs text-muted-foreground">#{card.number}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={showSetLookupDialog} onOpenChange={setShowSetLookupDialog}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Find Card Hedge Set Name</DialogTitle>
            <DialogDescription>
              Search for sets to find the exact name for the Card Hedge API
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="text-sm text-muted-foreground">
              Searching in: <Badge variant="secondary" data-testid="badge-lookup-category">{formData.cardhedgeCategory}</Badge>
            </div>
            <div className="flex flex-wrap gap-2">
              <Input 
                placeholder="Search by year, brand, or set name..."
                value={setLookupQuery}
                onChange={(e) => setSetLookupQuery(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleSetLookup()}
                data-testid="input-set-lookup-query"
                className="flex-1 min-w-[200px]"
              />
              <Button 
                onClick={handleSetLookup}
                disabled={setLookupMutation.isPending}
                data-testid="button-set-lookup-search"
              >
                {setLookupMutation.isPending 
                  ? <Loader2 className="h-4 w-4 animate-spin" />
                  : <Search className="h-4 w-4" />
                }
              </Button>
            </div>

            {setLookupResults.length > 0 && (
              <div className="space-y-2">
                <p className="text-sm text-muted-foreground">
                  Found {setLookupResults.length} set name{setLookupResults.length !== 1 ? "s" : ""}. Click to select:
                </p>
                <div className="border rounded-md p-2 space-y-1 max-h-[300px] overflow-y-auto">
                  {setLookupResults.map((result, i) => (
                    <Button
                      key={`${result.setName}-${i}`}
                      type="button"
                      variant="ghost"
                      className="w-full justify-between gap-2"
                      onClick={() => selectSetFromLookup(result.setName)}
                      data-testid={`button-select-set-${i}`}
                    >
                      <span className="font-medium truncate">{result.setName}</span>
                      <Badge variant="secondary" className="shrink-0">
                        {result.cardCount} card{result.cardCount !== 1 ? "s" : ""}
                      </Badge>
                    </Button>
                  ))}
                </div>
              </div>
            )}

            {setLookupMutation.isSuccess && setLookupResults.length === 0 && (
              <p className="text-sm text-muted-foreground text-center py-4">
                No sets found. Try a different search term.
              </p>
            )}
          </div>

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setShowSetLookupDialog(false)}
              data-testid="button-cancel-lookup"
            >
              Cancel
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={showPurgeConfirm} onOpenChange={setShowPurgeConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Purge & Re-import Cards</DialogTitle>
            <DialogDescription>
              This will delete all {purgeTargetSet?.cardsImportedCount || 0} existing cards 
              from "{purgeTargetSet?.setName}" and re-import fresh cards from Card Hedge with improved sport filtering.
            </DialogDescription>
          </DialogHeader>

          <div className="py-4 space-y-2">
            <p className="text-sm font-medium">This action will:</p>
            <ul className="text-sm text-muted-foreground list-disc pl-5 space-y-1">
              <li>Delete all currently imported cards from this set</li>
              <li>Fetch fresh data from Card Hedge API</li>
              <li>Skip cards that don't match the sport category</li>
              <li>Re-import only cards with correct sport classification</li>
            </ul>
          </div>

          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => setShowPurgeConfirm(false)}
              disabled={purgeReimportMutation.isPending}
              data-testid="button-cancel-purge"
            >
              Cancel
            </Button>
            <Button 
              variant="destructive"
              onClick={confirmPurgeReimport}
              disabled={purgeReimportMutation.isPending}
              data-testid="button-confirm-purge"
            >
              {purgeReimportMutation.isPending && (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              )}
              Purge & Re-import
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

shared/cardhedge/types.ts.content:
export type Category =
  | "Baseball"
  | "Basketball"
  | "Football"
  | "Hockey"
  | "Soccer"
  | "Pokemon"
  | string;

export type CardSearchCard = {
  card_id: string;
  category: Category;
  category_group?: string;
  description: string;
  player: string;
  set: string;
  set_type?: string;
  number?: string;
  variant?: string;
  rookie?: boolean;
  image: string;
  sales_7day?: number;
  sales_30day?: number;
  gain?: number;
  gain_30day?: number;
};

export type CardSearchRequest = {
  search?: string | null;
  set?: string | null;
  category?: Category | null;
  player?: string | null;
  rookie?: boolean | "Rookie" | null;
  raw_images_only?: boolean | null;
  page?: number;
  page_size?: number;
};

export type CardSearchSortedRequest = CardSearchRequest & {
  sort_by?: string;
  sort_order?: "asc" | "desc";
};

export type CardSearchResponse = {
  pages: number;
  count: number;
  cards: CardSearchCard[];
};

export type ImageSearchRequest = {
  image_url?: string | null;
  image_base64?: string | null;
  k?: number;
};

export type CardData = {
  card_id: string;
  description?: string;
  player?: string;
  set?: string;
  number?: string;
};

export type ImageSearchResultItem = {
  similarity: string;
  distance: number;
  ximilar_id?: string;
  product_id?: string | null;
  card_data?: CardData | null;
};

export type ImageSearchResponse = {
  success: boolean;
  results: ImageSearchResultItem[];
  total_results: number;
  query_id: string;
  has_cardhedge_matches: boolean;
  message?: string | null;
};

export type CardDetailsRequest = {
  card_id: string;
  raw_images_only?: boolean | null;
};

export type CardDetails = {
  cards: CardSearchCard[];
};

export type CardHedgeApiResponse<T> = {
  ok: true;
  data: T;
} | {
  ok: false;
  error: {
    code: string;
    message: string;
    status?: number;
  };
};

export type FetchEnoughCardsResult = {
  pages_scanned: number;
  pages: number;
  count: number;
  cards: CardSearchCard[];
};

server/services/store/packageGuardrailSe.content:
import { db } from "../../db";
import { 
  storeFeeProfiles, 
  storePackagePolicy, 
  storePackageValidations,
  products,
  adminBundleAuditLog,
  type StoreFeeProfile,
  type StorePackagePolicy,
  type InsertStorePackageValidation
} from "@shared/schema";
import { eq, and, desc, sql } from "drizzle-orm";

export type SalesChannel = "web_stripe" | "ios_iap" | "android_iap";

export type PackageDecision = "PASS" | "WARN" | "BLOCK" | "OVERRIDE";

export type DriverMode = "USD" | "PACKPTS";
export type RatioMode = "AUTO" | "OVERRIDE";

export interface BundleRatios {
  usdPerPackptMicro: number;
  packptPerUsdMicro: number;
}

export interface BundlePreviewResult {
  resolved: {
    usdPriceCents: number;
    packptsAmount: number;
    ratios: BundleRatios;
    ratioMode: RatioMode;
  };
  guardrails: EvaluationResult;
}

export interface ComputedPackageMetrics {
  priceCents: number;
  ptsGrant: number;
  channel: SalesChannel;
  feeRate: number;
  feeFixedCents: number;
  platformFeeRate: number;
  processorFeeCents: number;
  platformFeeCents: number;
  totalFeesCents: number;
  netRevenueCents: number;
  totalRedemptionCostCents: number;
  grossMarginRate: number;
  impliedValuePerPtMicrousd: number;
  marginContributionCents: number;
}

export interface EvaluationResult {
  decision: PackageDecision;
  reasons: string[];
  computed: ComputedPackageMetrics;
  policy: {
    minMarginRate: number;
    warnMarginBand: number;
    maxValuePerPtMicrousd: number;
    allowOverride: boolean;
    reserveRate: number;
  };
  feeProfile: {
    channel: SalesChannel;
    feeRate: number;
    feeFixedCents: number;
    platformFeeRate: number;
  };
}

class PackageGuardrailService {
  async getActivePolicy(): Promise<StorePackagePolicy | null> {
    const policies = await db
      .select()
      .from(storePackagePolicy)
      .where(eq(storePackagePolicy.isActive, true))
      .orderBy(desc(storePackagePolicy.createdAt))
      .limit(1);

    return policies[0] || null;
  }

  async getFeeProfile(channel: SalesChannel): Promise<StoreFeeProfile | null> {
    const profiles = await db
      .select()
      .from(storeFeeProfiles)
      .where(
        and(
          eq(storeFeeProfiles.channel, channel),
          eq(storeFeeProfiles.isActive, true)
        )
      )
      .limit(1);

    return profiles[0] || null;
  }

  async getAllFeeProfiles(): Promise<StoreFeeProfile[]> {
    return db
      .select()
      .from(storeFeeProfiles)
      .where(eq(storeFeeProfiles.isActive, true));
  }

  computeMetrics(
    priceCents: number,
    ptsGrant: number,
    channel: SalesChannel,
    feeProfile: StoreFeeProfile,
    policy: StorePackagePolicy
  ): ComputedPackageMetrics {
    // Step 1: Calculate processor fees = priceCents * feeRate + feeFixedCents
    const processorFeeCents = Math.round(priceCents * feeProfile.feeRate) + feeProfile.feeFixedCents;

    // Step 2: Calculate platform fees = priceCents * platformFeeRate
    const platformFeeCents = Math.round(priceCents * feeProfile.platformFeeRate);

    // Step 3: Total fees
    const totalFeesCents = processorFeeCents + platformFeeCents;

    // Step 4: Net revenue = priceCents - processorFees - platformFees
    const netRevenueCents = priceCents - totalFeesCents;

    // Step 5: Total redemption cost - the liability created when granting pts
    // Uses maxValuePerPtMicrousd as the expected redemption value per point
    // microusd = millionths of a dollar, so divide by 1,000,000 to get dollars, then * 100 for cents
    const totalRedemptionCostCents = Math.round(ptsGrant * policy.maxValuePerPtMicrousd / 10000);

    // Step 6: Gross margin = (netRevenue - totalRedemptionCost) / netRevenue
    // This measures what % of net revenue is profit after accounting for redemption liability
    const grossMarginRate = netRevenueCents > 0 
      ? (netRevenueCents - totalRedemptionCostCents) / netRevenueCents 
      : 0;

    // Step 7: Implied value per pt = priceCents * 100 / packpts (in microusd)
    // This is what each point is "worth" based on the package price (not net revenue)
    const impliedValuePerPtMicrousd = ptsGrant > 0 
      ? Math.round((priceCents * 100) / ptsGrant)
      : 0;

    // Step 8: Margin contribution = netRevenue * reserveRate
    const marginContributionCents = Math.round(netRevenueCents * policy.reserveRate);

    return {
      priceCents,
      ptsGrant,
      channel,
      feeRate: feeProfile.feeRate,
      feeFixedCents: feeProfile.feeFixedCents,
      platformFeeRate: feeProfile.platformFeeRate,
      processorFeeCents,
      platformFeeCents,
      totalFeesCents,
      netRevenueCents,
      totalRedemptionCostCents,
      grossMarginRate,
      impliedValuePerPtMicrousd,
      marginContributionCents,
    };
  }

  evaluateMetrics(
    computed: ComputedPackageMetrics,
    policy: StorePackagePolicy
  ): { decision: PackageDecision; reasons: string[] } {
    const reasons: string[] = [];
    let decision: PackageDecision = "PASS";

    if (computed.grossMarginRate < policy.minMarginRate) {
      decision = "BLOCK";
      reasons.push(
        `Gross margin ${(computed.grossMarginRate * 100).toFixed(1)}% is below minimum ${(policy.minMarginRate * 100).toFixed(1)}%`
      );
    }

    if (decision !== "BLOCK") {
      if (computed.grossMarginRate < policy.minMarginRate + policy.warnMarginBand) {
        if (decision === "PASS") decision = "WARN";
        reasons.push(
          `Gross margin ${(computed.grossMarginRate * 100).toFixed(1)}% is within warning band of minimum (${((policy.minMarginRate + policy.warnMarginBand) * 100).toFixed(1)}%)`
        );
      }

      if (computed.impliedValuePerPtMicrousd > policy.maxValuePerPtMicrousd) {
        if (decision === "PASS") decision = "WARN";
        const impliedValueUsd = computed.impliedValuePerPtMicrousd / 1000000;
        const maxValueUsd = policy.maxValuePerPtMicrousd / 1000000;
        reasons.push(
          `Implied value per PackPTS ($${impliedValueUsd.toFixed(6)}) exceeds max ($${maxValueUsd.toFixed(6)}) - too generous`
        );
      }

      if (computed.netRevenueCents < 0) {
        decision = "BLOCK";
        reasons.push("Net revenue is negative after fees");
      }
    }

    if (reasons.length === 0) {
      reasons.push("All guardrails passed");
    }

    return { decision, reasons };
  }

  async evaluatePackage(
    priceCents: number,
    ptsGrant: number,
    channel: SalesChannel = "web_stripe"
  ): Promise<EvaluationResult> {
    const policy = await this.getActivePolicy();
    if (!policy) {
      throw new Error("No active store package policy configured");
    }

    const feeProfile = await this.getFeeProfile(channel);
    if (!feeProfile) {
      throw new Error(`No active fee profile for channel: ${channel}`);
    }

    const computed = this.computeMetrics(priceCents, ptsGrant, channel, feeProfile, policy);
    const { decision, reasons } = this.evaluateMetrics(computed, policy);

    return {
      decision,
      reasons,
      computed,
      policy: {
        minMarginRate: policy.minMarginRate,
        warnMarginBand: policy.warnMarginBand,
        maxValuePerPtMicrousd: policy.maxValuePerPtMicrousd,
        allowOverride: policy.allowOverride,
        reserveRate: policy.reserveRate,
      },
      feeProfile: {
        channel: feeProfile.channel as SalesChannel,
        feeRate: feeProfile.feeRate,
        feeFixedCents: feeProfile.feeFixedCents,
        platformFeeRate: feeProfile.platformFeeRate,
      },
    };
  }

  async recordValidation(
    evaluation: EvaluationResult,
    productId: string | null,
    adminUserId: string | null,
    overrideNote?: string
  ): Promise<string> {
    const policy = await this.getActivePolicy();
    const feeProfile = await this.getFeeProfile(evaluation.computed.channel);

    if (!policy || !feeProfile) {
      throw new Error("Missing policy or fee profile");
    }

    const validation: InsertStorePackageValidation = {
      productId: productId || undefined,
      policyId: policy.id,
      feeProfileId: feeProfile.id,
      priceCents: evaluation.computed.priceCents,
      ptsGrant: evaluation.computed.ptsGrant,
      channel: evaluation.computed.channel,
      totalFeesCents: evaluation.computed.totalFeesCents,
      netRevenueCents: evaluation.computed.netRevenueCents,
      grossMarginRate: evaluation.computed.grossMarginRate,
      impliedValuePerPtMicrousd: evaluation.computed.impliedValuePerPtMicrousd,
      decision: overrideNote ? "OVERRIDE" : evaluation.decision,
      reasons: evaluation.reasons,
      adminUserId: adminUserId || undefined,
      overrideNote,
    };

    const [result] = await db
      .insert(storePackageValidations)
      .values(validation)
      .returning({ id: storePackageValidations.id });

    return result.id;
  }

  async getValidationHistory(productId: string): Promise<typeof storePackageValidations.$inferSelect[]> {
    return db
      .select()
      .from(storePackageValidations)
      .where(eq(storePackageValidations.productId, productId))
      .orderBy(desc(storePackageValidations.createdAt));
  }

  async getLatestValidation(productId: string): Promise<typeof storePackageValidations.$inferSelect | null> {
    const validations = await db
      .select()
      .from(storePackageValidations)
      .where(eq(storePackageValidations.productId, productId))
      .orderBy(desc(storePackageValidations.createdAt))
      .limit(1);

    return validations[0] || null;
  }

  async createPackage(
    sku: string,
    name: string,
    priceCents: number,
    ptsGrant: number,
    channel: SalesChannel,
    adminUserId: string,
    confirm: boolean = false
  ): Promise<{ productId: string; validationId: string; evaluation: EvaluationResult }> {
    const evaluation = await this.evaluatePackage(priceCents, ptsGrant, channel);

    if (evaluation.decision === "BLOCK") {
      throw new BlockedPackageError(evaluation);
    }

    if (evaluation.decision === "WARN" && !confirm) {
      throw new WarnPackageError(evaluation);
    }

    const [product] = await db
      .insert(products)
      .values({
        sku,
        name,
        type: "CONSUMABLE",
        packptsGrant: ptsGrant,
        priceUsd: priceCents,
        isActive: true,
        metadata: { channel },
      })
      .returning({ id: products.id });

    const validationId = await this.recordValidation(
      evaluation,
      product.id,
      adminUserId
    );

    return { productId: product.id, validationId, evaluation };
  }

  async updatePackage(
    productId: string,
    updates: {
      sku?: string;
      name?: string;
      priceCents?: number;
      ptsGrant?: number;
      channel?: SalesChannel;
    },
    adminUserId: string,
    confirm: boolean = false
  ): Promise<{ validationId: string; evaluation: EvaluationResult }> {
    const [existingProduct] = await db
      .select()
      .from(products)
      .where(eq(products.id, productId))
      .limit(1);

    if (!existingProduct) {
      throw new Error("Product not found");
    }

    const metadata = existingProduct.metadata as { channel?: SalesChannel } | null;
    const channel = updates.channel || metadata?.channel || "web_stripe";
    const priceCents = updates.priceCents ?? existingProduct.priceUsd ?? 0;
    const ptsGrant = updates.ptsGrant ?? existingProduct.packptsGrant ?? 0;

    const evaluation = await this.evaluatePackage(priceCents, ptsGrant, channel);

    if (evaluation.decision === "BLOCK") {
      throw new BlockedPackageError(evaluation);
    }

    if (evaluation.decision === "WARN" && !confirm) {
      throw new WarnPackageError(evaluation);
    }

    await db
      .update(products)
      .set({
        sku: updates.sku ?? existingProduct.sku,
        name: updates.name ?? existingProduct.name,
        priceUsd: priceCents,
        packptsGrant: ptsGrant,
        metadata: { ...metadata, channel },
      })
      .where(eq(products.id, productId));

    const validationId = await this.recordValidation(
      evaluation,
      productId,
      adminUserId
    );

    return { validationId, evaluation };
  }

  async overridePackage(
    productId: string,
    note: string,
    adminUserId: string
  ): Promise<{ validationId: string }> {
    const policy = await this.getActivePolicy();
    if (!policy?.allowOverride) {
      throw new Error("Policy does not allow overrides");
    }

    const [product] = await db
      .select()
      .from(products)
      .where(eq(products.id, productId))
      .limit(1);

    if (!product) {
      throw new Error("Product not found");
    }

    const metadata = product.metadata as { channel?: SalesChannel } | null;
    const channel = metadata?.channel || "web_stripe";
    const priceCents = product.priceUsd ?? 0;
    const ptsGrant = product.packptsGrant ?? 0;

    const evaluation = await this.evaluatePackage(priceCents, ptsGrant, channel);

    const validationId = await this.recordValidation(
      evaluation,
      productId,
      adminUserId,
      note
    );

    return { validationId };
  }

  async updatePolicy(
    updates: Partial<{
      minMarginRate: number;
      warnMarginBand: number;
      maxValuePerPtMicrousd: number;
      allowOverride: boolean;
      reserveRate: number;
    }>
  ): Promise<StorePackagePolicy> {
    const currentPolicy = await this.getActivePolicy();

    if (currentPolicy) {
      await db
        .update(storePackagePolicy)
        .set({ isActive: false })
        .where(eq(storePackagePolicy.id, currentPolicy.id));
    }

    const [newPolicy] = await db
      .insert(storePackagePolicy)
      .values({
        minMarginRate: updates.minMarginRate ?? currentPolicy?.minMarginRate ?? 0.30,
        warnMarginBand: updates.warnMarginBand ?? currentPolicy?.warnMarginBand ?? 0.05,
        maxValuePerPtMicrousd: updates.maxValuePerPtMicrousd ?? currentPolicy?.maxValuePerPtMicrousd ?? 2000,
        allowOverride: updates.allowOverride ?? currentPolicy?.allowOverride ?? false,
        reserveRate: updates.reserveRate ?? currentPolicy?.reserveRate ?? 1.0,
        isActive: true,
      })
      .returning();

    return newPolicy;
  }

  async updateFeeProfile(
    channel: SalesChannel,
    updates: Partial<{
      feeRate: number;
      feeFixedCents: number;
      platformFeeRate: number;
    }>
  ): Promise<StoreFeeProfile> {
    const [updatedProfile] = await db
      .update(storeFeeProfiles)
      .set({
        ...updates,
        updatedAt: new Date(),
      })
      .where(eq(storeFeeProfiles.channel, channel))
      .returning();

    if (!updatedProfile) {
      throw new Error(`Fee profile for channel ${channel} not found`);
    }

    return updatedProfile;
  }

  computeRatios(usdPriceCents: number, packptsAmount: number): BundleRatios {
    if (packptsAmount <= 0 || usdPriceCents <= 0) {
      return { usdPerPackptMicro: 0, packptPerUsdMicro: 0 };
    }
    const usdPerPackptMicro = Math.round((usdPriceCents * 10000) / packptsAmount);
    const packptPerUsdMicro = Math.round((packptsAmount * 1000000) / (usdPriceCents / 100));
    return { usdPerPackptMicro, packptPerUsdMicro };
  }

  autoCalculateFromDriver(
    driver: DriverMode,
    usdPriceCents: number | undefined,
    packptsAmount: number | undefined,
    defaultRatioMicro: number,
    overrideRatioMicro?: number
  ): { usdPriceCents: number; packptsAmount: number } {
    const ratioMicro = overrideRatioMicro || defaultRatioMicro;

    if (driver === "USD") {
      const price = usdPriceCents ?? 0;
      if (price <= 0 || ratioMicro <= 0) return { usdPriceCents: price, packptsAmount: packptsAmount ?? 0 };
      const computed = Math.floor((price * 10000) / ratioMicro);
      return { usdPriceCents: price, packptsAmount: Math.max(1, computed) };
    } else {
      const pts = packptsAmount ?? 0;
      if (pts <= 0 || ratioMicro <= 0) return { usdPriceCents: usdPriceCents ?? 0, packptsAmount: pts };
      const computed = Math.ceil((pts * ratioMicro) / 10000);
      return { usdPriceCents: Math.max(1, computed), packptsAmount: pts };
    }
  }

  async previewBundle(params: {
    channel?: SalesChannel;
    usdPriceCents?: number;
    packptsAmount?: number;
    driver?: DriverMode;
    ratioMode?: RatioMode;
    overrideRatioUsdPerPackptMicro?: number;
  }): Promise<BundlePreviewResult> {
    const policy = await this.getActivePolicy();
    if (!policy) throw new Error("No active store package policy configured");

    const channel = params.channel || "web_stripe";
    const driver = params.driver || "USD";
    const ratioMode = params.ratioMode || "AUTO";
    const defaultRatio = policy.maxValuePerPtMicrousd;

    const { usdPriceCents, packptsAmount } = this.autoCalculateFromDriver(
      driver,
      params.usdPriceCents,
      params.packptsAmount,
      defaultRatio,
      ratioMode === "OVERRIDE" ? params.overrideRatioUsdPerPackptMicro : undefined
    );

    const ratios = this.computeRatios(usdPriceCents, packptsAmount);
    const guardrails = await this.evaluatePackage(usdPriceCents, packptsAmount, channel);

    return {
      resolved: {
        usdPriceCents,
        packptsAmount,
        ratios,
        ratioMode,
      },
      guardrails,
    };
  }

  async createBundle(params: {
    sku: string;
    name: string;
    channel: SalesChannel;
    usdPriceCents: number;
    packptsAmount: number;
    ratioMode: RatioMode;
    overrideRatioUsdPerPackptMicro?: number;
    overrideReason?: string;
    overrideGuardrails?: boolean;
    overrideGuardrailsReason?: string;
    confirm?: boolean;
    adminUserId: string;
  }): Promise<{ productId: string; validationId: string; evaluation: EvaluationResult }> {
    if (params.ratioMode === "OVERRIDE" && (!params.overrideReason || params.overrideReason.length < 10)) {
      throw new Error("Override reason must be at least 10 characters when using OVERRIDE ratio mode");
    }

    const evaluation = await this.evaluatePackage(
      params.usdPriceCents, params.packptsAmount, params.channel
    );

    if (evaluation.decision === "BLOCK") {
      if (!params.overrideGuardrails) {
        throw new BlockedPackageError(evaluation);
      }
      if (!params.overrideGuardrailsReason || params.overrideGuardrailsReason.length < 10) {
        throw new Error("Override guardrails reason must be at least 10 characters");
      }
    }

    if (evaluation.decision === "WARN" && !params.confirm) {
      throw new WarnPackageError(evaluation);
    }

    const ratios = this.computeRatios(params.usdPriceCents, params.packptsAmount);

    const guardrailsStatus = params.overrideGuardrails && evaluation.decision === "BLOCK"
      ? "OVERRIDE"
      : evaluation.decision;

    const [product] = await db
      .insert(products)
      .values({
        sku: params.sku,
        name: params.name,
        type: "CONSUMABLE",
        packptsGrant: params.packptsAmount,
        priceUsd: params.usdPriceCents,
        isActive: true,
        metadata: { channel: params.channel },
        ratioUsdPerPackptMicro: ratios.usdPerPackptMicro,
        ratioPackptPerUsdMicro: ratios.packptPerUsdMicro,
        ratioMode: params.ratioMode,
        overrideReason: params.overrideReason || null,
        guardrailsStatus,
        guardrailsJson: evaluation as any,
        createdByUserId: params.adminUserId,
      })
      .returning({ id: products.id });

    const overrideNote = params.overrideGuardrails
      ? `Guardrails override: ${params.overrideGuardrailsReason}`
      : params.ratioMode === "OVERRIDE"
        ? `Ratio override: ${params.overrideReason}`
        : undefined;

    const validationId = await this.recordValidation(
      evaluation, product.id, params.adminUserId, overrideNote
    );

    await db.insert(adminBundleAuditLog).values({
      bundleId: product.id,
      actorUserId: params.adminUserId,
      action: "CREATE",
      afterJson: {
        sku: params.sku,
        name: params.name,
        usdPriceCents: params.usdPriceCents,
        packptsAmount: params.packptsAmount,
        channel: params.channel,
        ratioMode: params.ratioMode,
        ratios,
        guardrailsStatus,
        overrideReason: params.overrideReason,
        overrideGuardrailsReason: params.overrideGuardrailsReason,
      },
      reason: overrideNote || `Created bundle: ${params.sku}`,
    });

    return { productId: product.id, validationId, evaluation };
  }

  async updateBundle(params: {
    productId: string;
    sku?: string;
    name?: string;
    channel?: SalesChannel;
    usdPriceCents?: number;
    packptsAmount?: number;
    ratioMode?: RatioMode;
    overrideRatioUsdPerPackptMicro?: number;
    overrideReason?: string;
    overrideGuardrails?: boolean;
    overrideGuardrailsReason?: string;
    confirm?: boolean;
    adminUserId: string;
  }): Promise<{ validationId: string; evaluation: EvaluationResult }> {
    const [existing] = await db
      .select()
      .from(products)
      .where(eq(products.id, params.productId))
      .limit(1);

    if (!existing) throw new Error("Product not found");

    const metadata = existing.metadata as { channel?: SalesChannel } | null;
    const channel = params.channel || metadata?.channel || "web_stripe";
    const priceCents = params.usdPriceCents ?? existing.priceUsd ?? 0;
    const ptsGrant = params.packptsAmount ?? existing.packptsGrant ?? 0;
    const ratioMode = params.ratioMode ?? (existing.ratioMode as RatioMode) ?? "AUTO";

    if (ratioMode === "OVERRIDE" && (!params.overrideReason || params.overrideReason.length < 10)) {
      throw new Error("Override reason must be at least 10 characters when using OVERRIDE ratio mode");
    }

    const evaluation = await this.evaluatePackage(priceCents, ptsGrant, channel);

    if (evaluation.decision === "BLOCK" && !params.overrideGuardrails) {
      throw new BlockedPackageError(evaluation);
    }

    if (evaluation.decision === "BLOCK" && params.overrideGuardrails) {
      if (!params.overrideGuardrailsReason || params.overrideGuardrailsReason.length < 10) {
        throw new Error("Override guardrails reason must be at least 10 characters");
      }
    }

    if (evaluation.decision === "WARN" && !params.confirm) {
      throw new WarnPackageError(evaluation);
    }

    const ratios = this.computeRatios(priceCents, ptsGrant);
    const guardrailsStatus = params.overrideGuardrails && evaluation.decision === "BLOCK"
      ? "OVERRIDE"
      : evaluation.decision;

    const beforeSnapshot = {
      sku: existing.sku,
      name: existing.name,
      usdPriceCents: existing.priceUsd,
      packptsAmount: existing.packptsGrant,
      channel: metadata?.channel,
      ratioMode: existing.ratioMode,
      guardrailsStatus: existing.guardrailsStatus,
    };

    await db
      .update(products)
      .set({
        sku: params.sku ?? existing.sku,
        name: params.name ?? existing.name,
        priceUsd: priceCents,
        packptsGrant: ptsGrant,
        metadata: { ...metadata, channel },
        ratioUsdPerPackptMicro: ratios.usdPerPackptMicro,
        ratioPackptPerUsdMicro: ratios.packptPerUsdMicro,
        ratioMode,
        overrideReason: params.overrideReason ?? existing.overrideReason,
        guardrailsStatus,
        guardrailsJson: evaluation as any,
        updatedAt: new Date(),
      })
      .where(eq(products.id, params.productId));

    const overrideNote = params.overrideGuardrails
      ? `Guardrails override: ${params.overrideGuardrailsReason}`
      : ratioMode === "OVERRIDE"
        ? `Ratio override: ${params.overrideReason}`
        : undefined;

    const validationId = await this.recordValidation(
      evaluation, params.productId, params.adminUserId, overrideNote
    );

    const afterSnapshot = {
      sku: params.sku ?? existing.sku,
      name: params.name ?? existing.name,
      usdPriceCents: priceCents,
      packptsAmount: ptsGrant,
      channel,
      ratioMode,
      ratios,
      guardrailsStatus,
      overrideReason: params.overrideReason,
      overrideGuardrailsReason: params.overrideGuardrailsReason,
    };

    await db.insert(adminBundleAuditLog).values({
      bundleId: params.productId,
      actorUserId: params.adminUserId,
      action: ratioMode === "OVERRIDE" ? "OVERRIDE_RATIO" : "UPDATE",
      beforeJson: beforeSnapshot,
      afterJson: afterSnapshot,
      reason: overrideNote || `Updated bundle: ${params.sku ?? existing.sku}`,
    });

    return { validationId, evaluation };
  }

  async listBundles(filters?: { channel?: SalesChannel; status?: string }): Promise<any[]> {
    let query = db
      .select()
      .from(products)
      .where(eq(products.type, "CONSUMABLE"))
      .orderBy(desc(products.createdAt));

    const results = await query;

    return results
      .filter(p => {
        if (filters?.channel) {
          const meta = p.metadata as { channel?: string } | null;
          if (meta?.channel !== filters.channel) return false;
        }
        if (filters?.status && p.guardrailsStatus !== filters.status) return false;
        return true;
      })
      .map(p => {
        const meta = p.metadata as { channel?: string } | null;
        return {
          id: p.id,
          sku: p.sku,
          name: p.name,
          usdPriceCents: p.priceUsd,
          packptsAmount: p.packptsGrant,
          channel: meta?.channel || "web_stripe",
          ratioUsdPerPackptMicro: p.ratioUsdPerPackptMicro,
          ratioPackptPerUsdMicro: p.ratioPackptPerUsdMicro,
          ratioMode: p.ratioMode || "AUTO",
          guardrailsStatus: p.guardrailsStatus || "PASS",
          isActive: p.isActive,
          createdAt: p.createdAt,
          updatedAt: p.updatedAt,
        };
      });
  }

  async getBundleAuditLog(bundleId: string) {
    return db
      .select()
      .from(adminBundleAuditLog)
      .where(eq(adminBundleAuditLog.bundleId, bundleId))
      .orderBy(desc(adminBundleAuditLog.createdAt));
  }
}

export class BlockedPackageError extends Error {
  public evaluation: EvaluationResult;

  constructor(evaluation: EvaluationResult) {
    super(`Package blocked: ${evaluation.reasons.join(", ")}`);
    this.name = "BlockedPackageError";
    this.evaluation = evaluation;
  }
}

export class WarnPackageError extends Error {
  public evaluation: EvaluationResult;

  constructor(evaluation: EvaluationResult) {
    super(`Package requires confirmation: ${evaluation.reasons.join(", ")}`);
    this.name = "WarnPackageError";
    this.evaluation = evaluation;
  }
}

export async function seedPackageGuardrailConfig(): Promise<void> {
  const existingPolicy = await db
    .select()
    .from(storePackagePolicy)
    .where(eq(storePackagePolicy.isActive, true))
    .limit(1);

  if (existingPolicy.length === 0) {
    console.log("[PackageGuardrails] Creating default policy...");
    await db.insert(storePackagePolicy).values({
      minMarginRate: 0.30,
      warnMarginBand: 0.05,
      maxValuePerPtMicrousd: 2000,
      allowOverride: false,
      reserveRate: 1.0,
      isActive: true,
    });
  }

  const existingFeeProfiles = await db
    .select()
    .from(storeFeeProfiles)
    .where(eq(storeFeeProfiles.isActive, true));

  const channelConfigs: Array<{ 
    channel: SalesChannel; 
    feeRate: number; 
    feeFixedCents: number; 
    platformFeeRate: number 
  }> = [
    { channel: "web_stripe", feeRate: 0.029, feeFixedCents: 30, platformFeeRate: 0 },
    { channel: "ios_iap", feeRate: 0, feeFixedCents: 0, platformFeeRate: 0.30 },
    { channel: "android_iap", feeRate: 0, feeFixedCents: 0, platformFeeRate: 0.15 },
  ];

  for (const config of channelConfigs) {
    const exists = existingFeeProfiles.some(fp => fp.channel === config.channel);
    if (!exists) {
      console.log(`[PackageGuardrails] Creating fee profile for ${config.channel}...`);
      await db.insert(storeFeeProfiles).values({
        channel: config.channel,
        feeRate: config.feeRate,
        feeFixedCents: config.feeFixedCents,
        platformFeeRate: config.platformFeeRate,
        isActive: true,
      });
    }
  }

  console.log("[PackageGuardrails] Configuration seeded successfully");
}

export const packageGuardrailService = new PackageGuardrailService();

