import crypto from "crypto";
import { db } from "../db";
import { userGeoSession, userGeoProfile, geoRollupsDaily } from "@shared/schema";
import { eq, sql, and, gte, desc } from "drizzle-orm";

const GEO_SALT = process.env.GEO_SALT || crypto.randomBytes(32).toString("hex");
const GEO_TTL_DAYS = parseInt(process.env.GEO_TTL_DAYS || "30", 10);
const HOME_STATE_MIN_DISTINCT_DAYS = parseInt(process.env.HOME_STATE_MIN_DISTINCT_DAYS || "3", 10);
const HOME_STATE_MIN_SESSIONS = parseInt(process.env.HOME_STATE_MIN_SESSIONS || "5", 10);
const IPINFO_TOKEN = process.env.IPINFO_TOKEN;
const GEO_PROVIDER = process.env.GEO_PROVIDER || "ipinfo";
const GEO_TIMEOUT_MS = parseInt(process.env.GEO_TIMEOUT_MS || "3000", 10);

if (!process.env.GEO_SALT) {
  console.warn("[Geo] WARNING: GEO_SALT not configured. Using randomly generated salt which will change on restart. Set GEO_SALT env var for consistent IP hashing.");
}

const US_STATE_CODES = [
  "AL", "AK", "AZ", "AR", "CA", "CO", "CT", "DE", "FL", "GA",
  "HI", "ID", "IL", "IN", "IA", "KS", "KY", "LA", "ME", "MD",
  "MA", "MI", "MN", "MS", "MO", "MT", "NE", "NV", "NH", "NJ",
  "NM", "NY", "NC", "ND", "OH", "OK", "OR", "PA", "RI", "SC",
  "SD", "TN", "TX", "UT", "VT", "VA", "WA", "WV", "WI", "WY", "DC"
];

const TIMEZONE_STATE_MAP: Record<string, string[]> = {
  "America/New_York": ["NY", "NJ", "CT", "MA", "RI", "VT", "NH", "ME", "PA", "DE", "MD", "VA", "WV", "NC", "SC", "GA", "FL", "OH", "MI", "IN"],
  "America/Chicago": ["IL", "WI", "MN", "IA", "MO", "AR", "LA", "MS", "AL", "TN", "KY", "KS", "NE", "SD", "ND", "OK", "TX"],
  "America/Denver": ["CO", "WY", "MT", "UT", "NM", "AZ"],
  "America/Los_Angeles": ["CA", "WA", "OR", "NV"],
  "America/Phoenix": ["AZ"],
  "America/Anchorage": ["AK"],
  "Pacific/Honolulu": ["HI"],
};

export interface GeoData {
  country?: string;
  region?: string;
  asn?: string;
  carrierName?: string;
  isVpn?: boolean;
  city?: string;
}

export interface GeoSessionData {
  userId?: string;
  sessionId?: string;
  ipHash?: string;
  userAgent?: string;
  timezone?: string;
  country?: string;
  region?: string;
  asn?: string;
  carrierName?: string;
  isVpn?: boolean;
  source: "http" | "ws";
  geoConfidence: number;
}

export function hashIp(ip: string): string {
  return crypto.createHmac("sha256", GEO_SALT).update(ip).digest("hex");
}

export function normalizeStateCode(region: string | undefined): string | undefined {
  if (!region) return undefined;
  const upper = region.toUpperCase().trim();
  if (US_STATE_CODES.includes(upper)) return upper;

  const stateNameMap: Record<string, string> = {
    "CALIFORNIA": "CA", "TEXAS": "TX", "FLORIDA": "FL", "NEW YORK": "NY",
    "PENNSYLVANIA": "PA", "ILLINOIS": "IL", "OHIO": "OH", "GEORGIA": "GA",
    "NORTH CAROLINA": "NC", "MICHIGAN": "MI", "NEW JERSEY": "NJ",
    "VIRGINIA": "VA", "WASHINGTON": "WA", "ARIZONA": "AZ", "MASSACHUSETTS": "MA",
    "TENNESSEE": "TN", "INDIANA": "IN", "MARYLAND": "MD", "MISSOURI": "MO",
    "WISCONSIN": "WI", "COLORADO": "CO", "MINNESOTA": "MN", "SOUTH CAROLINA": "SC",
    "ALABAMA": "AL", "LOUISIANA": "LA", "KENTUCKY": "KY", "OREGON": "OR",
    "OKLAHOMA": "OK", "CONNECTICUT": "CT", "UTAH": "UT", "IOWA": "IA",
    "NEVADA": "NV", "ARKANSAS": "AR", "MISSISSIPPI": "MS", "KANSAS": "KS",
    "NEW MEXICO": "NM", "NEBRASKA": "NE", "IDAHO": "ID", "WEST VIRGINIA": "WV",
    "HAWAII": "HI", "NEW HAMPSHIRE": "NH", "MAINE": "ME", "MONTANA": "MT",
    "RHODE ISLAND": "RI", "DELAWARE": "DE", "SOUTH DAKOTA": "SD",
    "NORTH DAKOTA": "ND", "ALASKA": "AK", "VERMONT": "VT", "WYOMING": "WY",
    "DISTRICT OF COLUMBIA": "DC", "D.C.": "DC",
  };

  return stateNameMap[upper] || undefined;
}

export async function resolveGeo(ip: string): Promise<GeoData> {
  if (!IPINFO_TOKEN) {
    console.log("[Geo] No IPINFO_TOKEN configured, skipping geo resolution");
    return {};
  }

  if (GEO_PROVIDER !== "ipinfo") {
    console.log("[Geo] Only ipinfo provider is currently supported");
    return {};
  }

  try {
    const cleanIp = ip.replace(/^::ffff:/, "");
    if (cleanIp === "127.0.0.1" || cleanIp === "::1" || cleanIp.startsWith("192.168.") || cleanIp.startsWith("10.")) {
      return { country: "US", region: undefined };
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), GEO_TIMEOUT_MS);

    try {
      const response = await fetch(`https://ipinfo.io/${cleanIp}?token=${IPINFO_TOKEN}`, {
        signal: controller.signal,
      });
      clearTimeout(timeoutId);

      if (!response.ok) {
        console.error(`[Geo] ipinfo.io error: ${response.status}`);
        return {};
      }

      const data = await response.json();

      return {
        country: data.country || undefined,
        region: data.country === "US" ? normalizeStateCode(data.region) : data.region,
        asn: data.org || undefined,
        carrierName: data.carrier?.name || undefined,
        isVpn: data.privacy?.vpn || data.privacy?.proxy || data.privacy?.tor || false,
        city: data.city || undefined,
      };
    } catch (fetchError: any) {
      clearTimeout(timeoutId);
      if (fetchError.name === "AbortError") {
        console.warn("[Geo] ipinfo.io request timed out after", GEO_TIMEOUT_MS, "ms");
      } else {
        throw fetchError;
      }
      return {};
    }
  } catch (error) {
    console.error("[Geo] Failed to resolve geo:", error);
    return {};
  }
}

export function computeConfidence(
  geoData: GeoData,
  timezone?: string,
  existingSameRegion?: boolean
): number {
  let confidence = 50;

  if (geoData.isVpn) {
    confidence -= 30;
  }

  if (existingSameRegion) {
    confidence += 10;
  }

  if (timezone && geoData.region && geoData.country === "US") {
    const matchingStates = TIMEZONE_STATE_MAP[timezone];
    if (matchingStates?.includes(geoData.region)) {
      confidence += 10;
    }
    if (timezone === "Pacific/Honolulu" && geoData.region === "HI") {
      confidence += 15;
    }
  }

  return Math.max(0, Math.min(100, confidence));
}

export async function checkRecentSameRegion(
  ipHash: string,
  region: string | undefined
): Promise<boolean> {
  if (!region) return false;

  const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
  const [existing] = await db
    .select()
    .from(userGeoSession)
    .where(
      and(
        eq(userGeoSession.ipHash, ipHash),
        eq(userGeoSession.region, region),
        gte(userGeoSession.lastSeenAt, oneDayAgo)
      )
    )
    .limit(1);

  return !!existing;
}

export async function upsertGeoSession(data: GeoSessionData): Promise<void> {
  const { sessionId, userId, ...rest } = data;

  if (sessionId) {
    const [existing] = await db
      .select()
      .from(userGeoSession)
      .where(eq(userGeoSession.sessionId, sessionId))
      .limit(1);

    if (existing) {
      await db.update(userGeoSession)
        .set({
          lastSeenAt: new Date(),
          userId: userId || existing.userId,
          ...rest,
        })
        .where(eq(userGeoSession.id, existing.id));
      return;
    }
  }

  await db.insert(userGeoSession).values({
    userId,
    sessionId,
    startedAt: new Date(),
    lastSeenAt: new Date(),
    ...rest,
  });
}

export async function computeHomeState(userId: string): Promise<void> {
  const cutoffDate = new Date(Date.now() - GEO_TTL_DAYS * 24 * 60 * 60 * 1000);

  const sessions = await db
    .select()
    .from(userGeoSession)
    .where(
      and(
        eq(userGeoSession.userId, userId),
        gte(userGeoSession.startedAt, cutoffDate)
      )
    );

  if (sessions.length === 0) {
    await db.delete(userGeoProfile).where(eq(userGeoProfile.userId, userId));
    return;
  }

  const regionStats: Record<string, {
    sessions: number;
    distinctDays: Set<string>;
    weightedScore: number;
  }> = {};

  const now = Date.now();

  for (const session of sessions) {
    const region = session.region;
    if (!region || session.country !== "US") continue;

    if (!regionStats[region]) {
      regionStats[region] = { sessions: 0, distinctDays: new Set(), weightedScore: 0 };
    }

    regionStats[region].sessions++;
    regionStats[region].distinctDays.add(session.startedAt.toISOString().split("T")[0]);

    const recencyDays = (now - session.startedAt.getTime()) / (24 * 60 * 60 * 1000);
    const weight = Math.exp(-recencyDays / 10);
    regionStats[region].weightedScore += weight * (session.geoConfidence / 100);
  }

  const sortedRegions = Object.entries(regionStats)
    .map(([region, stats]) => ({
      region,
      sessions: stats.sessions,
      distinctDays: stats.distinctDays.size,
      weightedScore: stats.weightedScore,
    }))
    .sort((a, b) => b.weightedScore - a.weightedScore);

  const top = sortedRegions[0];
  let homeRegion: string | null = null;
  let confidence = 0;

  if (
    top &&
    top.distinctDays >= HOME_STATE_MIN_DISTINCT_DAYS &&
    top.sessions >= HOME_STATE_MIN_SESSIONS
  ) {
    homeRegion = top.region;
    confidence = Math.min(100, Math.round(
      (top.distinctDays / 7) * 30 +
      (top.sessions / 10) * 30 +
      top.weightedScore * 40
    ));
  }

  const basis = {
    topStates: sortedRegions.slice(0, 3).map(s => ({
      state: s.region,
      sessions: s.sessions,
      days: s.distinctDays,
      score: Math.round(s.weightedScore * 100) / 100,
    })),
    totalSessions: sessions.length,
  };

  await db
    .insert(userGeoProfile)
    .values({
      userId,
      homeCountry: "US",
      homeRegion,
      confidence,
      basis,
      lastComputedAt: new Date(),
    })
    .onConflictDoUpdate({
      target: userGeoProfile.userId,
      set: {
        homeCountry: "US",
        homeRegion,
        confidence,
        basis,
        lastComputedAt: new Date(),
      },
    });
}

export async function computeAllHomeStates(): Promise<number> {
  const cutoffDate = new Date(Date.now() - GEO_TTL_DAYS * 24 * 60 * 60 * 1000);

  const usersWithSessions = await db
    .selectDistinct({ userId: userGeoSession.userId })
    .from(userGeoSession)
    .where(
      and(
        sql`${userGeoSession.userId} IS NOT NULL`,
        gte(userGeoSession.startedAt, cutoffDate)
      )
    );

  let count = 0;
  for (const row of usersWithSessions) {
    if (row.userId) {
      await computeHomeState(row.userId);
      count++;
    }
  }

  console.log(`[Geo] Computed home states for ${count} users`);
  return count;
}

export async function computeDailyRollups(targetDate?: Date): Promise<void> {
  const day = targetDate || new Date();
  day.setUTCHours(0, 0, 0, 0);

  const nextDay = new Date(day);
  nextDay.setUTCDate(nextDay.getUTCDate() + 1);

  const rollupData = await db
    .select({
      country: userGeoSession.country,
      region: userGeoSession.region,
      activeUsers: sql<number>`COUNT(DISTINCT ${userGeoSession.userId})`.as("active_users"),
      sessions: sql<number>`COUNT(*)`.as("sessions"),
    })
    .from(userGeoSession)
    .where(
      and(
        gte(userGeoSession.startedAt, day),
        sql`${userGeoSession.startedAt} < ${nextDay}`,
        sql`${userGeoSession.country} IS NOT NULL`,
        sql`${userGeoSession.region} IS NOT NULL`
      )
    )
    .groupBy(userGeoSession.country, userGeoSession.region);

  for (const row of rollupData) {
    if (!row.country || !row.region) continue;

    await db
      .insert(geoRollupsDaily)
      .values({
        day,
        country: row.country,
        region: row.region,
        activeUsers: row.activeUsers,
        sessions: row.sessions,
        newUsers: 0,
      })
      .onConflictDoNothing();
  }

  console.log(`[Geo] Computed daily rollups for ${day.toISOString().split("T")[0]}: ${rollupData.length} regions`);
}

export async function getGeoStats(windowDays: number = 30): Promise<{
  states: Array<{
    state: string;
    activeUsers: number;
    sessions: number;
    pctOfTotal: number;
  }>;
  total: { users: number; sessions: number };
}> {
  const cutoffDate = new Date(Date.now() - windowDays * 24 * 60 * 60 * 1000);

  const stats = await db
    .select({
      region: userGeoSession.region,
      activeUsers: sql<number>`COUNT(DISTINCT ${userGeoSession.userId})`.as("active_users"),
      sessions: sql<number>`COUNT(*)`.as("sessions"),
    })
    .from(userGeoSession)
    .where(
      and(
        gte(userGeoSession.startedAt, cutoffDate),
        eq(userGeoSession.country, "US"),
        sql`${userGeoSession.region} IS NOT NULL`
      )
    )
    .groupBy(userGeoSession.region)
    .orderBy(desc(sql`active_users`));

  const totalUsers = stats.reduce((sum, s) => sum + s.activeUsers, 0);
  const totalSessions = stats.reduce((sum, s) => sum + s.sessions, 0);

  return {
    states: stats.map(s => ({
      state: s.region || "Unknown",
      activeUsers: s.activeUsers,
      sessions: s.sessions,
      pctOfTotal: totalUsers > 0 ? Math.round((s.activeUsers / totalUsers) * 10000) / 100 : 0,
    })),
    total: { users: totalUsers, sessions: totalSessions },
  };
}

export async function getCoverageStats(windowDays: number = 30): Promise<{
  statesWithUsers: string[];
  statesWithoutUsers: string[];
  hiCount: number;
  hasHawaiiUsers: boolean;
  caCount: number;
  maCount: number;
}> {
  const { states } = await getGeoStats(windowDays);
  const stateSet = new Set(states.map(s => s.state));

  const statesWithUsers = US_STATE_CODES.filter(s => stateSet.has(s));
  const statesWithoutUsers = US_STATE_CODES.filter(s => !stateSet.has(s));

  const hiStat = states.find(s => s.state === "HI");
  const caStat = states.find(s => s.state === "CA");
  const maStat = states.find(s => s.state === "MA");

  return {
    statesWithUsers,
    statesWithoutUsers,
    hiCount: hiStat?.activeUsers || 0,
    hasHawaiiUsers: !!hiStat && hiStat.activeUsers > 0,
    caCount: caStat?.activeUsers || 0,
    maCount: maStat?.activeUsers || 0,
  };
}

export async function getUserGeoProfile(userId: string): Promise<{
  profile: typeof userGeoProfile.$inferSelect | null;
  recentSessions: Array<{
    startedAt: Date;
    region: string | null;
    confidence: number;
    source: string;
  }>;
}> {
  const [profile] = await db
    .select()
    .from(userGeoProfile)
    .where(eq(userGeoProfile.userId, userId))
    .limit(1);

  const recentSessions = await db
    .select({
      startedAt: userGeoSession.startedAt,
      region: userGeoSession.region,
      confidence: userGeoSession.geoConfidence,
      source: userGeoSession.source,
    })
    .from(userGeoSession)
    .where(eq(userGeoSession.userId, userId))
    .orderBy(desc(userGeoSession.startedAt))
    .limit(10);

  return {
    profile: profile || null,
    recentSessions,
  };
}

export const geoService = {
  hashIp,
  resolveGeo,
  normalizeStateCode,
  computeConfidence,
  checkRecentSameRegion,
  upsertGeoSession,
  computeHomeState,
  computeAllHomeStates,
  computeDailyRollups,
  getGeoStats,
  getCoverageStats,
  getUserGeoProfile,
};

server/services/imageContentAnalyzer.ts.content:
/**
 * Image Content Analyzer
 * Detects placeholder/silhouette images by analyzing actual image content
 * Uses sharp for image processing to identify:
 * - Low color diversity (silhouettes are often single-color)
 * - Low entropy/complexity (real cards have text, details, patterns)
 * - Common placeholder dimensions
 */

import sharp from "sharp";

export interface ImageAnalysisResult {
  isPlaceholder: boolean;
  confidence: number;
  reasons: string[];
  stats?: {
    width: number;
    height: number;
    channels: number;
    uniqueColors: number;
    entropy: number;
    dominantColorPercent: number;
  };
}

const FETCH_TIMEOUT_MS = 10000;
const MAX_IMAGE_SIZE = 5 * 1024 * 1024; // 5MB max

const analysisCache = new Map<string, { result: ImageAnalysisResult; expiresAt: number }>();
const CACHE_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

function getCachedResult(url: string): ImageAnalysisResult | null {
  const cached = analysisCache.get(url);
  if (cached && cached.expiresAt > Date.now()) {
    return cached.result;
  }
  analysisCache.delete(url);
  return null;
}

function cacheResult(url: string, result: ImageAnalysisResult): void {
  if (analysisCache.size > 1000) {
    const firstKey = analysisCache.keys().next().value;
    if (firstKey) analysisCache.delete(firstKey);
  }
  analysisCache.set(url, { result, expiresAt: Date.now() + CACHE_TTL_MS });
}

async function fetchImageBuffer(url: string): Promise<Buffer | null> {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS);

    const response = await fetch(url, {
      signal: controller.signal,
      headers: { "User-Agent": "PackPoints-ImageAnalyzer/1.0" }
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      console.log(`[ImageAnalyzer] Failed to fetch ${url}: HTTP ${response.status}`);
      return null;
    }

    const contentType = response.headers.get("content-type") || "";
    if (!contentType.startsWith("image/")) {
      console.log(`[ImageAnalyzer] Invalid content type for ${url}: ${contentType}`);
      return null;
    }

    const contentLength = parseInt(response.headers.get("content-length") || "0", 10);
    if (contentLength > MAX_IMAGE_SIZE) {
      console.log(`[ImageAnalyzer] Image too large: ${contentLength} bytes`);
      return null;
    }

    const arrayBuffer = await response.arrayBuffer();
    return Buffer.from(arrayBuffer);
  } catch (error: any) {
    console.log(`[ImageAnalyzer] Error fetching ${url}: ${error.message}`);
    return null;
  }
}

function calculateEntropy(histogram: number[]): number {
  const total = histogram.reduce((sum, count) => sum + count, 0);
  if (total === 0) return 0;

  let entropy = 0;
  for (const count of histogram) {
    if (count > 0) {
      const p = count / total;
      entropy -= p * Math.log2(p);
    }
  }
  return entropy;
}

async function analyzeImageBuffer(buffer: Buffer): Promise<{
  width: number;
  height: number;
  channels: number;
  uniqueColors: number;
  entropy: number;
  dominantColorPercent: number;
  hasDetailedEdges: boolean;
  silhouetteScore: number;
  warmBackgroundPercent: number;
  darkPixelPercent: number;
  coolGradientPercent: number;
}> {
  const image = sharp(buffer);
  const metadata = await image.metadata();

  const width = metadata.width || 0;
  const height = metadata.height || 0;
  const channels = metadata.channels || 3;

  const resized = await image
    .resize(100, 100, { fit: "inside" })
    .raw()
    .toBuffer({ resolveWithObject: true });

  const { data } = resized;
  const pixelCount = data.length / channels;

  const colorMap = new Map<string, number>();
  const histogram = new Array(256).fill(0);

  let warmPixels = 0;
  let darkPixels = 0;
  let orangeTanPixels = 0;
  let purplePixels = 0;
  let bluePixels = 0;
  let coolGradientPixels = 0;

  for (let i = 0; i < data.length; i += channels) {
    const r = data[i];
    const g = data[i + 1] || 0;
    const b = data[i + 2] || 0;

    const colorKey = `${Math.floor(r / 16)}-${Math.floor(g / 16)}-${Math.floor(b / 16)}`;
    colorMap.set(colorKey, (colorMap.get(colorKey) || 0) + 1);

    const gray = Math.floor((r * 0.299 + g * 0.587 + b * 0.114));
    histogram[gray]++;

    if (r > 150 && g > 80 && g < 180 && b < 100) {
      warmPixels++;
      if (r > 180 && g > 100 && g < 160 && b < 80) {
        orangeTanPixels++;
      }
    }

    if (r < 60 && g < 60 && b < 60) {
      darkPixels++;
    }

    // Purple detection: high red, high blue, low-medium green
    if (r > 80 && b > 120 && g < 100 && b > g) {
      purplePixels++;
    }

    // Blue detection: high blue, low red
    if (b > 150 && r < 120 && g < 180) {
      bluePixels++;
    }

    // Cool gradient pixels: purple-blue spectrum (like basketball silhouettes)
    if ((r > 60 && b > 100 && b > r * 0.8 && g < Math.max(r, b)) || 
        (b > 120 && r > 50 && g < 120)) {
      coolGradientPixels++;
    }
  }

  const uniqueColors = colorMap.size;
  const entropy = calculateEntropy(histogram);

  let maxColorCount = 0;
  colorMap.forEach((count) => {
    if (count > maxColorCount) maxColorCount = count;
  });
  const dominantColorPercent = (maxColorCount / pixelCount) * 100;

  const edgeBuffer = await sharp(buffer)
    .resize(100, 100, { fit: "inside" })
    .greyscale()
    .convolve({
      width: 3,
      height: 3,
      kernel: [-1, -1, -1, -1, 8, -1, -1, -1, -1]
    })
    .raw()
    .toBuffer();

  let edgeSum = 0;
  for (let i = 0; i < edgeBuffer.length; i++) {
    edgeSum += edgeBuffer[i];
  }
  const avgEdgeValue = edgeSum / edgeBuffer.length;
  const hasDetailedEdges = avgEdgeValue > 15;

  const warmBackgroundPercent = (warmPixels / pixelCount) * 100;
  const darkPixelPercent = (darkPixels / pixelCount) * 100;
  const orangeTanPercent = (orangeTanPixels / pixelCount) * 100;
  const purplePercent = (purplePixels / pixelCount) * 100;
  const bluePercent = (bluePixels / pixelCount) * 100;
  const coolGradientPercent = (coolGradientPixels / pixelCount) * 100;

  let silhouetteScore = 0;
  // Silhouette detection requires MULTIPLE conditions to avoid false positives
  // Real cards have high color diversity and detailed edges
  const hasLowColorDiversity = uniqueColors < 100;
  const hasVeryLowColorDiversity = uniqueColors < 60;
  const hasWarmBackground = warmBackgroundPercent > 35 || orangeTanPercent > 25;
  const hasCoolBackground = coolGradientPercent > 30 || purplePercent > 20 || bluePercent > 25;
  const hasDarkSilhouetteShape = darkPixelPercent > 10 && darkPixelPercent < 50;
  const lacksDetailedEdges = !hasDetailedEdges;

  // === WARM COLOR SILHOUETTES (orange/tan backgrounds) ===
  // Strong signal: warm background + dark shape + low colors + no edges
  if (hasWarmBackground && hasDarkSilhouetteShape && hasLowColorDiversity && lacksDetailedEdges) {
    silhouetteScore += 50; // High confidence silhouette
  }
  // Medium signal: orange/tan specifically + dark shape + low colors
  else if (orangeTanPercent > 30 && darkPixelPercent > 15 && uniqueColors < 80) {
    silhouetteScore += 35;
  }
  // Weak signal: just warm background with dark pixels (but not enough on its own)
  else if (warmBackgroundPercent > 50 && darkPixelPercent > 20 && uniqueColors < 60) {
    silhouetteScore += 25;
  }

  // === COOL COLOR SILHOUETTES (purple/blue gradient backgrounds) ===
  // Strong signal: cool gradient + dark shape + low colors + no edges
  if (hasCoolBackground && hasDarkSilhouetteShape && hasLowColorDiversity && lacksDetailedEdges) {
    silhouetteScore += 50; // High confidence purple/blue silhouette
  }
  // Medium signal: significant purple or blue + dark shape + very low colors
  else if ((purplePercent > 15 || bluePercent > 20) && darkPixelPercent > 10 && hasVeryLowColorDiversity) {
    silhouetteScore += 40;
  }
  // Cool gradient with silhouette shape
  else if (coolGradientPercent > 40 && darkPixelPercent > 15 && uniqueColors < 80) {
    silhouetteScore += 35;
  }

  return {
    width,
    height,
    channels,
    uniqueColors,
    entropy,
    dominantColorPercent,
    hasDetailedEdges,
    silhouetteScore,
    warmBackgroundPercent,
    darkPixelPercent,
    coolGradientPercent
  };
}

export async function analyzeImageContent(url: string): Promise<ImageAnalysisResult> {
  const cached = getCachedResult(url);
  if (cached) {
    return cached;
  }

  try {
    const buffer = await fetchImageBuffer(url);
    if (!buffer) {
      const result: ImageAnalysisResult = {
        isPlaceholder: true,
        confidence: 100,
        reasons: ["Failed to fetch image"]
      };
      cacheResult(url, result);
      return result;
    }

    const stats = await analyzeImageBuffer(buffer);
    const reasons: string[] = [];
    let placeholderScore = 0;

    if (stats.uniqueColors < 50) {
      reasons.push(`Very low color diversity (${stats.uniqueColors} unique color clusters)`);
      placeholderScore += 40;
    } else if (stats.uniqueColors < 100) {
      reasons.push(`Low color diversity (${stats.uniqueColors} unique color clusters)`);
      placeholderScore += 20;
    }

    if (stats.entropy < 4.0) {
      reasons.push(`Very low image complexity (entropy: ${stats.entropy.toFixed(2)})`);
      placeholderScore += 40;
    } else if (stats.entropy < 5.5) {
      reasons.push(`Low image complexity (entropy: ${stats.entropy.toFixed(2)})`);
      placeholderScore += 15;
    }

    if (stats.dominantColorPercent > 60) {
      reasons.push(`Dominant color covers ${stats.dominantColorPercent.toFixed(1)}% of image`);
      placeholderScore += 30;
    } else if (stats.dominantColorPercent > 40) {
      reasons.push(`High dominant color presence (${stats.dominantColorPercent.toFixed(1)}%)`);
      placeholderScore += 15;
    }

    if (!stats.hasDetailedEdges) {
      reasons.push("Lacks detailed edges/text typical of real cards");
      placeholderScore += 25;
    }

    if (stats.silhouetteScore >= 40) {
      reasons.push(`Sport silhouette pattern detected (warm=${stats.warmBackgroundPercent.toFixed(1)}%, cool=${stats.coolGradientPercent.toFixed(1)}%, dark=${stats.darkPixelPercent.toFixed(1)}%)`);
      placeholderScore += stats.silhouetteScore;
    } else if (stats.silhouetteScore >= 20) {
      reasons.push(`Possible silhouette pattern (warm=${stats.warmBackgroundPercent.toFixed(1)}%, cool=${stats.coolGradientPercent.toFixed(1)}%, dark=${stats.darkPixelPercent.toFixed(1)}%)`);
      placeholderScore += stats.silhouetteScore;
    }

    const knownPlaceholderDimensions = [
      [300, 400], [200, 300], [150, 200], [100, 150],
      [400, 300], [300, 200]
    ];
    for (const [w, h] of knownPlaceholderDimensions) {
      if (stats.width === w && stats.height === h) {
        reasons.push(`Matches common placeholder dimensions (${w}x${h})`);
        placeholderScore += 15;
        break;
      }
    }

    const isPlaceholder = placeholderScore >= 50;
    const confidence = Math.min(placeholderScore, 100);

    const result: ImageAnalysisResult = {
      isPlaceholder,
      confidence,
      reasons: reasons.length > 0 ? reasons : ["Image appears to be authentic"],
      stats: {
        width: stats.width,
        height: stats.height,
        channels: stats.channels,
        uniqueColors: stats.uniqueColors,
        entropy: stats.entropy,
        dominantColorPercent: stats.dominantColorPercent
      }
    };

    cacheResult(url, result);
    console.log(`[ImageAnalyzer] ${url.slice(-50)}: placeholder=${isPlaceholder}, confidence=${confidence}%, reasons=${reasons.join("; ")}`);

    return result;
  } catch (error: any) {
    console.error(`[ImageAnalyzer] Error analyzing ${url}:`, error.message);
    const result: ImageAnalysisResult = {
      isPlaceholder: true,
      confidence: 50,
      reasons: [`Analysis error: ${error.message}`]
    };
    cacheResult(url, result);
    return result;
  }
}

export async function batchAnalyzeImages(urls: string[]): Promise<Map<string, ImageAnalysisResult>> {
  const results = new Map<string, ImageAnalysisResult>();

  for (const url of urls) {
    const result = await analyzeImageContent(url);
    results.set(url, result);
    await new Promise(resolve => setTimeout(resolve, 100));
  }

  return results;
}

export function isLikelyPlaceholderByContent(result: ImageAnalysisResult): boolean {
  return result.isPlaceholder && result.confidence >= 50;
}

server/services/telemetry/cardDelivery.t.content:
import { db } from "../../db";
import { telemetryCardDelivery } from "@shared/schema";
import { sql } from "drizzle-orm";

export type CardDeliveryStage = 
  | "prefetch" 
  | "validate" 
  | "validate_fail"
  | "serve" 
  | "image_fail" 
  | "replace_card"
  | "prefetch_fail"
  | "build_queue";

interface TelemetryDetail {
  reason?: string;
  cardCount?: number;
  validCount?: number;
  invalidCount?: number;
  duration_ms?: number;
  questionIdx?: number;
  replacementCardId?: string;
  error?: string;
  [key: string]: unknown;
}

export async function logCardDelivery(
  stage: CardDeliveryStage,
  options: {
    matchId?: string;
    setKey?: string;
    cardId?: string;
    detail?: TelemetryDetail;
  } = {}
): Promise<void> {
  try {
    await db.insert(telemetryCardDelivery).values({
      matchId: options.matchId || null,
      setKey: options.setKey || null,
      stage,
      cardId: options.cardId || null,
      detail: options.detail || null,
    });
  } catch (error) {
    console.error("[Telemetry] Failed to log card delivery:", error);
  }
}

export async function getCardDeliveryStats(hours: number = 24): Promise<{
  totalEvents: number;
  byStage: Record<string, number>;
  imageOkRateBySet: Array<{ setKey: string; total: number; valid: number; rate: number }>;
  replacementStats: { matchesWithReplacements: number; totalReplacements: number };
}> {
  const cutoff = new Date(Date.now() - hours * 60 * 60 * 1000);

  const events = await db
    .select()
    .from(telemetryCardDelivery)
    .where(sql`${telemetryCardDelivery.ts} > ${cutoff}`);

  const byStage: Record<string, number> = {};
  const setValidation: Record<string, { valid: number; total: number }> = {};
  const matchReplacements = new Set<string>();
  let totalReplacements = 0;

  for (const event of events) {
    byStage[event.stage] = (byStage[event.stage] || 0) + 1;

    if (event.stage === "validate" && event.setKey) {
      if (!setValidation[event.setKey]) {
        setValidation[event.setKey] = { valid: 0, total: 0 };
      }
      setValidation[event.setKey].total++;
      const detail = event.detail as TelemetryDetail | null;
      if (detail?.validCount) {
        setValidation[event.setKey].valid += detail.validCount;
      }
    }

    if (event.stage === "replace_card") {
      totalReplacements++;
      if (event.matchId) {
        matchReplacements.add(event.matchId);
      }
    }
  }

  const imageOkRateBySet = Object.entries(setValidation).map(([setKey, stats]) => ({
    setKey,
    total: stats.total,
    valid: stats.valid,
    rate: stats.total > 0 ? stats.valid / stats.total : 0,
  }));

  return {
    totalEvents: events.length,
    byStage,
    imageOkRateBySet,
    replacementStats: {
      matchesWithReplacements: matchReplacements.size,
      totalReplacements,
    },
  };
}

server/services/friends/friendMatchInvit.content:
import { db } from "../../db";
import { friendMatchInvites, users, lobbies, type FriendMatchInvite } from "@shared/schema";
import { eq, and, sql, gt, lt } from "drizzle-orm";
import { isAcceptedFriend } from "./friendshipService";
import { matchService } from "../matchService";
import { randomUUID } from "crypto";
import { 
  notifyFriendMatchInvite, 
  notifyFriendMatchInviteCancelled,
  notifyFriendMatchInviteExpired,
  notifyFriendMatchAccepted,
} from "../../websocket";
import { validateActiveUser } from "../auth/validateActiveUser";

const INVITE_EXPIRY_MINUTES = 5;
const MAX_INVITES_PER_HOUR = 10;

function generateJoinCode(): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let code = "";
  for (let i = 0; i < 6; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return code;
}

function generateSecret(): string {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
  let secret = "";
  for (let i = 0; i < 32; i++) {
    secret += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return secret;
}

export interface InviteResult {
  success: boolean;
  invite?: FriendMatchInvite;
  error?: string;
}

export async function createFriendMatchInvite(
  fromUserId: string, 
  toUserId: string, 
  bucket: string = "ANY"
): Promise<InviteResult> {
  if (fromUserId === toUserId) {
    return { success: false, error: "Cannot invite yourself" };
  }

  const fromUserValidation = await validateActiveUser(fromUserId);
  if (!fromUserValidation.valid) {
    return { 
      success: false, 
      error: fromUserValidation.reason === "BANNED" 
        ? "Your account has been suspended" 
        : "Your account is not active"
    };
  }

  const toUserValidation = await validateActiveUser(toUserId);
  if (!toUserValidation.valid) {
    return { 
      success: false, 
      error: toUserValidation.reason === "BANNED" 
        ? "This user's account has been suspended" 
        : toUserValidation.reason === "NOT_FOUND"
        ? "User not found"
        : "This user's account is not active"
    };
  }

  const areFriends = await isAcceptedFriend(fromUserId, toUserId);
  if (!areFriends) {
    return { success: false, error: "You must be friends to send a match invite" };
  }

  const hourAgo = new Date(Date.now() - 60 * 60 * 1000);
  const recentInvitesResult = await db.execute(sql`
    SELECT COUNT(*) as count FROM friend_match_invites
    WHERE from_user_id = ${fromUserId}
      AND created_at > ${hourAgo}
  `);
  const recentCount = Number((recentInvitesResult.rows?.[0] as any)?.count || 0);
  if (recentCount >= MAX_INVITES_PER_HOUR) {
    return { success: false, error: "Rate limit exceeded. Maximum 10 invites per hour." };
  }

  const existingResult = await db
    .select()
    .from(friendMatchInvites)
    .where(
      and(
        eq(friendMatchInvites.fromUserId, fromUserId),
        eq(friendMatchInvites.toUserId, toUserId),
        eq(friendMatchInvites.bucket, bucket),
        eq(friendMatchInvites.status, "PENDING"),
        gt(friendMatchInvites.expiresAt, new Date())
      )
    )
    .limit(1);

  if (existingResult.length > 0) {
    return { success: true, invite: existingResult[0] };
  }

  const expiresAt = new Date(Date.now() + INVITE_EXPIRY_MINUTES * 60 * 1000);

  const [fromUser] = await db
    .select({ username: users.username })
    .from(users)
    .where(eq(users.id, fromUserId))
    .limit(1);

  const [invite] = await db
    .insert(friendMatchInvites)
    .values({
      fromUserId,
      toUserId,
      bucket,
      mode: "1vFriends",
      status: "PENDING",
      expiresAt,
    })
    .returning();

  notifyFriendMatchInvite(toUserId, {
    inviteId: invite.id,
    fromUserId,
    fromUsername: fromUser?.username || "Unknown",
    bucket,
    expiresAt,
  });

  return { success: true, invite };
}

export async function cancelFriendMatchInvite(inviteId: string, userId: string): Promise<{ success: boolean; error?: string }> {
  const [invite] = await db
    .select()
    .from(friendMatchInvites)
    .where(eq(friendMatchInvites.id, inviteId))
    .limit(1);

  if (!invite) {
    return { success: false, error: "Invite not found" };
  }

  if (invite.fromUserId !== userId) {
    return { success: false, error: "Not authorized to cancel this invite" };
  }

  if (invite.status !== "PENDING") {
    return { success: false, error: "Invite is not pending" };
  }

  await db
    .update(friendMatchInvites)
    .set({ status: "CANCELLED" })
    .where(eq(friendMatchInvites.id, inviteId));

  notifyFriendMatchInviteCancelled(invite.toUserId, inviteId);

  return { success: true };
}

export interface RespondResult {
  success: boolean;
  matchId?: string;
  lobbyId?: string;
  hostSecret?: string;
  guestSecret?: string;
  error?: string;
}

export async function respondToFriendMatchInvite(
  inviteId: string, 
  userId: string, 
  action: "ACCEPT" | "DECLINE"
): Promise<RespondResult> {
  const [invite] = await db
    .select()
    .from(friendMatchInvites)
    .where(eq(friendMatchInvites.id, inviteId))
    .limit(1);

  if (!invite) {
    return { success: false, error: "Invite not found" };
  }

  if (invite.toUserId !== userId) {
    return { success: false, error: "Not authorized to respond to this invite" };
  }

  if (invite.status !== "PENDING") {
    return { success: false, error: "Invite is not pending" };
  }

  if (invite.expiresAt < new Date()) {
    await db
      .update(friendMatchInvites)
      .set({ status: "EXPIRED" })
      .where(eq(friendMatchInvites.id, inviteId));
    return { success: false, error: "Invite has expired" };
  }

  if (action === "DECLINE") {
    await db
      .update(friendMatchInvites)
      .set({ status: "DECLINED" })
      .where(eq(friendMatchInvites.id, inviteId));
    return { success: true };
  }

  const responderValidation = await validateActiveUser(userId);
  if (!responderValidation.valid) {
    return { 
      success: false, 
      error: responderValidation.reason === "BANNED" 
        ? "Your account has been suspended" 
        : "Your account is not active"
    };
  }

  const inviterValidation = await validateActiveUser(invite.fromUserId);
  if (!inviterValidation.valid) {
    await db
      .update(friendMatchInvites)
      .set({ status: "CANCELLED" })
      .where(eq(friendMatchInvites.id, inviteId));
    return { 
      success: false, 
      error: "The inviter's account is no longer active"
    };
  }

  const [fromUser] = await db
    .select({ username: users.username })
    .from(users)
    .where(eq(users.id, invite.fromUserId))
    .limit(1);

  const [toUser] = await db
    .select({ username: users.username })
    .from(users)
    .where(eq(users.id, invite.toUserId))
    .limit(1);

  const lobbyId = randomUUID();
  const joinCode = generateJoinCode();
  const hostSecret = generateSecret();
  const guestSecret = generateSecret();

  await db.insert(lobbies).values({
    id: lobbyId,
    joinCode,
    hostId: invite.fromUserId,
    hostUsername: fromUser?.username || "Player1",
    hostSecret,
    guestId: invite.toUserId,
    guestUsername: toUser?.username || "Player2",
    guestSecret,
    status: "ready",
    mode: "1v1_friend",
    totalQuestions: 10,
    gameSetId: invite.bucket !== "ANY" ? invite.bucket : null,
    createdAt: new Date(),
  });

  const result = await matchService.startMatchForRandom(lobbyId);

  if (!result.matchState) {
    console.error(`[FriendMatchInvite] Failed to create match: ${result.error}`);
    return { success: false, error: result.error || "Failed to create match" };
  }

  const match = result.matchState;

  await db
    .update(friendMatchInvites)
    .set({ status: "ACCEPTED", matchId: match.matchId })
    .where(eq(friendMatchInvites.id, inviteId));

  notifyFriendMatchAccepted(invite.fromUserId, {
    inviteId,
    matchId: match.matchId,
    lobbyId,
    membershipSecret: hostSecret,
  });

  notifyFriendMatchAccepted(invite.toUserId, {
    inviteId,
    matchId: match.matchId,
    lobbyId,
    membershipSecret: guestSecret,
  });

  return { 
    success: true, 
    matchId: match.matchId, 
    lobbyId,
    hostSecret,
    guestSecret,
  };
}

export interface InboxInvite {
  inviteId: string;
  fromUserId: string;
  fromUsername: string;
  fromProfileImageUrl: string | null;
  bucket: string;
  expiresAt: Date;
  createdAt: Date | null;
}

export async function getIncomingInvites(userId: string): Promise<InboxInvite[]> {
  const result = await db.execute(sql`
    SELECT 
      i.id as invite_id,
      i.from_user_id,
      u.username as from_username,
      u.profile_image_url as from_profile_image_url,
      i.bucket,
      i.expires_at,
      i.created_at
    FROM friend_match_invites i
    JOIN users u ON u.id = i.from_user_id
    WHERE i.to_user_id = ${userId}
      AND i.status = 'PENDING'
      AND i.expires_at > NOW()
    ORDER BY i.created_at DESC
  `);

  return (result.rows || []).map((row: any) => ({
    inviteId: row.invite_id,
    fromUserId: row.from_user_id,
    fromUsername: row.from_username,
    fromProfileImageUrl: row.from_profile_image_url,
    bucket: row.bucket,
    expiresAt: row.expires_at,
    createdAt: row.created_at,
  }));
}

export async function getOutgoingInvites(userId: string): Promise<{ inviteId: string; toUserId: string; toUsername: string; bucket: string; expiresAt: Date }[]> {
  const result = await db.execute(sql`
    SELECT 
      i.id as invite_id,
      i.to_user_id,
      u.username as to_username,
      i.bucket,
      i.expires_at
    FROM friend_match_invites i
    JOIN users u ON u.id = i.to_user_id
    WHERE i.from_user_id = ${userId}
      AND i.status = 'PENDING'
      AND i.expires_at > NOW()
    ORDER BY i.created_at DESC
  `);

  return (result.rows || []).map((row: any) => ({
    inviteId: row.invite_id,
    toUserId: row.to_user_id,
    toUsername: row.to_username,
    bucket: row.bucket,
    expiresAt: row.expires_at,
  }));
}

export async function expireOldInvites(): Promise<{ toUserId: string; inviteId: string }[]> {
  const result = await db.execute(sql`
    UPDATE friend_match_invites 
    SET status = 'EXPIRED'
    WHERE status = 'PENDING' AND expires_at < NOW()
    RETURNING id, to_user_id, from_user_id
  `);

  const expired = (result.rows || []).map((row: any) => ({
    inviteId: row.id,
    toUserId: row.to_user_id,
    fromUserId: row.from_user_id,
  }));

  for (const { inviteId, toUserId, fromUserId } of expired) {
    notifyFriendMatchInviteExpired(toUserId, inviteId);
    notifyFriendMatchInviteExpired(fromUserId, inviteId);
  }

  return expired;
}

export const friendMatchInviteService = {
  createFriendMatchInvite,
  cancelFriendMatchInvite,
  respondToFriendMatchInvite,
  getIncomingInvites,
  getOutgoingInvites,
  expireOldInvites,
};

