import { db } from "../../db";
import { marketplaceCache } from "@shared/schema";
import { eq, and, lt, gt } from "drizzle-orm";
import type { MarketplaceSource } from "./types";

const DEFAULT_TTL_SECONDS = 300;

export async function getFromCache<T>(
  source: MarketplaceSource,
  cacheKey: string
): Promise<{ data: T; lastUpdated: string } | null> {
  const now = new Date();

  const cached = await db.query.marketplaceCache.findFirst({
    where: and(
      eq(marketplaceCache.source, source),
      eq(marketplaceCache.cacheKey, cacheKey),
      gt(marketplaceCache.expiresAt, now)
    ),
  });

  if (cached) {
    return {
      data: cached.payload as T,
      lastUpdated: cached.createdAt?.toISOString() || now.toISOString(),
    };
  }

  return null;
}

export async function setCache<T>(
  source: MarketplaceSource,
  cacheKey: string,
  data: T,
  ttlSeconds: number = DEFAULT_TTL_SECONDS
): Promise<void> {
  const now = new Date();
  const expiresAt = new Date(now.getTime() + ttlSeconds * 1000);

  await db
    .insert(marketplaceCache)
    .values({
      source,
      cacheKey,
      payload: data as any,
      expiresAt,
      createdAt: now,
    })
    .onConflictDoUpdate({
      target: marketplaceCache.cacheKey,
      set: {
        payload: data as any,
        expiresAt,
        createdAt: now,
      },
    });
}

export async function getOrSetCache<T>(
  source: MarketplaceSource,
  cacheKey: string,
  ttlSeconds: number,
  fetcher: () => Promise<T>
): Promise<{ data: T; lastUpdated: string; cached: boolean }> {
  const cached = await getFromCache<T>(source, cacheKey);

  if (cached) {
    return { ...cached, cached: true };
  }

  const data = await fetcher();
  await setCache(source, cacheKey, data, ttlSeconds);

  return {
    data,
    lastUpdated: new Date().toISOString(),
    cached: false,
  };
}

export async function clearExpiredCache(): Promise<number> {
  const now = new Date();
  await db
    .delete(marketplaceCache)
    .where(lt(marketplaceCache.expiresAt, now));

  return 0;
}

server/scripts/testCardHedge.ts.content:
import { cardSearch } from "../integrations/cardhedge/client";

async function runTests() {
  console.log("=== CardHedge Integration Smoke Tests ===\n");

  let passed = 0;
  let failed = 0;

  async function test(name: string, fn: () => Promise<boolean>) {
    try {
      const result = await fn();
      if (result) {
        console.log(`✓ ${name}`);
        passed++;
      } else {
        console.log(`✗ ${name} - assertion failed`);
        failed++;
      }
    } catch (error) {
      console.log(`✗ ${name} - ${error instanceof Error ? error.message : 'Unknown error'}`);
      failed++;
    }
  }

  await test("1. API Key Configured", async () => {
    return !!process.env.CARDHEDGE_API_KEY;
  });

  await test("2. Basic Search Returns Cards", async () => {
    const result = await cardSearch(
      { search: "Topps", page: 1, page_size: 5 },
      { rawImagesOnly: false, filterPlaceholders: false }
    );
    console.log(`   - Count: ${result.count}, Pages: ${result.pages}, Cards returned: ${result.cards.length}`);
    return result.cards.length > 0;
  });

  await test("3. 1987 Topps Set Search", async () => {
    const result = await cardSearch(
      { set: "1987 Topps Baseball", page: 1, page_size: 10 },
      { rawImagesOnly: false, filterPlaceholders: false }
    );
    console.log(`   - Total count: ${result.count}, Pages: ${result.pages}`);
    return result.count > 0;
  });

  await test("4. Cards Have Required Fields", async () => {
    const result = await cardSearch(
      { search: "1987 Topps", page: 1, page_size: 5 },
      { rawImagesOnly: false, filterPlaceholders: false }
    );
    const card = result.cards[0];
    if (!card) return false;

    const hasFields = !!(card.card_id && card.player && card.set);
    console.log(`   - Sample card: ${card.player} - ${card.set}`);
    console.log(`   - Has image: ${!!card.image}`);
    return hasFields;
  });

  await test("5. Raw Images Filter Works", async () => {
    const result = await cardSearch(
      { search: "Topps Baseball", page: 1, page_size: 20, raw_images_only: true },
      { rawImagesOnly: true, filterPlaceholders: false }
    );
    console.log(`   - Raw images count: ${result.count}`);
    return result.cards.length > 0;
  });

  await test("6. Count Uses Metadata (Not Array Length)", async () => {
    const result = await cardSearch(
      { search: "Topps", page: 1, page_size: 10 },
      { rawImagesOnly: false, filterPlaceholders: false }
    );
    const metadataCount = result.count;
    const arrayLength = result.cards.length;
    console.log(`   - Metadata count: ${metadataCount}, Array length: ${arrayLength}`);
    return metadataCount > arrayLength;
  });

  console.log(`\n=== Results: ${passed} passed, ${failed} failed ===`);

  if (failed > 0) {
    process.exit(1);
  }
}

runTests().catch(console.error);

server/services/catalog/providers/cardhe.content:
import { 
  CatalogProvider, 
  CatalogSport, 
  DiagnoseCoverageResult, 
  ProviderCard, 
  SearchCardsInput, 
  SearchCardsResult 
} from "../types";
import { cardHedgeFetch, CardSearchResponse, normalizeImageUrl } from "../../../cardhedge/client";

export class CardHedgeProvider implements CatalogProvider {
  provider = "cardhedge" as const;

  async diagnoseCoverage(input: { sport: CatalogSport }): Promise<DiagnoseCoverageResult> {
    const { sport } = input;
    const notes: string[] = [];
    const workingCategories: string[] = [];
    let totalSampleCount = 0;

    const categoriesToTry = [
      sport,
      sport.toLowerCase(),
      sport.toUpperCase(),
      null,
    ];

    for (const category of categoriesToTry) {
      try {
        const response = await cardHedgeFetch<CardSearchResponse>(
          "/v1/cards/card-search",
          "POST",
          {
            category: category,
            search: sport,
            page: 1,
            page_size: 5,
          },
          { useCache: false }
        );

        const count = response.count ?? response.cards?.length ?? 0;
        const categoryLabel = category === null ? "(no category filter)" : `"${category}"`;

        if (count > 0) {
          notes.push(`Category ${categoryLabel}: ${count} cards found`);
          if (category !== null) {
            workingCategories.push(category);
          }
          totalSampleCount += count;
        } else {
          notes.push(`Category ${categoryLabel}: 0 cards found`);
        }
      } catch (error) {
        const categoryLabel = category === null ? "(no category filter)" : `"${category}"`;
        notes.push(`Category ${categoryLabel}: ERROR - ${error instanceof Error ? error.message : "Unknown error"}`);
      }
    }

    const fallbackResponse = await this.testFallbackSearch(sport);
    notes.push(`Fallback search (sport only): ${fallbackResponse.count} cards found`);
    totalSampleCount += fallbackResponse.count;

    return {
      ok: workingCategories.length > 0 || fallbackResponse.count > 0,
      notes: notes.join("\n"),
      sampleCount: totalSampleCount,
      workingCategories,
    };
  }

  private async testFallbackSearch(sport: string): Promise<{ count: number }> {
    try {
      const response = await cardHedgeFetch<CardSearchResponse>(
        "/v1/cards/card-search",
        "POST",
        {
          search: sport,
          page: 1,
          page_size: 5,
        },
        { useCache: false }
      );
      return { count: response.count ?? response.cards?.length ?? 0 };
    } catch {
      return { count: 0 };
    }
  }

  async searchCards(input: SearchCardsInput): Promise<SearchCardsResult> {
    const { search, set, category, page, pageSize } = input;

    const requestBody: Record<string, unknown> = {
      page,
      page_size: pageSize,
      raw_images_only: true,
    };

    if (search) {
      requestBody.search = search;
    }
    if (set) {
      requestBody.set = set;
    }
    if (category) {
      requestBody.category = category;
    }

    const response = await cardHedgeFetch<CardSearchResponse>(
      "/v1/cards/card-search",
      "POST",
      requestBody
    );

    const cards: ProviderCard[] = (response.cards || []).map((card) => ({
      provider: "cardhedge",
      providerCardId: card.card_id || "",
      description: card.description,
      player: card.player,
      set: card.set,
      number: card.number,
      variant: card.variant,
      image: normalizeImageUrl(card.image) || undefined,
      category: card.category,
      setType: card.set_type,
      raw: card,
    }));

    return {
      pages: response.pages || 1,
      count: response.count ?? response.cards?.length ?? 0,
      cards,
    };
  }
}

export const cardHedgeProvider = new CardHedgeProvider();

