import { useState, useEffect, useCallback } from "react";
import { useQuery } from "@tanstack/react-query";
import { Loader2 } from "lucide-react";

interface MaskRegion {
  xPct: number;
  yPct: number;
  wPct: number;
  hPct: number;
  type: "solid" | "blur" | "pixelate";
  radiusPct?: number;
}

interface MaskConfig {
  setKey: string;
  regions: MaskRegion[];
  maskVersion: number;
}

const DEFAULT_MASK_REGIONS: MaskRegion[] = [
  { xPct: 0, yPct: 0, wPct: 100, hPct: 18, type: "solid", radiusPct: 0 },
  { xPct: 0, yPct: 80, wPct: 100, hPct: 20, type: "solid", radiusPct: 0 },
];

interface MaskedCardImageProps {
  src: string;
  setKey?: string;
  alt?: string;
  className?: string;
  showMasks?: boolean;
  onImageLoad?: () => void;
  onImageError?: () => void;
  maskColor?: string;
}

export function MaskedCardImage({
  src,
  setKey,
  alt = "Card image",
  className = "",
  showMasks = true,
  onImageLoad,
  onImageError,
  maskColor = "#0b0f16",
}: MaskedCardImageProps) {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);

  const { data: maskConfig } = useQuery<MaskConfig>({
    queryKey: ["/api/card-sets/mask", setKey || "__default__"],
    queryFn: async () => {
      if (!setKey) {
        return {
          setKey: "__default__",
          regions: DEFAULT_MASK_REGIONS,
          maskVersion: 1,
        };
      }
      const res = await fetch(`/api/card-sets/${encodeURIComponent(setKey)}/mask`);
      if (!res.ok) {
        return {
          setKey: setKey,
          regions: DEFAULT_MASK_REGIONS,
          maskVersion: 1,
        };
      }
      return res.json();
    },
    staleTime: 10 * 60 * 1000,
  });

  const regions = maskConfig?.regions || DEFAULT_MASK_REGIONS;

  const handleImageLoad = useCallback(() => {
    setImageLoaded(true);
    onImageLoad?.();
  }, [onImageLoad]);

  const handleImageError = useCallback(() => {
    setImageError(true);
    onImageError?.();
  }, [onImageError]);

  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    return false;
  }, []);

  const handleDragStart = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    return false;
  }, []);

  return (
    <div
      className={`relative overflow-hidden select-none ${className}`}
      onContextMenu={handleContextMenu}
      style={{
        touchAction: "manipulation",
        WebkitTouchCallout: "none",
        WebkitUserSelect: "none",
        userSelect: "none",
      }}
      data-testid="masked-card-wrapper"
    >
      {!imageLoaded && !imageError && (
        <div 
          className="absolute inset-0 flex items-center justify-center bg-muted z-10"
          data-testid="masked-card-loading"
        >
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      )}

      {imageError && (
        <div 
          className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-amber-100 to-amber-200 z-10"
          data-testid="masked-card-error"
        >
          <p className="text-amber-800 font-medium">Image failed to load</p>
        </div>
      )}

      <img
        src={src}
        alt={alt}
        className="w-full h-full object-contain pointer-events-none"
        style={{
          opacity: imageLoaded && !imageError ? 1 : 0,
          WebkitUserDrag: "none",
          userSelect: "none",
        } as React.CSSProperties}
        onLoad={handleImageLoad}
        onError={handleImageError}
        onDragStart={handleDragStart}
        draggable={false}
        crossOrigin="anonymous"
        referrerPolicy="no-referrer"
        data-testid="masked-card-image"
      />

      {showMasks && regions.map((region, index) => (
        <div
          key={index}
          className="absolute pointer-events-auto"
          style={{
            left: `${region.xPct}%`,
            top: `${region.yPct}%`,
            width: `${region.wPct}%`,
            height: `${region.hPct}%`,
            backgroundColor: region.type === "solid" ? maskColor : "transparent",
            borderRadius: region.radiusPct ? `${region.radiusPct}%` : undefined,
            backdropFilter: region.type === "blur" ? "blur(10px)" : undefined,
            zIndex: 20,
          }}
          onContextMenu={handleContextMenu}
          data-testid={`mask-region-${index}`}
        />
      ))}
    </div>
  );
}

export { DEFAULT_MASK_REGIONS };
export type { MaskRegion, MaskConfig };

