                  </div>
                </div>
              ) : (
                <div className="text-center py-8 text-muted-foreground">
                  <FileText className="w-12 h-12 mx-auto mb-4 opacity-50" />
                  <p>No import has been run yet.</p>
                  <Button 
                    className="mt-4"
                    onClick={() => importMutation.mutate(selectedSet!.id)}
