          </Tabs>
        </DialogContent>
      </Dialog>
    </div>
  );
}

server/jobs/runExpiration.ts.content:
import "../db";
import { expirationEngine } from "../services/expirationEngine";

async function main() {
  console.log("Starting PackPTS expiration job...");
  console.log("Time:", new Date().toISOString());

  try {
    console.log("\n--- Running date-based expiration ---");
    const expirationResult = await expirationEngine.runExpirationJob(false);
    console.log(`Expired ${expirationResult.expiredBuckets} buckets`);
    console.log(`Total points expired: ${expirationResult.totalPointsExpired}`);
    if (expirationResult.errors.length > 0) {
      console.log("Errors:", expirationResult.errors);
    }

    console.log("\n--- Running inactivity-based expiration ---");
    const inactivityResult = await expirationEngine.runInactivityExpiration(false);
    console.log(`Users affected: ${inactivityResult.usersAffected}`);
    console.log(`Buckets expired: ${inactivityResult.bucketsExpired}`);
    console.log(`Total points expired: ${inactivityResult.totalPointsExpired}`);
    if (inactivityResult.errors.length > 0) {
      console.log("Errors:", inactivityResult.errors);
    }

    console.log("\nExpiration job completed successfully.");
    process.exit(0);
  } catch (error) {
    console.error("Expiration job failed:", error);
    process.exit(1);
  }
}

main();

server/services/images/imageGate.ts.content:
import { db } from "../../db";
import { cardImageCache, cardImageQuarantine, baseballCards, playableCards } from "@shared/schema";
import { eq, sql } from "drizzle-orm";
import { normalizeImageUrl, isPlaceholderImage, quarantineCard } from "../cards/imageQuality";

const VALIDATION_TIMEOUT_MS = 6000;
const MIN_IMAGE_BYTES = 5 * 1024;
const MAX_IMAGE_BYTES = 10 * 1024 * 1024;

export interface ValidationResult {
  valid: boolean;
  status: "ok" | "bad" | "pending";
  httpStatus?: number;
  contentType?: string;
  bytes?: number;
  error?: string;
}

export async function validateRemoteImage(url: string): Promise<ValidationResult> {
  const normalized = normalizeImageUrl(url);
  if (!normalized) {
    return { valid: false, status: "bad", error: "Invalid or empty URL" };
  }

  if (isPlaceholderImage(normalized)) {
    return { valid: false, status: "bad", error: "Placeholder URL detected" };
  }

  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), VALIDATION_TIMEOUT_MS);

    const response = await fetch(normalized, {
      method: "GET",
      headers: {
        Range: "bytes=0-65535",
        "User-Agent": "PackPTS/1.0 ImageValidator",
      },
      signal: controller.signal,
      redirect: "follow",
    });

    clearTimeout(timeoutId);

    const httpStatus = response.status;
    const contentType = response.headers.get("content-type") || "";

    if (httpStatus !== 200 && httpStatus !== 206) {
      return {
        valid: false,
        status: "bad",
        httpStatus,
        contentType,
        error: `HTTP ${httpStatus}`,
      };
    }

    if (!contentType.toLowerCase().startsWith("image/")) {
      return {
        valid: false,
        status: "bad",
        httpStatus,
        contentType,
        error: `Invalid content-type: ${contentType}`,
      };
    }

    const contentLength = response.headers.get("content-length");
    let estimatedBytes = contentLength ? parseInt(contentLength, 10) : 0;

    if (httpStatus === 206) {
      const contentRange = response.headers.get("content-range");
      if (contentRange) {
        const match = contentRange.match(/\/(\d+)$/);
        if (match) {
          estimatedBytes = parseInt(match[1], 10);
        }
      }
    }

    if (!estimatedBytes) {
      const body = await response.arrayBuffer();
      estimatedBytes = body.byteLength;
    }

    if (estimatedBytes < MIN_IMAGE_BYTES) {
      return {
        valid: false,
        status: "bad",
        httpStatus,
        contentType,
        bytes: estimatedBytes,
        error: `Image too small: ${estimatedBytes} bytes (min: ${MIN_IMAGE_BYTES})`,
      };
    }

    if (estimatedBytes > MAX_IMAGE_BYTES) {
      return {
        valid: false,
        status: "bad",
        httpStatus,
        contentType,
        bytes: estimatedBytes,
        error: `Image too large: ${estimatedBytes} bytes (max: ${MAX_IMAGE_BYTES})`,
      };
    }

    return {
      valid: true,
      status: "ok",
      httpStatus,
      contentType,
      bytes: estimatedBytes,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";

    if (message.includes("aborted") || message.includes("timeout")) {
      return { valid: false, status: "bad", error: "Request timeout" };
    }

    return { valid: false, status: "bad", error: message };
  }
}

export async function getOrValidateCardImage(cardId: string, sourceUrl: string): Promise<{
  proxiedPath: string;
  status: "ok" | "bad" | "pending";
  cached: boolean;
}> {
  const normalized = normalizeImageUrl(sourceUrl);
  if (!normalized) {
    return { proxiedPath: "", status: "bad", cached: false };
  }

  const [existing] = await db
    .select()
    .from(cardImageCache)
    .where(eq(cardImageCache.cardId, cardId))
    .limit(1);

  if (existing) {
    if (existing.status === "ok") {
      return { proxiedPath: existing.proxiedPath, status: "ok", cached: true };
    }

    if (existing.status === "bad") {
      return { proxiedPath: "", status: "bad", cached: true };
    }
  }

  const validation = await validateRemoteImage(normalized);
  const proxiedPath = `/api/images/card/${cardId}`;

  await db
    .insert(cardImageCache)
    .values({
      cardId,
      sourceUrl,
      normalizedUrl: normalized,
      proxiedPath,
      status: validation.status,
      lastHttpStatus: validation.httpStatus || null,
      lastContentType: validation.contentType || null,
      bytes: validation.bytes || null,
      failCount: validation.valid ? 0 : 1,
    })
    .onConflictDoUpdate({
      target: cardImageCache.cardId,
      set: {
        status: validation.status,
        lastHttpStatus: validation.httpStatus || null,
        lastContentType: validation.contentType || null,
        bytes: validation.bytes || null,
        failCount: validation.valid 
          ? 0 
          : sql`${cardImageCache.failCount} + 1`,
        lastCheckedAt: new Date(),
      },
    });

  if (!validation.valid) {
    quarantineCard(cardId, validation.error || "validation_failed", normalized).catch(() => {});
  }

  return {
    proxiedPath: validation.valid ? proxiedPath : "",
    status: validation.status,
    cached: false,
  };
}

export async function getCachedImageUrl(cardId: string): Promise<string | null> {
  const [cached] = await db
    .select()
    .from(cardImageCache)
    .where(eq(cardImageCache.cardId, cardId))
    .limit(1);

  if (!cached || cached.status !== "ok") {
    return null;
  }

  return cached.normalizedUrl;
}

export async function getSourceUrlForCard(cardId: string): Promise<string | null> {
  const [cached] = await db
    .select({ normalizedUrl: cardImageCache.normalizedUrl })
    .from(cardImageCache)
    .where(eq(cardImageCache.cardId, cardId))
    .limit(1);

  if (cached) {
    return cached.normalizedUrl;
  }

  const [card] = await db
    .select({ imageUrl: baseballCards.imageUrl })
    .from(baseballCards)
    .where(eq(baseballCards.id, cardId))
    .limit(1);

  if (card?.imageUrl) {
    return normalizeImageUrl(card.imageUrl);
  }

  const [pcCard] = await db
    .select({ imageUrl: playableCards.imageUrl })
    .from(playableCards)
    .where(eq(playableCards.id, cardId))
    .limit(1);

  return pcCard?.imageUrl ? normalizeImageUrl(pcCard.imageUrl) : null;
}

export async function markImageBad(cardId: string, reason: string): Promise<void> {
  await db
    .update(cardImageCache)
    .set({
      status: "bad",
      failCount: sql`${cardImageCache.failCount} + 1`,
      lastCheckedAt: new Date(),
    })
    .where(eq(cardImageCache.cardId, cardId));

  await quarantineCard(cardId, reason, null);
}

export async function invalidateCacheEntry(cardId: string): Promise<void> {
  await db
    .delete(cardImageCache)
    .where(eq(cardImageCache.cardId, cardId));
}

export async function getValidatedCardIds(): Promise<Set<string>> {
  const rows = await db
    .select({ cardId: cardImageCache.cardId })
    .from(cardImageCache)
    .where(eq(cardImageCache.status, "ok"));

  return new Set(rows.map(r => r.cardId));
}

export async function getBadCardIds(): Promise<Set<string>> {
  const rows = await db
    .select({ cardId: cardImageCache.cardId })
    .from(cardImageCache)
    .where(eq(cardImageCache.status, "bad"));

  return new Set(rows.map(r => r.cardId));
}

server/services/expirationEngine.ts.content:
import { db } from "../db";
import {
  packptsBucket,
  packptsExpirationPolicy,
  packptsLiabilitySnapshot,
  ledgerEntries,
  wallets,
  users,
  type PackptsBucket,
  type PackptsExpirationPolicy,
  type InsertPackptsLiabilitySnapshot,
  DEFAULT_EXPIRATION_POLICY,
} from "@shared/schema";
import { eq, and, lte, gt, sql, asc, isNull, not, gte } from "drizzle-orm";
import { bucketService } from "./bucketService";

export interface ExpirationJobResult {
  success: boolean;
  expiredBuckets: number;
  totalPointsExpired: number;
  errors: string[];
}

export interface InactivityExpirationResult {
  success: boolean;
  usersAffected: number;
  bucketsExpired: number;
  totalPointsExpired: number;
  errors: string[];
}

export interface LiabilitySnapshotResult {
  success: boolean;
  snapshot?: InsertPackptsLiabilitySnapshot;
  error?: string;
}

class ExpirationEngine {
  async runExpirationJob(dryRun: boolean = false): Promise<ExpirationJobResult> {
    const errors: string[] = [];
    let expiredBuckets = 0;
    let totalPointsExpired = 0;

    const now = new Date();
    const dateKey = now.toISOString().split("T")[0];

    const expiredOpenBuckets = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          sql`${packptsBucket.expiresAt} IS NOT NULL`,
          lte(packptsBucket.expiresAt, now)
        )
      )
      .orderBy(asc(packptsBucket.expiresAt));

    for (const bucket of expiredOpenBuckets) {
      const idempotencyKey = `expire_bucket_${bucket.id}_${dateKey}`;

      try {
        const existingEntry = await db
          .select()
          .from(ledgerEntries)
          .where(eq(ledgerEntries.idempotencyKey, idempotencyKey))
          .limit(1);

        if (existingEntry.length > 0) {
          continue;
        }

        if (dryRun) {
          expiredBuckets++;
          totalPointsExpired += bucket.remainingAmount;
          continue;
        }

        const [wallet] = await db
          .select()
          .from(wallets)
          .where(eq(wallets.userId, bucket.userId))
          .limit(1);

        if (!wallet) {
          errors.push(`Wallet not found for user ${bucket.userId}`);
          continue;
        }

        let expiredAmount = 0;

        await db.transaction(async (tx) => {
          const [freshWallet] = await tx
            .select()
            .from(wallets)
            .where(eq(wallets.userId, bucket.userId))
            .for("update")
            .limit(1);

          if (!freshWallet) {
            errors.push(`Wallet not found for user ${bucket.userId} during transaction`);
            return;
          }

          const expireAmount = Math.min(bucket.remainingAmount, freshWallet.balance);

          if (expireAmount <= 0) {
            return;
          }

          const newBalance = freshWallet.balance - expireAmount;
          const newRemainingAmount = bucket.remainingAmount - expireAmount;
          const newStatus = newRemainingAmount === 0 ? "EXPIRED" : "OPEN";

          await tx.insert(ledgerEntries).values({
            walletId: freshWallet.id,
            entryType: "EXPIRE",
            amount: -expireAmount,
            balanceAfter: newBalance,
            reason: `PackPTS expiration - bucket from ${new Date(bucket.earnedAt).toLocaleDateString()}`,
            metadata: {
              bucketId: bucket.id,
              sourceType: bucket.sourceType,
              originalAmount: bucket.originalAmount,
              expiredAmount: expireAmount,
              remainingInBucket: newRemainingAmount,
              expiredAt: now.toISOString(),
            },
            idempotencyKey,
          });

          await tx
            .update(wallets)
            .set({
              balance: newBalance,
              updatedAt: now,
            })
            .where(eq(wallets.id, freshWallet.id));

          await tx
            .update(packptsBucket)
            .set({
              remainingAmount: newRemainingAmount,
              status: newStatus,
              updatedAt: now,
            })
            .where(eq(packptsBucket.id, bucket.id));

          expiredAmount = expireAmount;
        });

        if (expiredAmount > 0) {
          expiredBuckets++;
          totalPointsExpired += expiredAmount;
        }
      } catch (error) {
        errors.push(`Error expiring bucket ${bucket.id}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    return {
      success: errors.length === 0,
      expiredBuckets,
      totalPointsExpired,
      errors,
    };
  }

  async runInactivityExpiration(dryRun: boolean = false): Promise<InactivityExpirationResult> {
    const errors: string[] = [];
    let usersAffected = 0;
    let bucketsExpired = 0;
    let totalPointsExpired = 0;

    const policy = await bucketService.getCurrentPolicy();

    if (!policy || !policy.inactivityEnabled) {
      return {
        success: true,
        usersAffected: 0,
        bucketsExpired: 0,
        totalPointsExpired: 0,
        errors: ["Inactivity expiration is disabled"],
      };
    }

    const now = new Date();
    const dateKey = now.toISOString().split("T")[0];
    const inactivityThreshold = new Date(now);
    inactivityThreshold.setDate(inactivityThreshold.getDate() - policy.inactivityDays);

    const minAgeDate = new Date(now);
    minAgeDate.setDate(minAgeDate.getDate() - policy.inactivityMinAgeDays);

    const usersWithOldBuckets = await db
      .selectDistinct({ userId: packptsBucket.userId })
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          lte(packptsBucket.earnedAt, minAgeDate)
        )
      );

    for (const { userId } of usersWithOldBuckets) {
      try {
        const [wallet] = await db
          .select()
          .from(wallets)
          .where(eq(wallets.userId, userId))
          .limit(1);

        if (!wallet) continue;

        const lastActivity = await db
          .select({ createdAt: ledgerEntries.createdAt })
          .from(ledgerEntries)
          .where(eq(ledgerEntries.walletId, wallet.id))
          .orderBy(sql`${ledgerEntries.createdAt} DESC`)
          .limit(1);

        const lastActivityDate = lastActivity.length > 0 && lastActivity[0].createdAt 
          ? new Date(lastActivity[0].createdAt) 
          : null;

        if (lastActivityDate && lastActivityDate > inactivityThreshold) {
          continue;
        }

        const eligibleBuckets = await db
          .select()
          .from(packptsBucket)
          .where(
            and(
              eq(packptsBucket.userId, userId),
              eq(packptsBucket.status, "OPEN"),
              gt(packptsBucket.remainingAmount, 0),
              lte(packptsBucket.earnedAt, minAgeDate)
            )
          );

        if (eligibleBuckets.length === 0) continue;

        let userPointsExpired = 0;
        for (const bucket of eligibleBuckets) {
          const idempotencyKey = `inactivity_expire_${bucket.id}_${dateKey}`;

          const existingEntry = await db
            .select()
            .from(ledgerEntries)
            .where(eq(ledgerEntries.idempotencyKey, idempotencyKey))
            .limit(1);

          if (existingEntry.length > 0) continue;

          if (dryRun) {
            bucketsExpired++;
            totalPointsExpired += bucket.remainingAmount;
            userPointsExpired += bucket.remainingAmount;
            continue;
          }

          const [wallet] = await db
            .select()
            .from(wallets)
            .where(eq(wallets.userId, userId))
            .limit(1);

          if (!wallet) continue;

          await db.transaction(async (tx) => {
            const newBalance = wallet.balance - bucket.remainingAmount;

            if (newBalance < 0) return;

            await tx.insert(ledgerEntries).values({
              walletId: wallet.id,
              entryType: "EXPIRE",
              amount: -bucket.remainingAmount,
              balanceAfter: newBalance,
              reason: `PackPTS inactivity expiration - ${policy.inactivityDays} days inactive`,
              metadata: {
                bucketId: bucket.id,
                sourceType: bucket.sourceType,
                inactivityDays: policy.inactivityDays,
                lastActivityDate: lastActivityDate?.toISOString() || null,
              },
              idempotencyKey,
            });

            await tx
              .update(wallets)
              .set({
                balance: newBalance,
                updatedAt: now,
              })
              .where(eq(wallets.id, wallet.id));

            await tx
              .update(packptsBucket)
              .set({
                remainingAmount: 0,
                status: "EXPIRED",
                updatedAt: now,
              })
              .where(eq(packptsBucket.id, bucket.id));
          });

          bucketsExpired++;
          totalPointsExpired += bucket.remainingAmount;
          userPointsExpired += bucket.remainingAmount;
        }

        if (userPointsExpired > 0) {
          usersAffected++;
        }
      } catch (error) {
        errors.push(`Error processing user ${userId}: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    return {
      success: errors.length === 0,
      usersAffected,
      bucketsExpired,
      totalPointsExpired,
      errors,
    };
  }

  async createLiabilitySnapshot(): Promise<LiabilitySnapshotResult> {
    const now = new Date();
    const asOfDate = now.toISOString().split("T")[0];

    const existingSnapshot = await db
      .select()
      .from(packptsLiabilitySnapshot)
      .where(eq(packptsLiabilitySnapshot.asOfDate, asOfDate))
      .limit(1);

    if (existingSnapshot.length > 0) {
      return {
        success: true,
        snapshot: existingSnapshot[0] as InsertPackptsLiabilitySnapshot,
      };
    }

    const allOpenBuckets = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0)
        )
      );

    let totalOutstanding = 0;
    let outstandingEarned = 0;
    let outstandingPurchased = 0;
    let outstandingBonus = 0;
    let expiring30d = 0;
    let expiring60d = 0;
    let expiring90d = 0;
    let aged0_30 = 0;
    let aged31_90 = 0;
    let aged91_180 = 0;
    let aged181_365 = 0;
    let aged366Plus = 0;

    const in30Days = new Date(now);
    in30Days.setDate(in30Days.getDate() + 30);
    const in60Days = new Date(now);
    in60Days.setDate(in60Days.getDate() + 60);
    const in90Days = new Date(now);
    in90Days.setDate(in90Days.getDate() + 90);

    for (const bucket of allOpenBuckets) {
      totalOutstanding += bucket.remainingAmount;

      switch (bucket.sourceType) {
        case "EARNED":
          outstandingEarned += bucket.remainingAmount;
          break;
        case "PURCHASED":
          outstandingPurchased += bucket.remainingAmount;
          break;
        case "BONUS":
          outstandingBonus += bucket.remainingAmount;
          break;
      }

      if (bucket.expiresAt) {
        const expiresAt = new Date(bucket.expiresAt);
        if (expiresAt <= in30Days) {
          expiring30d += bucket.remainingAmount;
        }
        if (expiresAt <= in60Days) {
          expiring60d += bucket.remainingAmount;
        }
        if (expiresAt <= in90Days) {
          expiring90d += bucket.remainingAmount;
        }
      }

      const earnedAt = new Date(bucket.earnedAt);
      const ageDays = Math.floor((now.getTime() - earnedAt.getTime()) / (1000 * 60 * 60 * 24));

      if (ageDays <= 30) {
        aged0_30 += bucket.remainingAmount;
      } else if (ageDays <= 90) {
        aged31_90 += bucket.remainingAmount;
      } else if (ageDays <= 180) {
        aged91_180 += bucket.remainingAmount;
      } else if (ageDays <= 365) {
        aged181_365 += bucket.remainingAmount;
      } else {
        aged366Plus += bucket.remainingAmount;
      }
    }

    const breakageEstimatePct = DEFAULT_EXPIRATION_POLICY.breakageEstimatePct;
    const projectedBreakage = Math.floor((totalOutstanding * breakageEstimatePct) / 100);

    const [snapshot] = await db
      .insert(packptsLiabilitySnapshot)
      .values({
        asOfDate,
        totalOutstanding,
        outstandingEarned,
        outstandingPurchased,
        outstandingBonus,
        expiring30d,
        expiring60d,
        expiring90d,
        aged0_30,
        aged31_90,
        aged91_180,
        aged181_365,
        aged366Plus,
        breakageEstimatePct,
        projectedBreakage,
        metadata: {
          bucketCount: allOpenBuckets.length,
          generatedAt: now.toISOString(),
        },
      })
      .returning();

    return {
      success: true,
      snapshot: snapshot as InsertPackptsLiabilitySnapshot,
    };
  }

  async getLatestLiabilitySnapshot(): Promise<InsertPackptsLiabilitySnapshot | null> {
    const result = await db
      .select()
      .from(packptsLiabilitySnapshot)
      .orderBy(sql`${packptsLiabilitySnapshot.asOfDate} DESC`)
      .limit(1);

    return result.length > 0 ? (result[0] as InsertPackptsLiabilitySnapshot) : null;
  }

  async getGracePeriodBuckets(userId: string): Promise<PackptsBucket[]> {
    const policy = await bucketService.getCurrentPolicy();
    if (!policy) return [];

    const now = new Date();
    const gracePeriodEnd = new Date(now);
    gracePeriodEnd.setDate(gracePeriodEnd.getDate() + policy.gracePeriodDays);

    return await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          sql`${packptsBucket.expiresAt} IS NOT NULL`,
          gt(packptsBucket.expiresAt, now),
          lte(packptsBucket.expiresAt, gracePeriodEnd)
        )
      )
      .orderBy(asc(packptsBucket.expiresAt));
  }

  async getExpirationPolicy(): Promise<PackptsExpirationPolicy | null> {
    return bucketService.getCurrentPolicy();
  }

  async updateExpirationPolicy(
    updates: Partial<PackptsExpirationPolicy>
  ): Promise<PackptsExpirationPolicy | null> {
    const currentPolicy = await bucketService.getCurrentPolicy();

    if (!currentPolicy) {
      return null;
    }

    const [updated] = await db
      .update(packptsExpirationPolicy)
      .set({
        ...updates,
        updatedAt: new Date(),
      })
      .where(eq(packptsExpirationPolicy.id, currentPolicy.id))
      .returning();

    return updated;
  }
}

export const expirationEngine = new ExpirationEngine();

