import crypto from "crypto";
import { db } from "../../db";
import { outboundClicks } from "@shared/schema";
import type { MarketplaceSource, OutboundTokenPayload } from "./types";

const TOKEN_EXPIRY_SECONDS = 3600;

function getTokenSecret(): string {
  const secret = process.env.OUTBOUND_SECRET;
  if (!secret) {
    throw new Error("[Outbound] OUTBOUND_SECRET environment variable is required for secure token signing");
  }
  return secret;
}

export function generateOutboundToken(payload: Omit<OutboundTokenPayload, "expiresAt">): string {
  const tokenPayload: OutboundTokenPayload = {
    ...payload,
    expiresAt: Date.now() + TOKEN_EXPIRY_SECONDS * 1000,
  };

  const data = JSON.stringify(tokenPayload);
  const encoded = Buffer.from(data).toString("base64url");
  const signature = crypto
    .createHmac("sha256", getTokenSecret())
    .update(encoded)
    .digest("base64url");

  return `${encoded}.${signature}`;
}

export function validateOutboundToken(token: string): OutboundTokenPayload | null {
  try {
    const parts = token.split(".");
    if (parts.length !== 2) return null;

    const [encoded, signature] = parts;
    const expectedSignature = crypto
      .createHmac("sha256", getTokenSecret())
      .update(encoded)
      .digest("base64url");

    if (signature !== expectedSignature) return null;

    const data = Buffer.from(encoded, "base64url").toString("utf-8");
    const payload: OutboundTokenPayload = JSON.parse(data);

    if (payload.expiresAt < Date.now()) return null;

    return payload;
  } catch {
    return null;
  }
}

/**
 * Hash an IP address for privacy-safe storage
 */
export function hashIp(ip: string): string {
  const salt = process.env.OUTBOUND_SECRET || "packpts-salt";
  return crypto
    .createHmac("sha256", salt)
    .update(ip)
    .digest("hex");
}

export interface OutboundClickData {
  source: MarketplaceSource;
  listingId: string;
  destinationUrl: string;
  outboundUrl?: string;
  customId?: string;
  userId: string | null;
  sessionId: string | null;
  ip: string | null;
  userAgent: string | null;
  referrer?: string | null;
  pagePath?: string | null;
  cardSetId?: string | null;
  cardId?: string | null;
}

export async function logOutboundClick(data: OutboundClickData): Promise<void> {
  try {
    await db.insert(outboundClicks).values({
      source: data.source,
      listingId: data.listingId,
      destinationUrl: data.destinationUrl,
      outboundUrl: data.outboundUrl,
      customId: data.customId,
      userId: data.userId,
      sessionId: data.sessionId,
      ip: null,
      ipHash: data.ip ? hashIp(data.ip) : null,
      userAgent: data.userAgent,
      referrer: data.referrer,
      pagePath: data.pagePath,
      cardSetId: data.cardSetId,
      cardId: data.cardId,
    });
  } catch (error) {
    console.error("[Outbound] Failed to log click:", error);
  }
}

// EPN Affiliate Config
const EPN_CONFIG = {
  get campId() {
    return process.env.EPN_CAMPID;
  },
  get customIdPrefix() {
    return process.env.EPN_CUSTOMID_PREFIX || "packpts";
  },
  get mkcid() {
    return process.env.EPN_MKCID;
  },
  get mksid() {
    return process.env.EPN_MKSID;
  },
};

/**
 * Build a fully-qualified EPN affiliate URL with tracking parameters
 */
export function buildEpnEbayUrl(opts: {
  baseEbayUrl: string;
  campid: string;
  customid: string;
  mkcid?: string;
  mksid?: string;
}): string {
  const urlObj = new URL(opts.baseEbayUrl);
  urlObj.searchParams.set("campid", opts.campid);
  urlObj.searchParams.set("toolid", "10001");
  urlObj.searchParams.set("customid", opts.customid);

  if (opts.mkcid) {
    urlObj.searchParams.set("mkcid", opts.mkcid);
  }
  if (opts.mksid) {
    urlObj.searchParams.set("mksid", opts.mksid);
  }

  return urlObj.toString();
}

/**
 * Generate a unique customId for EPN tracking attribution
 * Format: prefix:u_userId:i_itemId:t_timestamp
 */
export function generateEpnCustomId(
  userId: string | null,
  itemId: string
): string {
  const prefix = EPN_CONFIG.customIdPrefix;
  const userPart = userId ? `u_${userId.substring(0, 12)}` : "u_anon";
  const itemPart = `i_${itemId.substring(0, 16)}`;
  const timePart = `t_${Date.now()}`;
  return `${prefix}:${userPart}:${itemPart}:${timePart}`;
}

/**
 * Normalize an eBay item reference to a canonical URL
 */
export function normalizeEbayUrl(itemIdOrUrl: string): string {
  // If it's just digits, it's an item ID
  if (/^\d+$/.test(itemIdOrUrl)) {
    return `https://www.ebay.com/itm/${itemIdOrUrl}`;
  }
  // Otherwise treat as URL
  return itemIdOrUrl;
}

export function applyEpnTracking(
  url: string, 
  userId: string | null = null,
  itemId?: string
): string {
  const campaignId = EPN_CONFIG.campId;
  if (!campaignId) {
    console.warn("[EPN] Missing EPN_CAMPID - affiliate tracking disabled");
    return url;
  }

  // Extract item ID from URL if not provided
  const extractedItemId = itemId || extractItemIdFromUrl(url) || "unknown";

  const customId = generateEpnCustomId(userId, extractedItemId);

  return buildEpnEbayUrl({
    baseEbayUrl: url,
    campid: campaignId,
    customid: customId,
    mkcid: EPN_CONFIG.mkcid,
    mksid: EPN_CONFIG.mksid,
  });
}

/**
 * Extract eBay item ID from a URL
 */
function extractItemIdFromUrl(url: string): string | null {
  try {
    const match = url.match(/\/itm\/(\d+)/);
    return match ? match[1] : null;
  } catch {
    return null;
  }
}

export function generateListingWithOutboundUrl(
  listing: { source: MarketplaceSource; listingId: string; url: string },
  baseUrl: string
): string {
  const token = generateOutboundToken({
    source: listing.source,
    listingId: listing.listingId,
    destinationUrl: listing.url,
  });

  return `${baseUrl}/out/${listing.source}/${listing.listingId}?token=${encodeURIComponent(token)}`;
}

server/services/bucketService.ts.content:
import { db } from "../db";
import {
  packptsBucket,
  packptsExpirationPolicy,
  packptsSpendAllocation,
  ledgerEntries,
  type PackptsBucket,
  type PackptsExpirationPolicy,
  type BucketSourceType,
} from "@shared/schema";
import { eq, and, asc, isNull, lte, gt, sql } from "drizzle-orm";

export interface BucketCreationResult {
  success: boolean;
  bucket?: PackptsBucket;
  error?: string;
}

export interface SpendAllocationResult {
  success: boolean;
  allocations?: Array<{ bucketId: string; amount: number }>;
  error?: string;
}

export interface UserExpirationInfo {
  totalBalance: number;
  expiringNext30Days: number;
  expiringNext60Days: number;
  expiringNext90Days: number;
  nextExpirationDate: Date | null;
  nextExpirationAmount: number;
  bucketsBySource: {
    earned: number;
    purchased: number;
    bonus: number;
    adjustment: number;
  };
}

export interface WeeklyExpiration {
  weekStart: string;
  weekEnd: string;
  amount: number;
}

class BucketService {
  async getCurrentPolicy(): Promise<PackptsExpirationPolicy | null> {
    const result = await db
      .select()
      .from(packptsExpirationPolicy)
      .where(
        and(
          eq(packptsExpirationPolicy.enabled, true),
          lte(packptsExpirationPolicy.effectiveFrom, new Date())
        )
      )
      .orderBy(sql`${packptsExpirationPolicy.effectiveFrom} DESC`)
      .limit(1);

    return result.length > 0 ? result[0] : null;
  }

  calculateExpirationDate(
    sourceType: BucketSourceType,
    earnedAt: Date,
    policy: PackptsExpirationPolicy,
    overrideDays?: number
  ): Date | null {
    let daysToExpire: number | null = null;

    if (overrideDays !== undefined) {
      daysToExpire = overrideDays;
    } else {
      switch (sourceType) {
        case "EARNED":
          daysToExpire = policy.earnedDaysToExpire;
          break;
        case "PURCHASED":
          daysToExpire = policy.purchasedDaysToExpire;
          break;
        case "BONUS":
          daysToExpire = policy.bonusDefaultDaysToExpire;
          break;
        case "ADJUSTMENT":
          daysToExpire = null;
          break;
      }
    }

    if (daysToExpire === null) {
      return null;
    }

    const expiresAt = new Date(earnedAt);
    expiresAt.setDate(expiresAt.getDate() + daysToExpire);
    return expiresAt;
  }

  async createBucket(
    userId: string,
    amount: number,
    sourceType: BucketSourceType,
    ledgerEntryId: string,
    metadata?: Record<string, unknown>,
    overrideExpireDays?: number,
    txOrDb?: any
  ): Promise<BucketCreationResult> {
    if (amount <= 0) {
      return { success: false, error: "Amount must be positive" };
    }

    const executor = txOrDb ?? db;

    const policy = await this.getCurrentPolicy();
    const earnedAt = new Date();
    let expiresAt: Date | null = null;

    if (policy) {
      expiresAt = this.calculateExpirationDate(
        sourceType,
        earnedAt,
        policy,
        overrideExpireDays
      );
    }

    const [bucket] = await executor
      .insert(packptsBucket)
      .values({
        userId,
        sourceType,
        originalAmount: amount,
        remainingAmount: amount,
        earnedAt,
        expiresAt,
        createdFromLedgerEntryId: ledgerEntryId,
        status: "OPEN",
        metadata: metadata || null,
      })
      .returning();

    return { success: true, bucket };
  }

  async getUserOpenBuckets(userId: string): Promise<PackptsBucket[]> {
    return await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0)
        )
      )
      .orderBy(
        asc(packptsBucket.expiresAt),
        asc(packptsBucket.earnedAt)
      );
  }

  async getUserOpenBucketsFIFO(userId: string): Promise<PackptsBucket[]> {
    const bucketsWithExpiry = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          sql`${packptsBucket.expiresAt} IS NOT NULL`
        )
      )
      .orderBy(asc(packptsBucket.expiresAt), asc(packptsBucket.earnedAt));

    const bucketsWithoutExpiry = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          isNull(packptsBucket.expiresAt)
        )
      )
      .orderBy(asc(packptsBucket.earnedAt));

    return [...bucketsWithExpiry, ...bucketsWithoutExpiry];
  }

  async allocateSpend(
    userId: string,
    amount: number,
    spendLedgerEntryId: string,
    tx?: any
  ): Promise<SpendAllocationResult> {
    const executor = tx || db;

    const buckets = await this.getUserOpenBucketsFIFO(userId);
    let remainingToAllocate = amount;
    const allocations: Array<{ bucketId: string; amount: number }> = [];

    for (const bucket of buckets) {
      if (remainingToAllocate <= 0) break;

      const allocateAmount = Math.min(bucket.remainingAmount, remainingToAllocate);

      await executor
        .update(packptsBucket)
        .set({
          remainingAmount: bucket.remainingAmount - allocateAmount,
          status: bucket.remainingAmount - allocateAmount === 0 ? "DEPLETED" : "OPEN",
          updatedAt: new Date(),
        })
        .where(eq(packptsBucket.id, bucket.id));

      await executor.insert(packptsSpendAllocation).values({
        spendLedgerEntryId,
        bucketId: bucket.id,
        amount: allocateAmount,
      });

      allocations.push({ bucketId: bucket.id, amount: allocateAmount });
      remainingToAllocate -= allocateAmount;
    }

    if (remainingToAllocate > 0) {
      return {
        success: false,
        error: `Could only allocate ${amount - remainingToAllocate} of ${amount} from buckets`,
      };
    }

    return { success: true, allocations };
  }

  async getUserExpirationInfo(userId: string): Promise<UserExpirationInfo> {
    const now = new Date();
    const in30Days = new Date(now);
    in30Days.setDate(in30Days.getDate() + 30);
    const in60Days = new Date(now);
    in60Days.setDate(in60Days.getDate() + 60);
    const in90Days = new Date(now);
    in90Days.setDate(in90Days.getDate() + 90);

    const buckets = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0)
        )
      );

    let totalBalance = 0;
    let expiringNext30Days = 0;
    let expiringNext60Days = 0;
    let expiringNext90Days = 0;
    let nextExpirationDate: Date | null = null;
    let nextExpirationAmount = 0;
    const bucketsBySource = { earned: 0, purchased: 0, bonus: 0, adjustment: 0 };

    for (const bucket of buckets) {
      totalBalance += bucket.remainingAmount;

      const sourceKey = bucket.sourceType.toLowerCase() as keyof typeof bucketsBySource;
      if (bucketsBySource.hasOwnProperty(sourceKey)) {
        bucketsBySource[sourceKey] += bucket.remainingAmount;
      }

      if (bucket.expiresAt) {
        const expiresAt = new Date(bucket.expiresAt);

        if (expiresAt <= in30Days) {
          expiringNext30Days += bucket.remainingAmount;
        }
        if (expiresAt <= in60Days) {
          expiringNext60Days += bucket.remainingAmount;
        }
        if (expiresAt <= in90Days) {
          expiringNext90Days += bucket.remainingAmount;
        }

        if (expiresAt > now && (!nextExpirationDate || expiresAt < nextExpirationDate)) {
          nextExpirationDate = expiresAt;
          nextExpirationAmount = bucket.remainingAmount;
        } else if (nextExpirationDate && expiresAt.getTime() === nextExpirationDate.getTime()) {
          nextExpirationAmount += bucket.remainingAmount;
        }
      }
    }

    return {
      totalBalance,
      expiringNext30Days,
      expiringNext60Days,
      expiringNext90Days,
      nextExpirationDate,
      nextExpirationAmount,
      bucketsBySource,
    };
  }

  async getUpcomingExpirations(userId: string, days: number = 90): Promise<WeeklyExpiration[]> {
    const now = new Date();
    const endDate = new Date(now);
    endDate.setDate(endDate.getDate() + days);

    const buckets = await db
      .select()
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN"),
          gt(packptsBucket.remainingAmount, 0),
          sql`${packptsBucket.expiresAt} IS NOT NULL`,
          sql`${packptsBucket.expiresAt} > ${now}`,
          sql`${packptsBucket.expiresAt} <= ${endDate}`
        )
      )
      .orderBy(asc(packptsBucket.expiresAt));

    const weeklyMap = new Map<string, number>();

    for (const bucket of buckets) {
      if (!bucket.expiresAt) continue;

      const expiresAt = new Date(bucket.expiresAt);
      const weekStart = new Date(expiresAt);
      weekStart.setDate(weekStart.getDate() - weekStart.getDay());
      weekStart.setHours(0, 0, 0, 0);

      const weekKey = weekStart.toISOString().split("T")[0];
      weeklyMap.set(weekKey, (weeklyMap.get(weekKey) || 0) + bucket.remainingAmount);
    }

    const result: WeeklyExpiration[] = [];
    for (const [weekStartStr, amount] of weeklyMap) {
      const weekStart = new Date(weekStartStr);
      const weekEnd = new Date(weekStart);
      weekEnd.setDate(weekEnd.getDate() + 6);

      result.push({
        weekStart: weekStartStr,
        weekEnd: weekEnd.toISOString().split("T")[0],
        amount,
      });
    }

    return result.sort((a, b) => a.weekStart.localeCompare(b.weekStart));
  }

  async getTotalUserBucketBalance(userId: string): Promise<number> {
    const result = await db
      .select({
        total: sql<number>`COALESCE(SUM(${packptsBucket.remainingAmount}), 0)`,
      })
      .from(packptsBucket)
      .where(
        and(
          eq(packptsBucket.userId, userId),
          eq(packptsBucket.status, "OPEN")
        )
      );

    return Number(result[0]?.total || 0);
  }

  mapLedgerTypeToSourceType(entryType: string): BucketSourceType {
    switch (entryType) {
      case "EARN":
      case "STREAK_EARN":
        return "EARNED";
      case "PURCHASE_CREDIT":
        return "PURCHASED";
      case "BONUS":
        return "BONUS";
      case "ADJUST":
        return "ADJUSTMENT";
      default:
        return "EARNED";
    }
  }
}

export const bucketService = new BucketService();

