import { useState, useEffect, useCallback, useRef } from "react";
import { useLocation, useRoute } from "wouter";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Trophy, User, Check, X, Loader2, Home, RotateCcw } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useWebSocket } from "@/hooks/useWebSocket";
import { useAuth } from "@/hooks/use-auth";
import { queryClient } from "@/lib/queryClient";
import { DAILY_PROGRESS_QUERY_KEY } from "@/hooks/use-daily-progress";
import { GameCard } from "@/components/GameCard";

function getMatchSecret(): string | null {
  return localStorage.getItem("packpoints_match_secret");
}

function clearMatchSecret(): void {
  localStorage.removeItem("packpoints_match_secret");
}

interface Participant {
  userId: string;
  username: string;
  score: number;
  correctAnswers: number;
  hasAnsweredCurrent: boolean;
}

interface MatchState {
  matchId: string;
  lobbyId: string;
  status: "LOBBY" | "INITIALIZING" | "ACTIVE" | "FINISHED" | "CANCELLED";
  currentQuestionIndex: number;
  totalQuestions: number;
  gameSetId?: string;
  currentQuestion: {
    card: {
      id: string;
      imageUrl: string;
      team: string;
      year: number;
      setName: string;
      cardNumber: string;
    };
    options: string[];
    pointValue: number;
  } | null;
  participants: Participant[];
  winner?: string;
  endReason?: string;
}

interface MatchEndEvent {
  matchId: string;
  reason: string;
  status: "FINISHED" | "CANCELLED";
  winner?: string;
  winnerUserId?: string;
  result?: "PENDING" | "HOST_WIN" | "GUEST_WIN" | "TIE";
  hostCorrect?: number;
  guestCorrect?: number;
  participants: {
    userId: string;
    username: string;
    score: number;
    correctAnswers: number;
  }[];
}

interface AnswerStatus {
  matchId: string;
  idx: number;
  answeredCount: number;
  required: number;
}

export default function Match() {
  const [, navigate] = useLocation();
  const [, params] = useRoute("/match/:matchId");
  const matchId = params?.matchId;
  const { user, isLoading: authLoading } = useAuth();

  const [matchState, setMatchState] = useState<MatchState | null>(null);
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [lockedIn, setLockedIn] = useState(false);
  const [answerResult, setAnswerResult] = useState<{ correct: boolean; correctAnswer: string } | null>(null);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [pendingClientMsgId, setPendingClientMsgId] = useState<string | null>(null);
  const [imageError, setImageError] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);
  const [matchEnded, setMatchEnded] = useState<MatchEndEvent | null>(null);
  const [answerStatus, setAnswerStatus] = useState<AnswerStatus | null>(null);
  const [seedVersion, setSeedVersion] = useState(1);
  const [imageRetryCount, setImageRetryCount] = useState(0);
  const [replacementPending, setReplacementPending] = useState(false);
  const [showReplaceButton, setShowReplaceButton] = useState(false);
  const { toast } = useToast();

  const fallbackTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const resyncTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const submittingRef = useRef(false);
  const lockedInRef = useRef(false);
  const pendingClientMsgIdRef = useRef<string | null>(null);
  const hasJoinedMatchRef = useRef(false);
  const processedAnswerForIdx = useRef<number>(-1);

  const userId = user?.id || "";
  const username = user?.username || user?.firstName || "Player";

  const handleMessage = useCallback((message: any) => {
    switch (message.type) {
      case "match_started":
      case "match_state":
      case "next_question":
        // Clear waiting state - server says we're moving to next question
        setMatchState(message.payload);
        setSelectedChoice(null);
        setSubmitting(false);
        submittingRef.current = false;
        setLockedIn(false);
        lockedInRef.current = false;
        setAnswerResult(null);
        setSubmitError(null);
        setPendingClientMsgId(null);
        pendingClientMsgIdRef.current = null;
        setImageError(false);
        setImageLoaded(false);
        setImageRetryCount(0);
        setShowReplaceButton(false);
        setReplacementPending(false);
        processedAnswerForIdx.current = -1;
        // Extract seedVersion from currentQuestion if available, default to 1
        if (message.payload.currentQuestion?.seedVersion) {
          setSeedVersion(message.payload.currentQuestion.seedVersion);
        } else {
          setSeedVersion(1);
        }
        // Use server-provided answerStatus from next_question payload (always includes answeredCount:0, required:2)
        if (message.payload.answerStatus) {
          setAnswerStatus(message.payload.answerStatus);
        } else {
          // Fallback: set to 0/2 for the new question index
          setAnswerStatus({
            matchId: message.payload.matchId || matchId || '',
            idx: message.payload.currentQuestionIndex ?? 0,
            answeredCount: 0,
            required: 2,
          });
        }
        if (fallbackTimeoutRef.current) {
          clearTimeout(fallbackTimeoutRef.current);
          fallbackTimeoutRef.current = null;
        }
        if (resyncTimeoutRef.current) {
          clearTimeout(resyncTimeoutRef.current);
          resyncTimeoutRef.current = null;
        }
        break;
      case "question_replaced":
        // Card was replaced - update current question WITHOUT changing idx
        console.log("[Match] question_replaced received:", message.payload);
        setReplacementPending(false);
        setImageError(false);
        setImageLoaded(false);
        setImageRetryCount(0);
        setShowReplaceButton(false);
        setSeedVersion(message.payload.seedVersion);
        // Update matchState with new question
        setMatchState((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            currentQuestion: {
              card: message.payload.card,
              options: message.payload.choices,
              pointValue: message.payload.pointValue,
            },
          };
        });
        toast({
          title: "Card replaced",
          description: "A new card has been loaded for this question.",
        });
        break;
      case "question_replace_error":
        console.log("[Match] question_replace_error:", message.payload);
        setReplacementPending(false);
        setShowReplaceButton(true);
        toast({
          title: "Unable to replace card",
          description: message.payload.error || "Please try again.",
          variant: "destructive",
        });
        break;
      case "answer_status":
        // Server tells us how many have answered for this idx
        // Update answer status to derive waiting state from server
        setAnswerStatus(message.payload);
        break;
      case "answer_ack":
        if (message.payload.clientMsgId === pendingClientMsgIdRef.current) {
          if (fallbackTimeoutRef.current) {
            clearTimeout(fallbackTimeoutRef.current);
            fallbackTimeoutRef.current = null;
          }

          if (message.payload.status === "ACCEPTED") {
            setLockedIn(true);
            lockedInRef.current = true;
            setSubmitting(false);
            submittingRef.current = false;
            setSubmitError(null);
            setPendingClientMsgId(null);
            pendingClientMsgIdRef.current = null;

            // CRITICAL: Update answerStatus from answer_ack payload
            // This ensures the client always reflects the server's answer count
            if (message.payload.answeredCount !== undefined && message.payload.required !== undefined) {
              setAnswerStatus({
                matchId: message.payload.matchId || matchId || '',
                idx: message.payload.idx,
                answeredCount: message.payload.answeredCount,
                required: message.payload.required,
              });
            }
          } else {
            setSubmitting(false);
            submittingRef.current = false;
            setLockedIn(false);
            lockedInRef.current = false;
            setPendingClientMsgId(null);
            pendingClientMsgIdRef.current = null;

            const { reason, serverStatus } = message.payload;

            if (reason === "match_cancelled" || reason === "match_finished" || 
                serverStatus === "CANCELLED" || serverStatus === "FINISHED") {
              setSubmitError("Match has ended");
              return;
            }

            if (reason === "stale_index" || reason === "match_initializing" || reason === "match_not_started") {
              setSubmitError("Out of sync. Tap Resync.");
              return;
            }

            const errorMessages: Record<string, string> = {
              match_not_found: "Match not found",
              not_participant: "You are not a participant in this match",
              unauthorized: "Session expired. Please refresh the page.",
              missing_session: "Session expired. Please refresh and try again.",
              not_in_match: "You are not in this match",
              bad_payload: "Invalid submission. Please try again.",
            };
            setSubmitError(errorMessages[reason] || reason || "Failed to submit");
          }
        }
        break;
      case "answer_result": {
        const ackIdx = message.payload.idx ?? matchState?.currentQuestionIndex ?? -1;
        if (processedAnswerForIdx.current === ackIdx) {
          console.log(`[Match] Ignoring duplicate answer_result for idx=${ackIdx}`);
          break;
        }
        processedAnswerForIdx.current = ackIdx;
        setAnswerResult(message.payload);
        if (message.payload.correct) {
          queryClient.invalidateQueries({ queryKey: DAILY_PROGRESS_QUERY_KEY });
        }
        break;
      }
      case "participant_answered":
        setMatchState((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            participants: message.payload.participants,
          };
        });
        // Also update answerStatus from participant_answered as a fallback
        if (message.payload.participants && message.payload.idx !== undefined) {
          const answeredCount = message.payload.participants.filter((p: any) => p.hasAnsweredCurrent).length;
          const required = message.payload.participants.length;
          setAnswerStatus({
            matchId: message.payload.matchId || matchId || '',
            idx: message.payload.idx,
            answeredCount,
            required,
          });
        }
        break;
      case "match_completed":
      case "match_end":
        clearMatchSecret();
        setMatchEnded(message.payload);
        setMatchState((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            status: message.payload.status,
            winner: message.payload.winner,
            endReason: message.payload.reason,
            participants: message.payload.participants.map((p: any) => ({
              ...prev.participants.find((pp) => pp.userId === p.userId) || {},
              ...p,
            })),
          };
        });
        queryClient.invalidateQueries({ queryKey: DAILY_PROGRESS_QUERY_KEY });
        break;
      case "participant_disconnected":
        toast({ 
          title: "Opponent Disconnected", 
          description: `${message.payload.username} has left the match.`,
          variant: "destructive" 
        });
        break;
      case "error":
        toast({ title: "Error", description: message.message, variant: "destructive" });
        break;
    }
  }, [toast]);

  const handleWsClose = useCallback(() => {
    hasJoinedMatchRef.current = false;
  }, []);

  const { isConnected, connect, send, on } = useWebSocket({ onMessage: handleMessage, onClose: handleWsClose });

  useEffect(() => {
    if (!matchId || !userId || authLoading) return;
    connect();
  }, [matchId, userId, authLoading, connect]);

  // Auto-reconnect on connection drop during active match
  useEffect(() => {
    if (!isConnected && matchId && userId && !authLoading && !matchEnded) {
      const reconnectTimer = setTimeout(() => {
        console.log("[Match] Auto-reconnecting after connection drop");
        connect();
      }, 2000);
      return () => clearTimeout(reconnectTimer);
    }
  }, [isConnected, matchId, userId, authLoading, matchEnded, connect]);

  useEffect(() => {
    if (isConnected && matchId && userId && !hasJoinedMatchRef.current) {
      const matchSecret = getMatchSecret();
      console.log("[Match] Attempting join_match:", { matchId, userId, hasSecret: !!matchSecret });
      if (matchSecret) {
        hasJoinedMatchRef.current = true;
        console.log("[Match] Sending join_match with membershipSecret");
        send("join_match", { 
          matchId, 
          userId, 
          username, 
          membershipSecret: matchSecret 
        });
      } else {
        hasJoinedMatchRef.current = true;
        console.log("[Match] No secret, sending ready_next");
        send("ready_next", { matchId });
      }
    }
  }, [isConnected, matchId, send, userId, username]);

  useEffect(() => {
    if (!isConnected || !matchId || matchEnded) return;

    if (matchState && !matchState.currentQuestion && matchState.status === "ACTIVE") {
      const resyncTimeout = setTimeout(() => {
        send("match_resync", { matchId });
      }, 5000);

      return () => clearTimeout(resyncTimeout);
    }
  }, [isConnected, matchId, matchState, matchEnded, send]);

  // Auto-resync fallback: if stuck waiting for opponent for 8 seconds, trigger resync
  // This is placed after the opponent variable is declared
  const opponentHasAnswered = matchState?.participants.find((p) => p.userId !== userId)?.hasAnsweredCurrent;

  useEffect(() => {
    if (!isConnected || !matchId || matchEnded) return;

    // We're waiting if: lockedIn with answerResult, but answerStatus shows 1/2 or no next_question received
    const isWaiting = lockedIn && answerResult && 
      (answerStatus?.answeredCount === 1 || (!answerStatus && !opponentHasAnswered));

    if (isWaiting) {
      console.log("[Match] Auto-resync: starting 8s timer for stuck waiting state");
      resyncTimeoutRef.current = setTimeout(() => {
        console.log("[Match] Auto-resync: 8s elapsed, sending resync");
        send("match_resync", { matchId });
      }, 8000);

      return () => {
        if (resyncTimeoutRef.current) {
          clearTimeout(resyncTimeoutRef.current);
          resyncTimeoutRef.current = null;
        }
      };
    }
  }, [isConnected, matchId, matchEnded, lockedIn, answerResult, answerStatus, opponentHasAnswered, send]);

  const handleSelectChoice = (choice: string) => {
    if (lockedIn || submitting || answerResult) return;
    setSelectedChoice(choice);
    setSubmitError(null);
  };

  const submitAnswer = async () => {
    if (!selectedChoice || !matchState || lockedInRef.current || submittingRef.current || pendingClientMsgIdRef.current) return;

    setSubmitting(true);
    submittingRef.current = true;
    setSubmitError(null);

    const clientMsgId = crypto.randomUUID();
    setPendingClientMsgId(clientMsgId);
    pendingClientMsgIdRef.current = clientMsgId;

    const currentIdx = matchState.currentQuestionIndex;
    const currentChoice = selectedChoice;

    try {
      send("submit_answer", {
        matchId,
        userId,
        questionIndex: currentIdx,
        selectedAnswer: currentChoice,
        clientMsgId,
      });

      if (fallbackTimeoutRef.current) {
        clearTimeout(fallbackTimeoutRef.current);
      }

      fallbackTimeoutRef.current = setTimeout(async () => {
        if (submittingRef.current && !lockedInRef.current) {
          // Skip if WS already processed the answer for this question
          if (processedAnswerForIdx.current === currentIdx) {
            console.log(`[Match] HTTP fallback skipped: answer already processed for idx=${currentIdx}`);
            fallbackTimeoutRef.current = null;
            return;
          }
          try {
            const response = await fetch(`/api/matches/${matchId}/answer`, {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              credentials: "include",
              body: JSON.stringify({
                idx: currentIdx,
                selected: currentChoice,
                clientMsgId,
              }),
            });
            const data = await response.json();
            // Double-check dedup after async fetch completes
            if (processedAnswerForIdx.current === currentIdx) {
              console.log(`[Match] HTTP fallback response ignored: WS processed idx=${currentIdx} during fetch`);
              fallbackTimeoutRef.current = null;
              return;
            }
            if (data.ok) {
              processedAnswerForIdx.current = currentIdx;
              setLockedIn(true);
              lockedInRef.current = true;
              setSubmitting(false);
              submittingRef.current = false;
              setPendingClientMsgId(null);
              pendingClientMsgIdRef.current = null;
              setAnswerResult({ correct: data.correct, correctAnswer: data.correctAnswer });
            } else {
              setSubmitError(data.reason || "Failed to submit");
              setSubmitting(false);
              submittingRef.current = false;
              setPendingClientMsgId(null);
              pendingClientMsgIdRef.current = null;
            }
          } catch (error) {
            setSubmitError("Network error, please try again");
            setSubmitting(false);
            submittingRef.current = false;
            setPendingClientMsgId(null);
            pendingClientMsgIdRef.current = null;
          }
        }
        fallbackTimeoutRef.current = null;
      }, 3000);

    } catch (error) {
      setSubmitError("Failed to send answer");
      setSubmitting(false);
      submittingRef.current = false;
      setPendingClientMsgId(null);
      pendingClientMsgIdRef.current = null;
    }
  };

  const me = matchState?.participants.find((p) => p.userId === userId);
  const opponent = matchState?.participants.find((p) => p.userId !== userId);

  if (!matchState) {
    return (
      <div className="min-h-[100dvh] flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="h-8 w-8 animate-spin mx-auto mb-4" />
          <p className="text-muted-foreground">Connecting to match...</p>
        </div>
      </div>
    );
  }

  if (matchEnded && matchEnded.status === "CANCELLED") {
    const cancelReasonText: Record<string, string> = {
      no_ack: "A player failed to acknowledge the match",
      deck_empty: "Not enough cards available for this match",
      timeout: "Match timed out",
      forfeit: "A player forfeited the match",
      disconnect: "A player disconnected",
    };

    return (
      <div className="min-h-[100dvh] pb-20 md:pb-8 pt-8">
        <div className="container mx-auto px-4 max-w-lg">
          <Card>
            <CardContent className="p-8 text-center space-y-6">
              <div className="mx-auto p-4 rounded-full w-fit bg-destructive/20">
                <X className="h-12 w-12 text-destructive" />
              </div>

              <div>
                <h1 className="text-3xl font-bold mb-2" data-testid="text-match-result">
                  Match Cancelled
                </h1>
                <p className="text-muted-foreground">
                  {cancelReasonText[matchEnded.reason] || matchEnded.reason}
                </p>
              </div>

              <div className="flex flex-col gap-3">
                <Button onClick={() => navigate("/lobby")} className="gap-2" data-testid="button-return-lobby">
                  <RotateCcw className="h-4 w-4" />
                  Return to Lobby
                </Button>
                <Button variant="outline" onClick={() => navigate("/")} className="gap-2" data-testid="button-home">
                  <Home className="h-4 w-4" />
                  Home
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  if (matchEnded && matchEnded.status === "FINISHED") {
    const meResult = matchEnded.participants.find((p) => p.userId === userId);
    const opponentResult = matchEnded.participants.find((p) => p.userId !== userId);

    // Calculate winner from correctAnswers as fallback if result/winnerUserId missing
    const myCorrect = meResult?.correctAnswers ?? 0;
    const opponentCorrect = opponentResult?.correctAnswers ?? 0;

    let iWon: boolean;
    let isDraw: boolean;
    let winnerName: string | undefined;

    // Prefer server-provided result, but calculate from correctAnswers as fallback
    if (matchEnded.result === "TIE") {
      iWon = false;
      isDraw = true;
    } else if (matchEnded.winnerUserId) {
      iWon = matchEnded.winnerUserId === userId;
      isDraw = false;
      winnerName = matchEnded.winner;
    } else {
      // Fallback: calculate from correctAnswers
      console.log("[Match] Using fallback winner calculation:", { myCorrect, opponentCorrect });
      if (myCorrect > opponentCorrect) {
        iWon = true;
        isDraw = false;
        winnerName = meResult?.username || "You";
      } else if (opponentCorrect > myCorrect) {
        iWon = false;
        isDraw = false;
        winnerName = opponentResult?.username || "Opponent";
      } else {
        iWon = false;
        isDraw = true;
      }
    }

    return (
      <div className="min-h-[100dvh] pb-20 md:pb-8 pt-8">
        <div className="container mx-auto px-4 max-w-lg">
          <Card>
            <CardContent className="p-8 text-center space-y-6">
              <div className={`mx-auto p-4 rounded-full w-fit ${iWon ? "bg-yellow-500/20" : isDraw ? "bg-muted" : "bg-muted"}`}>
                <Trophy className={`h-12 w-12 ${iWon ? "text-yellow-500" : "text-muted-foreground"}`} />
              </div>

              <div>
                <h1 className="text-3xl font-bold mb-2" data-testid="text-match-result">
                  {iWon ? "You Win!" : isDraw ? "It's a Draw!" : "You Lose"}
                </h1>
                <p className="text-muted-foreground">
                  {isDraw ? "Both players got the same number correct" : `${winnerName || matchEnded.winner || "Winner"} got more correct!`}
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 rounded-lg bg-muted/50 space-y-1">
                  <p className="text-sm text-muted-foreground">Your Score</p>
                  <p className="text-3xl font-bold font-mono" data-testid="text-my-final-score">{meResult?.score || 0}</p>
                  <p className="text-sm text-muted-foreground">{meResult?.correctAnswers}/{matchState.totalQuestions} correct</p>
                </div>
                <div className="p-4 rounded-lg bg-muted/50 space-y-1">
                  <p className="text-sm text-muted-foreground">Opponent</p>
                  <p className="text-3xl font-bold font-mono" data-testid="text-opponent-final-score">{opponentResult?.score || 0}</p>
                  <p className="text-sm text-muted-foreground">{opponentResult?.correctAnswers}/{matchState.totalQuestions} correct</p>
                </div>
              </div>

              <div className="flex flex-col gap-3">
                <Button onClick={() => navigate("/lobby")} className="gap-2" data-testid="button-play-again">
                  <RotateCcw className="h-4 w-4" />
                  Play Again
                </Button>
                <Button variant="outline" onClick={() => navigate("/")} className="gap-2" data-testid="button-home">
                  <Home className="h-4 w-4" />
                  Home
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  const currentQuestion = matchState.currentQuestion;
  const progress = ((matchState.currentQuestionIndex + 1) / matchState.totalQuestions) * 100;

  return (
    <div className="min-h-[100dvh] pt-4" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom, 0px) + 96px)' }}>
      <div className="container mx-auto px-4 max-w-lg">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <div className="h-8 w-8 rounded-full bg-primary/20 flex items-center justify-center">
              <User className="h-4 w-4" />
            </div>
            <div>
              <p className="text-sm font-medium" data-testid="text-my-username">{me?.username}</p>
              <p className="text-lg font-bold font-mono" data-testid="text-my-score">{me?.score}</p>
            </div>
            {me?.hasAnsweredCurrent && (
              <Badge variant="secondary" className="ml-2">
                <Check className="h-3 w-3 mr-1" />
                Answered
              </Badge>
            )}
          </div>

          <div className="text-center">
            <Badge variant="outline">
              {matchState.currentQuestionIndex + 1} / {matchState.totalQuestions}
            </Badge>
          </div>

          <div className="flex items-center gap-2">
            {opponent?.hasAnsweredCurrent && (
              <Badge variant="secondary" className="mr-2">
                <Check className="h-3 w-3 mr-1" />
                Answered
              </Badge>
            )}
            <div className="text-right">
              <p className="text-sm font-medium" data-testid="text-opponent-username">{opponent?.username}</p>
              <p className="text-lg font-bold font-mono" data-testid="text-opponent-score">{opponent?.score}</p>
            </div>
            <div className="h-8 w-8 rounded-full bg-secondary/20 flex items-center justify-center">
              <User className="h-4 w-4" />
            </div>
          </div>
        </div>

        <Progress value={progress} className="mb-4" />

        {currentQuestion && (
          <div className="space-y-4">
            <GameCard
              key={`${matchState.currentQuestionIndex}-${seedVersion}-${imageRetryCount}`}
              imageUrl={`${currentQuestion.card.imageUrl}${currentQuestion.card.imageUrl.includes('?') ? '&' : '?'}t=${seedVersion}-${imageRetryCount}-${matchState.currentQuestionIndex}`}
              isRevealed={answerResult !== null}
              setLabel="MYSTERY CARD"
              setKey={matchState.gameSetId}
              onImageError={() => {
                if (imageRetryCount < 2) {
                  console.log(`[Match] Image load failed, retry ${imageRetryCount + 1}/2`);
                  setImageRetryCount(prev => prev + 1);
                } else {
                  console.log(`[Match] Image load failed after 2 retries, showing replace button`);
                  setImageError(true);
                  setShowReplaceButton(true);
                }
              }}
              showReplaceButton={showReplaceButton}
              replacePending={replacementPending}
              onReplace={() => {
                console.log(`[Match] Requesting card replacement: matchId=${matchId}, idx=${matchState.currentQuestionIndex}, seedVersion=${seedVersion}`);
                setReplacementPending(true);
                send("question_replace_request", {
                  matchId,
                  idx: matchState.currentQuestionIndex,
                  seedVersion,
                  reason: "image_load_failed",
                });
              }}
              cardNumber={currentQuestion.card.cardNumber}
              team={currentQuestion.card.team}
              cardId={(currentQuestion.card as any).playableCardId || currentQuestion.card.id}
              sessionId={matchId}
            />

            <div className="flex items-center justify-between">
              <Badge variant="outline">{currentQuestion.card.team}</Badge>
              <Badge>{currentQuestion.pointValue} pts</Badge>
            </div>

            <div className="grid grid-cols-2 gap-3">
              {currentQuestion.options.map((option, index) => {
                const isSelected = selectedChoice === option;
                const isCorrect = answerResult?.correctAnswer === option;
                const showResult = answerResult !== null;

                let variant: "default" | "outline" | "destructive" | "secondary" = "outline";
                if (showResult) {
                  if (isCorrect) variant = "default";
                  else if (isSelected && !isCorrect) variant = "destructive";
                } else if (isSelected) {
                  variant = "secondary";
                }

                return (
                  <Button
                    key={option}
                    variant={variant}
                    className={`h-auto py-3 px-4 text-left justify-start ${isSelected && !showResult ? "ring-2 ring-primary" : ""}`}
                    onClick={() => handleSelectChoice(option)}
                    disabled={lockedIn || submitting || showResult}
                    data-testid={`button-option-${index}`}
                  >
                    <span className="truncate">{option}</span>
                    {showResult && isCorrect && <Check className="h-4 w-4 ml-auto flex-shrink-0" />}
                    {showResult && isSelected && !isCorrect && <X className="h-4 w-4 ml-auto flex-shrink-0" />}
                  </Button>
                );
              })}
            </div>

          </div>
        )}
      </div>

      {currentQuestion && (
        <div className="fixed left-0 right-0 bottom-0 z-50 border-t bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/75">
          <div className="mx-auto max-w-lg px-4 py-3" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom, 0px) + 12px)' }}>
            {!answerResult && !lockedIn && (
              <Button
                onClick={submitAnswer}
                disabled={!selectedChoice || submitting}
                size="lg"
                className="w-full"
                data-testid="button-submit-answer"
              >
                {submitting ? (
                  <>
                    <Loader2 className="h-4 w-4 animate-spin mr-2" />
                    Submitting...
                  </>
                ) : (
                  "Submit Answer"
                )}
              </Button>
            )}
            {lockedIn && !answerResult && (
              <div className="text-center text-muted-foreground py-2">
                <Check className="h-4 w-4 inline mr-2 text-green-500" />
                Answer locked in! Waiting for result...
              </div>
            )}
            {answerResult && answerStatus && answerStatus.answeredCount < answerStatus.required && (
              <div className="text-center text-muted-foreground py-2" data-testid="text-waiting-opponent">
                <Loader2 className="h-4 w-4 animate-spin inline mr-2" />
                Waiting for opponent... ({answerStatus.answeredCount}/{answerStatus.required})
              </div>
            )}
            {answerResult && answerStatus && answerStatus.answeredCount >= answerStatus.required && (
              <div className="text-center text-muted-foreground py-2" data-testid="text-loading-next">
                <Loader2 className="h-4 w-4 animate-spin inline mr-2" />
                Loading next question...
              </div>
            )}
            {answerResult && !answerStatus && (
              <div className="text-center text-muted-foreground py-2" data-testid="text-waiting-sync">
                <Loader2 className="h-4 w-4 animate-spin inline mr-2" />
                Syncing with server...
              </div>
            )}
            {submitError && (
              <div className="mt-2 text-center text-destructive text-sm">
                {submitError}
              </div>
            )}
            {submitError && (
              <Button
                variant="outline"
                onClick={() => {
                  setSubmitError(null);
                  send("match_resync", { matchId });
                }}
                className="w-full mt-2"
                data-testid="button-resync"
              >
                <RotateCcw className="h-4 w-4 mr-2" />
                Resync
              </Button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

server/services/matches/replaceQuestion..content:
import { db } from "../../db";
import {
  matches,
  matchParticipants,
  matchQuestions,
  matchUsedCards,
  matchEvents,
  baseballCards,
  MatchStatus,
  type GameQuestion,
} from "@shared/schema";
import { eq, and, sql, notInArray } from "drizzle-orm";
import { quarantineCard, cardHasRealImage, getQuarantinedCardIds } from "../cards/imageQuality";

const MAX_REPLACES_PER_IDX = 3;
const COOLDOWN_SECONDS = 3;

export interface ReplaceQuestionResult {
  success: boolean;
  error?: string;
  errorCode?: string;
  newQuestion?: {
    idx: number;
    seedVersion: number;
    card: {
      id: string;
      imageUrl: string;
      team: string;
      year: number;
      setName: string;
      cardNumber: string;
    };
    choices: string[];
    pointValue: number;
    correctAnswer: string;
  };
  matchState?: any;
}

async function logEvent(matchId: string, type: string, payload: object, actorUserId?: string) {
  try {
    await db.insert(matchEvents).values({
      matchId,
      type,
      payload,
      actorUserId: actorUserId || null,
    });
  } catch (e) {
    console.error(`[ReplaceQuestion] Failed to log event: matchId=${matchId}, type=${type}`, e);
  }
}

export async function replaceMatchQuestion(
  matchId: string,
  userId: string,
  idx: number,
  seedVersion: number,
  reason: string = "image_load_failed"
): Promise<ReplaceQuestionResult> {
  console.log(`[ReplaceQuestion] Request: matchId=${matchId}, userId=${userId}, idx=${idx}, seedVersion=${seedVersion}, reason=${reason}`);

  return await db.transaction(async (tx) => {
    // 1) Lock match row FOR UPDATE
    const [match] = await tx
      .select()
      .from(matches)
      .where(eq(matches.id, matchId))
      .for("update")
      .limit(1);

    if (!match) {
      return { success: false, error: "Match not found", errorCode: "MATCH_NOT_FOUND" };
    }

    // 2) Validate match status
    if (match.status !== MatchStatus.ACTIVE && match.status !== MatchStatus.INITIALIZING) {
      return { 
        success: false, 
        error: "Match is not active", 
        errorCode: "MATCH_NOT_ACTIVE" 
      };
    }

    // 3) Validate idx matches current question
    if (match.currentQuestionIndex !== idx) {
      console.log(`[ReplaceQuestion] Stale index: current=${match.currentQuestionIndex}, requested=${idx}`);
      return { 
        success: false, 
        error: "Can only replace current question", 
        errorCode: "STALE_INDEX" 
      };
    }

    // 4) Validate user is participant
    const participants = await tx
      .select()
      .from(matchParticipants)
      .where(eq(matchParticipants.matchId, matchId));

    const isParticipant = participants.some(p => p.userId === userId);
    if (!isParticipant) {
      return { 
        success: false, 
        error: "Not a participant", 
        errorCode: "NOT_PARTICIPANT" 
      };
    }

    // 5) Get current question from match_questions table or parse from questionsData
    let currentQuestion = await tx
      .select()
      .from(matchQuestions)
      .where(and(eq(matchQuestions.matchId, matchId), eq(matchQuestions.idx, idx)))
      .limit(1)
      .then(rows => rows[0]);

    // If question doesn't exist in match_questions, create it from questionsData
    if (!currentQuestion) {
      let questions: GameQuestion[] = [];
      try {
        questions = JSON.parse(match.questionsData);
      } catch (e) {
        return { success: false, error: "Invalid match data", errorCode: "INVALID_DATA" };
      }

      if (idx >= questions.length) {
        return { success: false, error: "Invalid question index", errorCode: "INVALID_INDEX" };
      }

      const q = questions[idx];
      const [inserted] = await tx.insert(matchQuestions).values({
        matchId,
        idx,
        cardId: q.card.id,
        correctAnswer: q.correctAnswer,
        choices: JSON.stringify(q.options),
        pointValue: q.pointValue,
        seedVersion: 1,
        replacedCount: 0,
      }).returning();

      currentQuestion = inserted;

      // Also track this card as used
      try {
        await tx.insert(matchUsedCards).values({
          matchId,
          cardId: q.card.id,
        }).onConflictDoNothing();
      } catch (e) {
        // Ignore conflict
      }
    }

    // 6) Validate seedVersion matches
    if (currentQuestion.seedVersion !== seedVersion) {
      console.log(`[ReplaceQuestion] Stale seedVersion: current=${currentQuestion.seedVersion}, requested=${seedVersion}`);
      return { 
        success: false, 
        error: "Question already replaced, please refresh", 
        errorCode: "STALE_SEED_VERSION" 
      };
    }

    // 7) Check replaced count limit
    if (currentQuestion.replacedCount >= MAX_REPLACES_PER_IDX) {
      await logEvent(matchId, "REPLACE_DENIED", { userId, idx, reason: "max_replaces_exceeded" }, userId);
      return { 
        success: false, 
        error: `Maximum ${MAX_REPLACES_PER_IDX} replacements reached for this question`, 
        errorCode: "MAX_REPLACES_EXCEEDED" 
      };
    }

    // 8) Check cooldown
    if (currentQuestion.assignedAt) {
      const secondsSinceAssignment = (Date.now() - new Date(currentQuestion.assignedAt).getTime()) / 1000;
      if (secondsSinceAssignment < COOLDOWN_SECONDS) {
        await logEvent(matchId, "REPLACE_DENIED", { userId, idx, reason: "cooldown" }, userId);
        return { 
          success: false, 
          error: `Please wait ${Math.ceil(COOLDOWN_SECONDS - secondsSinceAssignment)} seconds before requesting another replacement`, 
          errorCode: "COOLDOWN" 
        };
      }
    }

    // 9) Quarantine the old card that failed to load
    const oldCardId = currentQuestion.cardId;
    if (oldCardId) {
      // Fire-and-forget quarantine (don't block the transaction)
      quarantineCard(oldCardId, `replaced_in_match:${reason}`, null).catch(e => {
        console.error(`[ReplaceQuestion] Failed to quarantine card ${oldCardId}:`, e);
      });
      console.warn(`[ReplaceQuestion] Quarantined card ${oldCardId}: ${reason}`);
    }

    // 10) Get all used card IDs for this match
    const usedCards = await tx
      .select({ cardId: matchUsedCards.cardId })
      .from(matchUsedCards)
      .where(eq(matchUsedCards.matchId, matchId));

    const usedCardIds = usedCards.map(c => c.cardId);

    // 11) Get quarantined card IDs
    const quarantinedIds = await getQuarantinedCardIds();

    // 12) Select a new verified card not already used and not quarantined
    const potentialCards = await tx
      .select()
      .from(baseballCards)
      .where(eq(baseballCards.imageVerified, true))
      .orderBy(sql`RANDOM()`)
      .limit(20);

    // Filter out used cards, quarantined cards, and cards without real images
    const availableCard = potentialCards.find(c => {
      if (usedCardIds.includes(c.id)) return false;
      if (quarantinedIds.has(c.id)) return false;
      if (!cardHasRealImage({ cardId: c.id, imageUrl: c.imageUrl, player: c.playerName })) {
        // Quarantine detected placeholder
        quarantineCard(c.id, "placeholder_image", c.imageUrl).catch(() => {});
        return false;
      }
      return true;
    });

    if (!availableCard) {
      await logEvent(matchId, "REPLACE_DENIED", { userId, idx, reason: "no_cards_available" }, userId);
      return { 
        success: false, 
        error: "No replacement cards available", 
        errorCode: "NO_CARDS_AVAILABLE" 
      };
    }

    // 11) Generate new question choices
    const allPlayerNames = await tx
      .select({ playerName: baseballCards.playerName })
      .from(baseballCards)
      .limit(100);

    const wrongOptions = allPlayerNames
      .map(c => c.playerName)
      .filter(name => name !== availableCard.playerName)
      .sort(() => Math.random() - 0.5)
      .slice(0, 3);

    const choices = [availableCard.playerName, ...wrongOptions].sort(() => Math.random() - 0.5);
    const basePoints = 100;
    const pointValue = Math.max(50, basePoints + (100 - availableCard.popularity) * 4);

    // 12) Update match_questions with new card
    const newSeedVersion = currentQuestion.seedVersion + 1;
    await tx.update(matchQuestions).set({
      cardId: availableCard.id,
      correctAnswer: availableCard.playerName,
      choices: JSON.stringify(choices),
      pointValue,
      seedVersion: newSeedVersion,
      replacedCount: currentQuestion.replacedCount + 1,
      assignedAt: new Date(),
    }).where(and(eq(matchQuestions.matchId, matchId), eq(matchQuestions.idx, idx)));

    // 13) Mark new card as used
    await tx.insert(matchUsedCards).values({
      matchId,
      cardId: availableCard.id,
    }).onConflictDoNothing();

    // 14) Update questionsData in match table (for compatibility)
    let questions: GameQuestion[] = [];
    try {
      questions = JSON.parse(match.questionsData);
    } catch (e) {
      console.error(`[ReplaceQuestion] Failed to parse questionsData`);
    }

    if (idx < questions.length) {
      const proxiedCard = {
        ...availableCard,
        imageUrl: `/api/images/card/${availableCard.id}`,
      };
      questions[idx] = {
        card: proxiedCard,
        options: choices,
        correctAnswer: availableCard.playerName,
        pointValue,
      };
      await tx.update(matches).set({
        questionsData: JSON.stringify(questions),
      }).where(eq(matches.id, matchId));
    }

    // 15) Log replacement event
    await tx.insert(matchEvents).values({
      matchId,
      type: "QUESTION_REPLACED",
      payload: {
        userId,
        idx,
        oldCardId: currentQuestion.cardId,
        newCardId: availableCard.id,
        oldSeedVersion: currentQuestion.seedVersion,
        newSeedVersion,
        reason,
      },
      actorUserId: userId,
    });

    console.log(`[ReplaceQuestion] Success: matchId=${matchId}, idx=${idx}, oldCard=${currentQuestion.cardId}, newCard=${availableCard.id}, newSeedVersion=${newSeedVersion}`);

    return {
      success: true,
      newQuestion: {
        idx,
        seedVersion: newSeedVersion,
        card: {
          id: availableCard.id,
          imageUrl: `/api/images/card/${availableCard.id}`,
          team: availableCard.team,
          year: availableCard.year,
          setName: availableCard.setName,
          cardNumber: availableCard.cardNumber,
        },
        choices,
        pointValue,
        correctAnswer: availableCard.playerName,
      },
    };
  });
}

export async function getQuestionSeedVersion(matchId: string, idx: number): Promise<number | null> {
  const [question] = await db
    .select({ seedVersion: matchQuestions.seedVersion })
    .from(matchQuestions)
    .where(and(eq(matchQuestions.matchId, matchId), eq(matchQuestions.idx, idx)))
    .limit(1);

  return question?.seedVersion ?? null;
}

