import { db } from "../../db";
import { cardImageQuarantine } from "@shared/schema";
import { eq, sql } from "drizzle-orm";
import { analyzeImageContent, type ImageAnalysisResult } from "../imageContentAnalyzer";

const PLACEHOLDER_URL_MARKERS = [
  "example.jpg",
  "example.png",
  "placeholder",
  "stock",
  "appforest",
  "default",
  "noimage",
  "no-image",
  "/example",
  "silhouette",
  "fallback",
  "blank",
  "missing",
  "notfound",
  "not-found",
  "image-not",
  "unavailable",
];

const ALLOWED_IMAGE_HOSTS = [
  "s3.amazonaws.com",
  "s3.us-east-1.amazonaws.com",
  "s3.us-west-2.amazonaws.com",
  "cardhedger.com",
  "cdn.cardhedger.com",
  "images.cardhedger.com",
  "cloudfront.net",
  "d1",
  "d2",
  "d3",
  "psacard.com",
  "beckett.com",
  "ebayimg.com",
  "i.ebayimg.com",
  "images.collector-cdn.com",
  "cdn.bubble.io",
];

export function normalizeImageUrl(url: string | null | undefined): string | null {
  if (!url || typeof url !== "string" || url.trim() === "") {
    return null;
  }

  let normalized = url.trim();

  if (normalized.startsWith("//")) {
    normalized = "https:" + normalized;
  }

  if (!normalized.startsWith("http://") && !normalized.startsWith("https://")) {
    normalized = "https://" + normalized;
  }

  return normalized;
}

export interface PlaceholderCheckMeta {
  description?: string | null;
  set?: string | null;
  player?: string | null;
}

export function isPlaceholderImage(
  url: string | null | undefined,
  meta?: PlaceholderCheckMeta
): boolean {
  if (!url || typeof url !== "string") {
    return true;
  }

  const normalized = normalizeImageUrl(url);
  if (!normalized) {
    return true;
  }

  if (normalized.length < 20) {
    return true;
  }

  const lowerUrl = normalized.toLowerCase();
  for (const marker of PLACEHOLDER_URL_MARKERS) {
    if (lowerUrl.includes(marker)) {
      console.warn(`[ImageQuality] Placeholder detected via marker "${marker}" in URL: ${url}`);
      return true;
    }
  }

  if (meta?.description) {
    const lowerDesc = meta.description.toLowerCase();
    if (lowerDesc.includes("example") || lowerDesc.includes("placeholder")) {
      console.warn(`[ImageQuality] Placeholder detected in description: ${meta.description}`);
      return true;
    }
  }

  try {
    const urlObj = new URL(normalized);
    const host = urlObj.hostname.toLowerCase();

    const isAllowedHost = ALLOWED_IMAGE_HOSTS.some(
      (allowed) => host.includes(allowed) || host.endsWith("." + allowed)
    );

    if (!isAllowedHost && !host.includes("amazonaws") && !host.includes("cloudfront")) {
      console.warn(`[ImageQuality] Unknown image host: ${host} for URL: ${url}`);
    }
  } catch {
  }

  return false;
}

export interface CardForImageCheck {
  card_id?: string;
  cardId?: string;
  image?: string | null;
  imageUrl?: string | null;
  raw_image?: string | null;
  description?: string | null;
  set?: string | null;
  player?: string | null;
}

export function cardHasRealImage(card: CardForImageCheck): boolean {
  const cardId = card.card_id || card.cardId;
  const imageUrl = card.raw_image || card.image || card.imageUrl;

  if (!imageUrl) {
    console.warn(`[ImageQuality] Card ${cardId} has no image URL`);
    return false;
  }

  const normalized = normalizeImageUrl(imageUrl);
  if (!normalized) {
    console.warn(`[ImageQuality] Card ${cardId} has invalid image URL: ${imageUrl}`);
    return false;
  }

  const isPlaceholder = isPlaceholderImage(normalized, {
    description: card.description,
    set: card.set,
    player: card.player,
  });

  if (isPlaceholder) {
    console.warn(`[ImageQuality] Card ${cardId} has placeholder image: ${imageUrl}`);
    return false;
  }

  return true;
}

export async function quarantineCard(
  cardId: string,
  reason: string,
  imageUrl?: string | null
): Promise<void> {
  try {
    await db
      .insert(cardImageQuarantine)
      .values({
        cardId,
        reason,
        imageUrl: imageUrl || null,
      })
      .onConflictDoUpdate({
        target: cardImageQuarantine.cardId,
        set: {
          lastSeenAt: new Date(),
          seenCount: sql`${cardImageQuarantine.seenCount} + 1`,
          reason,
          imageUrl: imageUrl || null,
        },
      });

    console.warn(`[ImageQuality] Quarantined card ${cardId}: ${reason}`);
  } catch (error) {
    console.error(`[ImageQuality] Failed to quarantine card ${cardId}:`, error);
  }
}

export async function isCardQuarantined(cardId: string): Promise<boolean> {
  const [quarantined] = await db
    .select({ cardId: cardImageQuarantine.cardId })
    .from(cardImageQuarantine)
    .where(eq(cardImageQuarantine.cardId, cardId))
    .limit(1);

  return !!quarantined;
}

export async function getQuarantinedCardIds(): Promise<Set<string>> {
  const rows = await db
    .select({ cardId: cardImageQuarantine.cardId })
    .from(cardImageQuarantine);

  return new Set(rows.map((r) => r.cardId));
}

export async function removeFromQuarantine(cardId: string): Promise<void> {
  await db
    .delete(cardImageQuarantine)
    .where(eq(cardImageQuarantine.cardId, cardId));

  console.info(`[ImageQuality] Removed card ${cardId} from quarantine`);
}

/**
 * Deep content-based analysis to detect placeholder/silhouette images
 * This analyzes the actual image pixels to detect:
 * - Low color diversity (silhouettes are single-color)
 * - Low entropy (real cards have text, details)
 * - Dominant solid colors
 */
export async function analyzeCardImageContent(
  cardId: string,
  imageUrl: string
): Promise<{ isPlaceholder: boolean; confidence: number; reasons: string[] }> {
  const normalized = normalizeImageUrl(imageUrl);
  if (!normalized) {
    return { isPlaceholder: true, confidence: 100, reasons: ["Invalid image URL"] };
  }

  try {
    const result = await analyzeImageContent(normalized);

    if (result.isPlaceholder && result.confidence >= 50) {
      console.warn(`[ImageQuality] Content analysis flagged card ${cardId}: ${result.reasons.join("; ")}`);
    }

    return {
      isPlaceholder: result.isPlaceholder,
      confidence: result.confidence,
      reasons: result.reasons
    };
  } catch (error: any) {
    console.error(`[ImageQuality] Content analysis failed for card ${cardId}:`, error.message);
    return { isPlaceholder: false, confidence: 0, reasons: ["Analysis error"] };
  }
}

/**
 * Full card image validation including content analysis
 * Use this for pre-game validation to catch placeholder images
 */
export async function validateCardImageFully(card: CardForImageCheck): Promise<{
  valid: boolean;
  reason?: string;
  shouldQuarantine: boolean;
}> {
  const cardId = card.card_id || card.cardId || "unknown";
  const imageUrl = card.raw_image || card.image || card.imageUrl;

  // Step 1: Basic URL checks
  if (!cardHasRealImage(card)) {
    return { valid: false, reason: "Failed URL-based checks", shouldQuarantine: true };
  }

  // Step 2: Content-based analysis
  const normalized = normalizeImageUrl(imageUrl);
  if (!normalized) {
    return { valid: false, reason: "Invalid image URL", shouldQuarantine: true };
  }

  const contentResult = await analyzeCardImageContent(cardId, normalized);

  if (contentResult.isPlaceholder && contentResult.confidence >= 60) {
    return { 
      valid: false, 
      reason: `Content analysis: ${contentResult.reasons.join("; ")}`,
      shouldQuarantine: true
    };
  }

  return { valid: true, shouldQuarantine: false };
}

/**
 * Batch validate cards for a game session
 * Returns IDs of cards that should be excluded
 */
export async function validateCardsForGameSession(
  cards: CardForImageCheck[]
): Promise<{ validCards: CardForImageCheck[]; invalidCardIds: string[] }> {
  const validCards: CardForImageCheck[] = [];
  const invalidCardIds: string[] = [];

  for (const card of cards) {
    const cardId = card.card_id || card.cardId || "";

    // Quick URL check first
    if (!cardHasRealImage(card)) {
      invalidCardIds.push(cardId);
      quarantineCard(cardId, "failed_url_check", card.image || card.imageUrl).catch(() => {});
      continue;
    }

    // For cards that pass URL check, do content analysis
    const imageUrl = card.raw_image || card.image || card.imageUrl;
    if (imageUrl) {
      const contentResult = await analyzeCardImageContent(cardId, imageUrl);

      if (contentResult.isPlaceholder && contentResult.confidence >= 60) {
        invalidCardIds.push(cardId);
        quarantineCard(cardId, `content_analysis: ${contentResult.reasons[0] || "placeholder_detected"}`, imageUrl).catch(() => {});
        continue;
      }
    }

    validCards.push(card);
  }

  if (invalidCardIds.length > 0) {
    console.log(`[ImageQuality] Pre-game validation: ${invalidCardIds.length} cards quarantined, ${validCards.length} valid`);
  }

  return { validCards, invalidCardIds };
}

server/websocket.ts.content:
import { WebSocketServer, WebSocket } from "ws";
import { Server as HttpServer, IncomingMessage } from "http";
import { matchService } from "./services/matchService";
import { dbMatchmakingQueue } from "./services/matchmaking/dbQueue";
import { presenceService } from "./services/presenceService";
import { streakService } from "./services/streakService";
import { friendMatchInviteService } from "./services/friends/friendMatchInviteService";
import { log } from "./index";
import { MatchStatus, type MatchState, matchQuestions } from "@shared/schema";
import { getSession } from "./replit_integrations/auth/replitAuth";
import { isMatchParticipantByState, isMatchParticipant } from "./services/auth/isMatchParticipant";
import { validateActiveUser } from "./services/auth/validateActiveUser";
import passport from "passport";
import * as matchEngine from "./services/matches/engine";
import { replaceMatchQuestion } from "./services/matches/replaceQuestion";
import { db } from "./db";
import { eq, and } from "drizzle-orm";

const INVITE_EXPIRATION_INTERVAL = 10000; // 10 seconds
let inviteExpirationInterval: NodeJS.Timeout | null = null;

const DISCONNECT_GRACE_PERIOD = 60000; // 60 seconds before cancelling match on disconnect
const disconnectTimers: Map<string, NodeJS.Timeout> = new Map(); // key: matchId-userId
const AUTO_SUBMIT_TIMEOUT = 15000; // 15 seconds before auto-submitting wrong answer for disconnected player
const autoSubmitTimers: Map<string, NodeJS.Timeout> = new Map(); // key: matchId-userId

const LOBBY_DISCONNECT_GRACE_PERIOD = 30000; // 30 seconds before closing lobby on host disconnect
const lobbyDisconnectTimers: Map<string, NodeJS.Timeout> = new Map(); // key: lobbyId-userId

function startInviteExpirationJob() {
  if (inviteExpirationInterval) return;

  inviteExpirationInterval = setInterval(async () => {
    try {
      const expired = await friendMatchInviteService.expireOldInvites();
      if (expired.length > 0) {
        log(`[FriendMatchInvite] Expired ${expired.length} invite(s)`, "ws");
      }
    } catch (err) {
      console.error("[FriendMatchInvite] Expiration job error:", err);
    }
  }, INVITE_EXPIRATION_INTERVAL);
}

// Heartbeat configuration
const HEARTBEAT_INTERVAL = 30000; // 30 seconds
const HEARTBEAT_TIMEOUT = 10000; // 10 seconds to respond

interface ClientConnection {
  userId: string;
  username: string;
  lobbyId?: string;
  matchId?: string;
  membershipSecret?: string;
  isAuthenticated?: boolean;
  inQueue?: boolean;
  lastHeartbeat?: number;
  heartbeatTimeout?: NodeJS.Timeout;
  socketId?: string;
  sessionUserId?: string;
}

interface ExtendedWebSocket extends WebSocket {
  sessionUserId?: string;
  sessionUsername?: string;
}

const clients = new Map<WebSocket, ClientConnection>();
const userSockets = new Map<string, WebSocket>(); // userId -> WebSocket for quick lookup
const lobbyConnections = new Map<string, Set<WebSocket>>();
const matchConnections = new Map<string, Set<WebSocket>>();

// Periodic heartbeat checker
let heartbeatChecker: NodeJS.Timeout | null = null;

function startHeartbeatChecker(wss: WebSocketServer) {
  if (heartbeatChecker) return;

  heartbeatChecker = setInterval(() => {
    const now = Date.now();
    wss.clients.forEach((ws) => {
      const client = clients.get(ws);
      if (client && client.lastHeartbeat) {
        const timeSinceHeartbeat = now - client.lastHeartbeat;
        if (timeSinceHeartbeat > HEARTBEAT_INTERVAL + HEARTBEAT_TIMEOUT) {
          log(`Heartbeat timeout for user ${client.userId}, closing connection`, "ws");
          ws.terminate();
        }
      }
    });
  }, HEARTBEAT_INTERVAL);
}

function parseSessionFromUpgrade(req: IncomingMessage): Promise<{ userId?: string; username?: string }> {
  return new Promise((resolve) => {
    const sessionMiddleware = getSession();
    const mockRes = { 
      on: () => {}, 
      end: () => {},
      setHeader: () => {},
      getHeader: () => undefined,
    } as any;

    sessionMiddleware(req as any, mockRes, () => {
      passport.initialize()(req as any, mockRes, () => {
        passport.session()(req as any, mockRes, () => {
          const user = (req as any).user;
          const session = (req as any).session;

          if (user?.claims?.sub) {
            resolve({ userId: user.claims.sub, username: user.claims.name || user.claims.preferred_username });
          } else if (session?.localUserId) {
            resolve({ userId: session.localUserId, username: session.localUsername });
          } else {
            resolve({});
          }
        });
      });
    });
  });
}

export function setupWebSocket(httpServer: HttpServer) {
  const wss = new WebSocketServer({ noServer: true, path: "/ws" });

  httpServer.on("upgrade", async (req, socket, head) => {
    if (req.url !== "/ws" && !req.url?.startsWith("/ws?")) {
      return;
    }

    try {
      const sessionData = await parseSessionFromUpgrade(req);

      wss.handleUpgrade(req, socket, head, (ws) => {
        const extWs = ws as ExtendedWebSocket;
        extWs.sessionUserId = sessionData.userId;
        extWs.sessionUsername = sessionData.username;

        if (sessionData.userId) {
          log(`[WS Upgrade] Session authenticated: userId=${sessionData.userId}, username=${sessionData.username}`, "ws");
        } else {
          log(`[WS Upgrade] No session found, will rely on message-based auth`, "ws");
        }

        wss.emit("connection", extWs, req);
      });
    } catch (err) {
      console.error("[WS Upgrade] Error parsing session:", err);
      socket.destroy();
    }
  });

  // Start periodic heartbeat checker
  startHeartbeatChecker(wss);

  // Start friend match invite expiration job
  startInviteExpirationJob();

  wss.on("connection", (ws: ExtendedWebSocket) => {
    log("WebSocket client connected", "ws");

    ws.on("message", async (data) => {
      try {
        const message = JSON.parse(data.toString());
        await handleMessage(ws, message);
      } catch (error) {
        console.error("WebSocket message error:", error);
        ws.send(JSON.stringify({ type: "error", message: "Invalid message format" }));
      }
    });

    ws.on("close", async () => {
      const client = clients.get(ws);
      if (client) {
        // Clear heartbeat timeout
        if (client.heartbeatTimeout) {
          clearTimeout(client.heartbeatTimeout);
        }

        // Update presence to offline
        if (client.userId) {
          userSockets.delete(client.userId);
          presenceService.setOffline(client.userId).catch((err: unknown) => {
            console.error("Failed to update presence:", err);
          });
        }

        if (client.inQueue) {
          dbMatchmakingQueue.handleDisconnect(client.userId);
        }
        if (client.lobbyId) {
          await handleDisconnectFromLobby(ws, client);
        }
        if (client.matchId) {
          await handleDisconnectFromMatch(ws, client);
        }
        clients.delete(ws);
        log(`WebSocket client disconnected: ${client.username}`, "ws");
      }
    });

    ws.on("error", (error) => {
      console.error("WebSocket error:", error);
    });
  });

  return wss;
}

// Export for other modules to send messages to specific users
export function sendToUser(userId: string, message: any): boolean {
  const ws = userSockets.get(userId);
  if (ws && ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(message));
    return true;
  }
  return false;
}

// Friend match invite notifications
export function notifyFriendMatchInvite(toUserId: string, invite: {
  inviteId: string;
  fromUserId: string;
  fromUsername: string;
  bucket: string;
  expiresAt: Date;
}) {
  return sendToUser(toUserId, {
    type: "FRIEND_MATCH_INVITE",
    payload: invite,
  });
}

export function notifyFriendMatchInviteCancelled(toUserId: string, inviteId: string) {
  return sendToUser(toUserId, {
    type: "FRIEND_MATCH_INVITE_CANCELLED",
    payload: { inviteId },
  });
}

export function notifyFriendMatchInviteExpired(toUserId: string, inviteId: string) {
  return sendToUser(toUserId, {
    type: "FRIEND_MATCH_INVITE_EXPIRED",
    payload: { inviteId },
  });
}

export function notifyFriendMatchAccepted(toUserId: string, data: {
  inviteId: string;
  matchId: string;
  lobbyId: string;
  membershipSecret: string;
}) {
  return sendToUser(toUserId, {
    type: "FRIEND_MATCH_ACCEPTED",
    payload: data,
  });
}

async function handleMessage(ws: WebSocket, message: any) {
  const { type, payload } = message;

  switch (type) {
    case "heartbeat":
      await handleHeartbeat(ws, payload);
      break;
    case "auth":
      await handleAuth(ws, payload);
      break;
    case "join_lobby":
      await handleJoinLobbyWs(ws, payload);
      break;
    case "leave_lobby":
      await handleLeaveLobbyWs(ws, payload);
      break;
    case "start_match":
      await handleStartMatch(ws, payload);
      break;
    case "submit_answer":
      await handleSubmitAnswer(ws, payload);
      break;
    case "ready_next":
      await handleReadyNext(ws, payload);
      break;
    case "join_match":
      await handleJoinMatch(ws, payload);
      break;
    case "join_queue":
      await handleJoinQueue(ws, payload);
      break;
    case "leave_queue":
      await handleLeaveQueue(ws, payload);
      break;
    case "match_resync":
      await handleMatchResync(ws, payload);
      break;
    case "question_replace_request":
      await handleQuestionReplaceRequest(ws, payload);
      break;
    default:
      ws.send(JSON.stringify({ type: "error", message: "Unknown message type" }));
  }
}

// Auth handler for initial connection
async function handleAuth(ws: WebSocket, payload: { userId: string; username: string }) {
  const { userId, username } = payload;

  if (!userId || !username) {
    ws.send(JSON.stringify({ type: "error", message: "Invalid auth payload" }));
    return;
  }

  // Check if user already has a connection
  const existingWs = userSockets.get(userId);
  if (existingWs && existingWs !== ws && existingWs.readyState === WebSocket.OPEN) {
    // Disconnect the old connection
    existingWs.send(JSON.stringify({ type: "disconnected", message: "Connected from another location" }));
    existingWs.close();
  }

  const socketId = Math.random().toString(36).substring(7);
  clients.set(ws, { 
    userId, 
    username, 
    isAuthenticated: true,
    lastHeartbeat: Date.now(),
    socketId
  });
  userSockets.set(userId, ws);

  // Update presence in database
  await presenceService.setOnline(userId, socketId);

  ws.send(JSON.stringify({ 
    type: "auth_success", 
    payload: { userId, socketId }
  }));

  log(`User ${username} (${userId}) authenticated`, "ws");
}

// Heartbeat handler
async function handleHeartbeat(ws: WebSocket, payload: { userId: string }) {
  const client = clients.get(ws);

  if (!client || client.userId !== payload.userId) {
    ws.send(JSON.stringify({ type: "error", message: "Not authenticated" }));
    return;
  }

  client.lastHeartbeat = Date.now();

  presenceService.updateLastSeen(client.userId).catch((err: unknown) => {
    console.error("Failed to update presence:", err);
  });

  if (client.inQueue) {
    dbMatchmakingQueue.updateHeartbeat(client.userId).catch((err: unknown) => {
      console.error("Failed to update matchmaking heartbeat:", err);
    });
  }

  ws.send(JSON.stringify({ type: "heartbeat_ack", timestamp: Date.now() }));
}

async function handleJoinLobbyWs(ws: WebSocket, payload: { userId: string; username: string; lobbyId: string; membershipSecret: string }) {
  const { userId, username, lobbyId, membershipSecret } = payload;

  const existingClient = clients.get(ws);
  if (existingClient && existingClient.userId && existingClient.userId !== userId) {
    ws.send(JSON.stringify({ type: "error", message: "Cannot change user identity mid-session" }));
    return;
  }

  const lobby = await matchService.getLobby(lobbyId);
  if (!lobby) {
    ws.send(JSON.stringify({ type: "error", message: "Lobby not found" }));
    return;
  }

  if (!matchService.verifyMembershipSecret(lobby, userId, membershipSecret)) {
    ws.send(JSON.stringify({ type: "error", message: "Invalid membership credentials" }));
    return;
  }

  clients.set(ws, { userId, username, lobbyId, membershipSecret, isAuthenticated: true });

  if (!lobbyConnections.has(lobbyId)) {
    lobbyConnections.set(lobbyId, new Set());
  }
  lobbyConnections.get(lobbyId)?.add(ws);

  // Cancel any pending host disconnect grace timer on reconnect
  const hadDisconnectTimer = cancelLobbyDisconnectTimer(lobbyId, userId);

  // Only notify other players of host reconnection if a real disconnect happened
  if (lobby.hostId === userId && hadDisconnectTimer) {
    broadcastToLobby(lobbyId, {
      type: "host_reconnected",
      payload: { userId, username },
    });
  }

  const safeLobby = {
    id: lobby.id,
    joinCode: lobby.joinCode,
    hostId: lobby.hostId,
    hostUsername: lobby.hostUsername,
    guestId: lobby.guestId,
    guestUsername: lobby.guestUsername,
    status: lobby.status,
    mode: lobby.mode,
    totalQuestions: lobby.totalQuestions,
    createdAt: lobby.createdAt,
    gameSetId: lobby.gameSetId,
  };

  broadcastToLobby(lobbyId, {
    type: "lobby_update",
    payload: safeLobby,
  });

  ws.send(JSON.stringify({ type: "joined_lobby", payload: { lobbyId } }));
}

async function handleLeaveLobbyWs(ws: WebSocket, payload: { lobbyId: string; userId: string }) {
  const { lobbyId, userId } = payload;

  const result = await matchService.leaveLobby(lobbyId, userId);

  const client = clients.get(ws);
  if (client) {
    client.lobbyId = undefined;
  }

  lobbyConnections.get(lobbyId)?.delete(ws);

  if (result) {
    broadcastToLobby(lobbyId, {
      type: "lobby_update",
      payload: result,
    });
  } else {
    broadcastToLobby(lobbyId, {
      type: "lobby_closed",
      payload: { lobbyId },
    });
    lobbyConnections.delete(lobbyId);
  }
}

async function handleStartMatch(ws: WebSocket, payload: { lobbyId: string; hostId: string }) {
  const { lobbyId, hostId } = payload;

  const client = clients.get(ws);
  if (!client || !client.isAuthenticated || client.userId !== hostId) {
    ws.send(JSON.stringify({ type: "start_match_error", message: "Unauthorized: only authenticated host can start the match" }));
    return;
  }

  const lobby = await matchService.getLobby(lobbyId);
  if (!lobby || lobby.hostId !== hostId) {
    ws.send(JSON.stringify({ type: "start_match_error", message: "Unauthorized: you are not the host of this lobby" }));
    return;
  }

  if (!client.membershipSecret || !matchService.verifyMembershipSecret(lobby, hostId, client.membershipSecret)) {
    ws.send(JSON.stringify({ type: "start_match_error", message: "Unauthorized: invalid membership secret. Please leave and recreate the lobby." }));
    return;
  }

  log(`[StartMatch] Starting match for lobby ${lobbyId}, host=${hostId}`, "ws");

  let result: { matchState: any; error?: string };
  try {
    result = await matchService.startMatch(lobbyId, hostId);
  } catch (err: any) {
    const errorMsg = err?.message === "NO_PLAYABLE_CARDS_AVAILABLE"
      ? "Not enough cards available to start a match right now. Please try again later."
      : "Something went wrong starting the match. Please try again.";
    log(`[StartMatch] Exception starting match: ${err?.message}`, "ws");
    ws.send(JSON.stringify({ type: "start_match_error", message: errorMsg }));
    return;
  }

  if (!result.matchState) {
    log(`[StartMatch] Failed to start match: ${result.error}`, "ws");
    ws.send(JSON.stringify({ type: "start_match_error", message: result.error || "Failed to start match" }));
    return;
  }

  const matchState = result.matchState;
  log(`[StartMatch] Match ${matchState.matchId} created with ${matchState.questions.length} questions`, "ws");

  const lobbyClients = lobbyConnections.get(lobbyId);
  const connectedPlayerCount = lobbyClients?.size || 0;
  log(`[StartMatch] Lobby has ${connectedPlayerCount} connected clients`, "ws");

  if (lobbyClients) {
    Array.from(lobbyClients).forEach(clientWs => {
      const clientInfo = clients.get(clientWs);
      if (clientInfo) {
        log(`[StartMatch] Moving client ${clientInfo.userId} from lobby to match`, "ws");
        clientInfo.matchId = matchState.matchId;
        clientInfo.lobbyId = undefined;
      }

      if (!matchConnections.has(matchState.matchId)) {
        matchConnections.set(matchState.matchId, new Set());
      }
      matchConnections.get(matchState.matchId)?.add(clientWs);
    });
    lobbyConnections.delete(lobbyId);
  }

  const matchClientCount = matchConnections.get(matchState.matchId)?.size || 0;
  log(`[StartMatch] Match now has ${matchClientCount} connected clients`, "ws");

  // Rebuild match state from DB for authoritative broadcast
  const dbMatchState = await matchEngine.buildMatchState(matchState.matchId);
  const broadcastState = dbMatchState || matchState;

  const seedVersion = await getSeedVersionForQuestion(broadcastState.matchId, broadcastState.currentQuestionIndex);
  const clientMatchState = sanitizeMatchStateForClient(broadcastState, seedVersion);

  log(`[StartMatch] Broadcasting match_started to ${matchClientCount} clients, currentQuestion exists: ${!!clientMatchState.currentQuestion}`, "ws");

  broadcastToMatch(broadcastState.matchId, {
    type: "match_started",
    payload: clientMatchState,
  });
}

const ANSWER_RATE_LIMIT_WINDOW = 2000; // 2 seconds
const ANSWER_RATE_LIMIT_MAX = 3; // max 3 submissions per window
const answerRateTracker: Map<string, number[]> = new Map(); // key: userId, value: timestamps

const SUSPICIOUSLY_FAST_THRESHOLD = 500; // answers under 500ms are flagged

function checkAnswerRateLimit(userId: string): boolean {
  const now = Date.now();
  const timestamps = answerRateTracker.get(userId) || [];
  const recent = timestamps.filter(t => now - t < ANSWER_RATE_LIMIT_WINDOW);
  recent.push(now);
  if (recent.length === 0) {
    answerRateTracker.delete(userId);
  } else {
    answerRateTracker.set(userId, recent);
  }
  return recent.length <= ANSWER_RATE_LIMIT_MAX;
}

// Periodic cleanup of stale rate tracker entries every 60 seconds
setInterval(() => {
  const now = Date.now();
  for (const [userId, timestamps] of answerRateTracker) {
    const recent = timestamps.filter(t => now - t < ANSWER_RATE_LIMIT_WINDOW);
    if (recent.length === 0) {
      answerRateTracker.delete(userId);
    } else {
      answerRateTracker.set(userId, recent);
    }
  }
}, 60000);

async function handleSubmitAnswer(ws: WebSocket, payload: { matchId: string; userId: string; questionIndex: number; selectedAnswer: string; clientMsgId?: string }) {
  const { matchId, questionIndex, selectedAnswer, clientMsgId } = payload;
  const extWs = ws as ExtendedWebSocket;

  const client = clients.get(ws);

  const serverUserId = client?.userId || extWs.sessionUserId;
  const isAuthenticated = client?.isAuthenticated || !!extWs.sessionUserId;

  log(`[SubmitAnswer] payload.userId=${payload.userId}, client.userId=${client?.userId}, sessionUserId=${extWs.sessionUserId}, isAuth=${isAuthenticated}, matchId=${matchId}, client.matchId=${client?.matchId}`, "ws");

  if (!serverUserId || !isAuthenticated) {
    log(`[SubmitAnswer] REJECTED missing_session: serverUserId=${serverUserId}, isAuthenticated=${isAuthenticated}`, "ws");
    ws.send(JSON.stringify({ 
      type: "answer_ack", 
      payload: { matchId, idx: questionIndex, clientMsgId, status: "REJECTED", reason: "missing_session" } 
    }));
    return;
  }

  if (client?.matchId && client.matchId !== matchId) {
    log(`[SubmitAnswer] REJECTED not_in_match: client.matchId=${client.matchId}, requested matchId=${matchId}`, "ws");
    ws.send(JSON.stringify({ 
      type: "answer_ack", 
      payload: { matchId, idx: questionIndex, clientMsgId, status: "REJECTED", reason: "not_in_match" } 
    }));
    return;
  }

  if (!checkAnswerRateLimit(serverUserId)) {
    log(`[SubmitAnswer] RATE_LIMITED: userId=${serverUserId}, matchId=${matchId}`, "ws");
    ws.send(JSON.stringify({ 
      type: "answer_ack", 
      payload: { matchId, idx: questionIndex, clientMsgId, status: "REJECTED", reason: "rate_limited" } 
    }));
    return;
  }

  const result = await matchEngine.submitAnswer(matchId, serverUserId, questionIndex, selectedAnswer, clientMsgId);

  // Send ACK to submitter with answer status
  ws.send(JSON.stringify({
    type: "answer_ack",
    payload: {
      matchId,
      idx: questionIndex,
      clientMsgId,
      status: result.status,
      reason: result.status === "REJECTED" ? result.reason : undefined,
      serverIndex: result.status === "REJECTED" ? result.serverIndex : undefined,
      serverStatus: result.status === "REJECTED" ? result.serverStatus : undefined,
      answeredCount: result.answerStatus?.answeredCount,
      required: result.answerStatus?.required,
    },
  }));

  if (result.status === "REJECTED") {
    log(`[SubmitAnswer] REJECTED: matchId=${matchId}, userId=${serverUserId}, idx=${questionIndex}, reason=${result.reason}`, "ws");
    return;
  }

  // Send answer result to submitter
  ws.send(JSON.stringify({
    type: "answer_result",
    payload: {
      correct: result.correct,
      pointsEarned: result.pointsEarned,
      correctAnswer: result.correctAnswer,
    },
  }));

  // CRITICAL: Broadcast ANSWER_STATUS to BOTH players
  // This ensures both clients know how many answers have been submitted
  if (result.answerStatus) {
    log(`[SubmitAnswer] Broadcasting answer_status to match ${matchId}: ${result.answerStatus.answeredCount}/${result.answerStatus.required} for idx=${questionIndex}`, "ws");
    broadcastToMatch(matchId, {
      type: "answer_status",
      payload: {
        matchId,
        idx: questionIndex,
        answeredCount: result.answerStatus.answeredCount,
        required: result.answerStatus.required,
      },
    });
  }

  // Also broadcast participant_answered for UI updates
  const updatedState = await matchEngine.buildMatchState(matchId);
  if (updatedState) {
    broadcastToMatch(matchId, {
      type: "participant_answered",
      payload: {
        matchId,
        userId: serverUserId,
        questionIndex,
        idx: questionIndex,
        participants: updatedState.participants.map(p => ({
          userId: p.userId,
          username: p.username,
          score: p.score,
          hasAnsweredCurrent: p.hasAnsweredCurrent,
        })),
      },
    });
  }

  // Handle advance if both answered
  if (result.advance) {
    if (result.advance.finished) {
      // Match completed - compute results and broadcast
      const participants = await matchEngine.getParticipants(matchId);
      const match = await matchEngine.getMatchFromDb(matchId);
      const totalQuestions = match?.totalQuestions || 10;

      const matchEnd = await matchEngine.completeMatchFinish(matchId, participants, totalQuestions);

      if (matchEnd) {
        for (const participant of matchEnd.participants) {
          try {
            const streakResult = await streakService.processMatchCompletion(participant.userId, matchId);
            if (streakResult.success && !streakResult.alreadyClaimed && streakResult.totalAwarded) {
              log(`[Streak] User ${participant.userId} earned ${streakResult.totalAwarded} PackPTS for day ${streakResult.streakInfo?.currentDays} streak`, "ws");
            }
          } catch (streakError) {
            console.error("Failed to process streak for participant:", streakError);
          }
        }

        log(`[SubmitAnswer] Broadcasting match_end to match ${matchId}`, "ws");
        broadcastToMatch(matchId, {
          type: "match_end",
          payload: matchEnd,
        });
      }
    } else if (result.advance.nextQuestion) {
      // Advance to next question - broadcast to BOTH players
      const advancedState = await matchEngine.buildMatchState(matchId);
      if (advancedState) {
        const newIdx = result.advance.newIndex;
        const seedVer = await getSeedVersionForQuestion(matchId, newIdx);
        const clientMatchState = sanitizeMatchStateForClient(advancedState, seedVer);

        log(`[SubmitAnswer] Broadcasting next_question to match ${matchId}: idx=${newIdx}`, "ws");
        broadcastToMatch(matchId, {
          type: "next_question",
          payload: {
            ...clientMatchState,
            // Include answer status for the new question (always 0/2 since it's a fresh question)
            answerStatus: {
              idx: newIdx,
              answeredCount: 0,
              required: 2,
            },
          },
        });
      }
    }
  }
}

async function handleReadyNext(ws: WebSocket, payload: { matchId: string }) {
  const { matchId } = payload;
  const extWs = ws as ExtendedWebSocket;
  const existingClient = clients.get(ws);

  // Get userId from existing client info or session
  const userId = existingClient?.userId || extWs.sessionUserId;
  const username = existingClient?.username || extWs.sessionUsername || "Player";

  log(`[ReadyNext] matchId=${matchId}, userId=${userId}, hasExistingClient=${!!existingClient}`, "ws");

  const matchState = await matchEngine.buildMatchState(matchId);

  if (!matchState) {
    ws.send(JSON.stringify({ type: "error", message: "Match not found" }));
    return;
  }

  // If we have a userId and they're a participant, ensure they're registered for this match
  if (userId && isMatchParticipantByState(matchState, userId)) {
    // Register this WebSocket for the match if not already registered
    if (!existingClient?.matchId || existingClient.matchId !== matchId) {
      log(`[ReadyNext] Registering user ${userId} for match ${matchId}`, "ws");

      clients.set(ws, { 
        ...existingClient,
        userId, 
        username, 
        matchId, 
        isAuthenticated: true,
        sessionUserId: extWs.sessionUserId
      });

      if (!matchConnections.has(matchId)) {
        matchConnections.set(matchId, new Set());
      }
      matchConnections.get(matchId)?.add(ws);

      cancelDisconnectTimer(matchId, userId);
      cancelAutoSubmit(matchId, userId);
      await matchEngine.markConnected(matchId, userId);
    }
  }

  const seedVersion = await getSeedVersionForQuestion(matchId, matchState.currentQuestionIndex);
  const clientMatchState = sanitizeMatchStateForClient(matchState, seedVersion);
  ws.send(JSON.stringify({
    type: "match_state",
    payload: clientMatchState,
  }));
}

async function handleMatchResync(ws: WebSocket, payload: { matchId: string }) {
  const { matchId } = payload;
  const extWs = ws as ExtendedWebSocket;
  const existingClient = clients.get(ws);
  const userId = existingClient?.userId || extWs.sessionUserId;
  const username = existingClient?.username || extWs.sessionUsername || "Player";

  log(`[MatchResync] Resync requested for match ${matchId}, userId=${userId}`, "ws");

  if (!userId) {
    ws.send(JSON.stringify({ 
      type: "error", 
      message: "Not authenticated",
    }));
    return;
  }

  const matchState = await matchEngine.resync(matchId, userId);

  if (!matchState) {
    ws.send(JSON.stringify({ 
      type: "error", 
      message: "Match not found or you are not a participant",
    }));
    return;
  }

  // Ensure the client is properly registered for this match
  if (!existingClient?.matchId || existingClient.matchId !== matchId) {
    log(`[MatchResync] Registering user ${userId} for match ${matchId}`, "ws");

    clients.set(ws, { 
      ...existingClient,
      userId, 
      username, 
      matchId, 
      isAuthenticated: true,
      sessionUserId: extWs.sessionUserId
    });

    if (!matchConnections.has(matchId)) {
      matchConnections.set(matchId, new Set());
    }
    matchConnections.get(matchId)?.add(ws);

    cancelDisconnectTimer(matchId, userId);
    cancelAutoSubmit(matchId, userId);
    await matchEngine.markConnected(matchId, userId);
  }

  if (matchState.status === MatchStatus.FINISHED || matchState.status === MatchStatus.CANCELLED) {
    ws.send(JSON.stringify({
      type: "match_end",
      payload: {
        matchId,
        reason: matchState.endReason || (matchState.status === MatchStatus.FINISHED ? "completed" : "unknown"),
        status: matchState.status,
        winner: matchState.winner,
        winnerUserId: matchState.winnerUserId,
        result: matchState.result,
        hostCorrect: matchState.hostCorrect,
        guestCorrect: matchState.guestCorrect,
        participants: matchState.participants.map(p => ({
          userId: p.userId,
          username: p.username,
          score: p.score,
          correctAnswers: p.correctAnswers,
        })),
      },
    }));
    return;
  }

  const seedVersion = await getSeedVersionForQuestion(matchId, matchState.currentQuestionIndex);
  const clientMatchState = sanitizeMatchStateForClient(matchState, seedVersion);

  // Calculate current answer count for the idx
  const answeredCount = matchState.participants.filter(p => p.hasAnsweredCurrent).length;
  const required = matchState.participants.length;

  ws.send(JSON.stringify({
    type: "match_state",
    payload: clientMatchState,
  }));

  // Also send answer status so client knows current state
  ws.send(JSON.stringify({
    type: "answer_status",
    payload: {
      matchId,
      idx: matchState.currentQuestionIndex,
      answeredCount,
      required,
    },
  }));

  log(`[MatchResync] Sent resync for match ${matchId}, status=${matchState.status}, questionIndex=${matchState.currentQuestionIndex}, answeredCount=${answeredCount}/${required}, seedVersion=${seedVersion}`, "ws");
}

async function handleQuestionReplaceRequest(ws: WebSocket, payload: { matchId: string; idx: number; seedVersion: number; reason?: string }) {
  const { matchId, idx, seedVersion, reason } = payload;
  const extWs = ws as ExtendedWebSocket;
  const client = clients.get(ws);
  const userId = client?.userId || extWs.sessionUserId;

  log(`[QuestionReplace] Request: matchId=${matchId}, userId=${userId}, idx=${idx}, seedVersion=${seedVersion}`, "ws");

  if (!userId) {
    ws.send(JSON.stringify({
      type: "question_replace_error",
      payload: { matchId, idx, error: "Not authenticated", errorCode: "NOT_AUTHENTICATED" },
    }));
    return;
  }

  const result = await replaceMatchQuestion(matchId, userId, idx, seedVersion, reason || "image_load_failed");

  if (!result.success) {
    log(`[QuestionReplace] Failed: ${result.errorCode} - ${result.error}`, "ws");
    ws.send(JSON.stringify({
      type: "question_replace_error",
      payload: { matchId, idx, error: result.error, errorCode: result.errorCode },
    }));

    // If stale seed version, also send current match state to resync
    if (result.errorCode === "STALE_SEED_VERSION" || result.errorCode === "STALE_INDEX") {
      const matchState = await matchEngine.buildMatchState(matchId);
      if (matchState) {
        const currentSeedVersion = await getSeedVersionForQuestion(matchId, matchState.currentQuestionIndex);
        const clientMatchState = sanitizeMatchStateForClient(matchState, currentSeedVersion);
        ws.send(JSON.stringify({
          type: "match_state",
          payload: clientMatchState,
        }));
      }
    }
    return;
  }

  log(`[QuestionReplace] Success: matchId=${matchId}, idx=${idx}, newSeedVersion=${result.newQuestion?.seedVersion}`, "ws");

  // Broadcast QUESTION_REPLACED to ALL players in the match (both 1vFriends and 1vRandom)
  broadcastToMatch(matchId, {
    type: "question_replaced",
    payload: {
      matchId,
      idx: result.newQuestion!.idx,
      seedVersion: result.newQuestion!.seedVersion,
      card: result.newQuestion!.card,
      choices: result.newQuestion!.choices,
      pointValue: result.newQuestion!.pointValue,
    },
  });
}

async function handleJoinMatch(ws: WebSocket, payload: { matchId: string; userId: string; username: string; membershipSecret?: string }) {
  const { matchId, membershipSecret } = payload;
  const extWs = ws as ExtendedWebSocket;

  const sessionUserId = extWs.sessionUserId;
  const sessionUsername = extWs.sessionUsername;

  const userId = payload.userId || sessionUserId;
  const username = payload.username || sessionUsername || "Unknown";

  log(`[JoinMatch] User ${username} (${userId}) attempting to join match ${matchId}, sessionUserId=${sessionUserId}`, "ws");

  if (!userId) {
    log(`[JoinMatch] REJECTED: No userId available (payload or session)`, "ws");
    ws.send(JSON.stringify({ type: "error", message: "Not authenticated" }));
    return;
  }

  const userValidation = await validateActiveUser(userId);
  if (!userValidation.valid) {
    log(`[JoinMatch] REJECTED: User ${userId} not active - ${userValidation.reason}`, "ws");
    ws.send(JSON.stringify({ 
      type: "error", 
      code: userValidation.reason === "BANNED" ? "USER_BANNED" : "NOT_AUTHORIZED",
      message: userValidation.reason === "BANNED" 
        ? "Your account has been suspended" 
        : "Your account is not active"
    }));
    return;
  }

  const existingClient = clients.get(ws);
  if (existingClient && existingClient.userId && existingClient.userId !== userId) {
    ws.send(JSON.stringify({ type: "error", message: "Cannot change user identity mid-session" }));
    return;
  }

  const matchState = await matchEngine.buildMatchState(matchId);
  if (!matchState) {
    log(`[JoinMatch] Match ${matchId} not found in database`, "ws");
    ws.send(JSON.stringify({ type: "error", message: "Match not found or has expired" }));
    return;
  }

  log(`[JoinMatch] Match ${matchId} found with ${matchState.questions.length} questions, status=${matchState.status}`, "ws");

  const lobby = await matchService.getLobby(matchState.lobbyId);
  if (!lobby) {
    ws.send(JSON.stringify({ type: "error", message: "Lobby not found" }));
    return;
  }

  const hasValidSecret = membershipSecret && matchService.verifyMembershipSecret(lobby, userId, membershipSecret);
  const hasSessionAuth = sessionUserId === userId && isMatchParticipant(lobby, userId);

  if (!hasValidSecret && !hasSessionAuth) {
    log(`[JoinMatch] REJECTED: No valid auth - hasValidSecret=${hasValidSecret}, hasSessionAuth=${hasSessionAuth}, sessionUserId=${sessionUserId}, userId=${userId}, lobbyHostId=${lobby.hostId}, lobbyGuestId=${lobby.guestId}`, "ws");
    ws.send(JSON.stringify({ type: "error", message: "Invalid membership credentials" }));
    return;
  }

  if (!isMatchParticipantByState(matchState, userId)) {
    log(`[JoinMatch] REJECTED: not_participant - userId=${userId}, participants=${matchState.participants.map(p => p.userId).join(",")}`, "ws");
    ws.send(JSON.stringify({ type: "error", message: "You are not a participant in this match" }));
    return;
  }

  clients.set(ws, { userId, username, matchId, membershipSecret, isAuthenticated: true, sessionUserId });

  if (!matchConnections.has(matchId)) {
    matchConnections.set(matchId, new Set());
  }
  matchConnections.get(matchId)?.add(ws);

  cancelDisconnectTimer(matchId, userId);
  cancelAutoSubmit(matchId, userId);
  await matchEngine.markConnected(matchId, userId);

  const seedVersion = await getSeedVersionForQuestion(matchId, matchState.currentQuestionIndex);
  const clientMatchState = sanitizeMatchStateForClient(matchState, seedVersion);

  log(`[JoinMatch] Sending match_started to ${username}, currentQuestion exists: ${!!clientMatchState.currentQuestion}`, "ws");

  ws.send(JSON.stringify({
    type: "match_started",
    payload: clientMatchState,
  }));

  log(`${username} joined match ${matchId}`, "ws");
}

async function getSeedVersionForQuestion(matchId: string, idx: number): Promise<number> {
  const question = await db
    .select({ seedVersion: matchQuestions.seedVersion })
    .from(matchQuestions)
    .where(and(
      eq(matchQuestions.matchId, matchId),
      eq(matchQuestions.idx, idx)
    ))
    .limit(1);

  return question.length > 0 && question[0].seedVersion ? question[0].seedVersion : 1;
}

function sanitizeMatchStateForClient(matchState: MatchState, seedVersion: number = 1): any {
  const currentQuestion = matchState.questions[matchState.currentQuestionIndex];

  return {
    matchId: matchState.matchId,
    lobbyId: matchState.lobbyId,
    status: matchState.status,
    currentQuestionIndex: matchState.currentQuestionIndex,
    totalQuestions: matchState.totalQuestions,
    currentQuestion: currentQuestion ? {
      card: {
        id: currentQuestion.card.id,
        imageUrl: currentQuestion.card.imageUrl,
        team: currentQuestion.card.team,
        year: currentQuestion.card.year,
        setName: currentQuestion.card.setName,
        cardNumber: currentQuestion.card.cardNumber,
      },
      options: currentQuestion.options,
      pointValue: currentQuestion.pointValue,
      seedVersion,
    } : null,
    participants: matchState.participants.map(p => ({
      userId: p.userId,
      username: p.username,
      score: p.score,
      correctAnswers: p.correctAnswers,
      hasAnsweredCurrent: p.hasAnsweredCurrent,
    })),
    winner: matchState.winner,
  };
}

function broadcastToLobby(lobbyId: string, message: any) {
  const lobbyClients = lobbyConnections.get(lobbyId);
  if (!lobbyClients) return;

  const messageStr = JSON.stringify(message);
  Array.from(lobbyClients).forEach(client => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(messageStr);
    }
  });
}

function broadcastToMatch(matchId: string, message: any) {
  const matchClients = matchConnections.get(matchId);
  if (!matchClients) {
    log(`[BroadcastToMatch] No clients found for match ${matchId}, message type: ${message.type}`, "ws");
    return;
  }

  const messageStr = JSON.stringify(message);
  let sentCount = 0;
  let closedCount = 0;
  Array.from(matchClients).forEach(client => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(messageStr);
      sentCount++;
    } else {
      closedCount++;
    }
  });

  if (message.type === "answer_status" || message.type === "next_question") {
    log(`[BroadcastToMatch] ${message.type} to ${matchId}: sent=${sentCount}, closed=${closedCount}, total=${matchClients.size}`, "ws");
  }
}

async function handleJoinQueue(ws: WebSocket, payload: { userId: string; username: string; totalQuestions?: number; gameSetId?: string | null }) {
  const { userId, username, totalQuestions = 10, gameSetId = null } = payload;

  if (!userId) {
    ws.send(JSON.stringify({ type: "error", code: "NOT_AUTHENTICATED", message: "Authentication required to join queue" }));
    return;
  }

  const userValidation = await validateActiveUser(userId);
  if (!userValidation.valid) {
    log(`[JoinQueue] User ${userId} rejected: ${userValidation.reason}`, "ws");
    ws.send(JSON.stringify({ 
      type: "error", 
      code: userValidation.reason === "BANNED" ? "USER_BANNED" : "NOT_AUTHORIZED",
      message: userValidation.reason === "BANNED" 
        ? "Your account has been suspended" 
        : userValidation.reason === "NOT_FOUND"
        ? "User account not found"
        : "Your account is not active"
    }));
    return;
  }

  const existingClient = clients.get(ws);

  if (existingClient && existingClient.isAuthenticated && existingClient.userId !== userId) {
    ws.send(JSON.stringify({ type: "error", message: "Cannot change user identity mid-session" }));
    return;
  }

  const socketId = existingClient?.socketId || Math.random().toString(36).substring(7);

  clients.set(ws, { 
    userId, 
    username, 
    inQueue: true, 
    isAuthenticated: true,
    lastHeartbeat: Date.now(),
    socketId
  });
  userSockets.set(userId, ws);

  const result = await dbMatchmakingQueue.joinQueue(userId, username, ws, socketId, totalQuestions, gameSetId);

  ws.send(JSON.stringify({
    type: "queue_joined",
    payload: {
      position: result.position,
      ticketId: result.ticketId,
      queueSize: result.queueSize,
    },
  }));

  log(`${username} joined matchmaking queue (position: ${result.position}, ticket: ${result.ticketId.slice(0, 8)}...)`, "ws");
}

async function handleLeaveQueue(ws: WebSocket, payload: { userId: string }) {
  const { userId } = payload;

  const client = clients.get(ws);
  if (!client || client.userId !== userId) {
    ws.send(JSON.stringify({ type: "error", message: "Not authenticated or user mismatch" }));
    return;
  }

  client.inQueue = false;

  const socketId = client.socketId || Math.random().toString(36).substring(7);
  await presenceService.setOnline(userId, socketId);

  const removed = await dbMatchmakingQueue.leaveQueue(userId);

  ws.send(JSON.stringify({
    type: "queue_left",
    payload: { success: removed },
  }));

  log(`User ${userId} left matchmaking queue`, "ws");
}

async function handleDisconnectFromLobby(ws: WebSocket, client: ClientConnection) {
  const { lobbyId, userId, username } = client;
  if (!lobbyId || !userId) return;

  const lobbyClients = lobbyConnections.get(lobbyId);
  lobbyClients?.delete(ws);

  const lobby = await matchService.getLobby(lobbyId);
  if (!lobby) return;

  if (lobby.hostId === userId) {
    // Host gets a grace period to reconnect instead of immediately closing
    broadcastToLobby(lobbyId, {
      type: "host_disconnected",
      payload: { userId, username, gracePeriodMs: LOBBY_DISCONNECT_GRACE_PERIOD },
    });
    log(`Host ${username} disconnected from lobby ${lobbyId}, starting ${LOBBY_DISCONNECT_GRACE_PERIOD / 1000}s grace period`, "ws");

    const timerKey = `${lobbyId}-${userId}`;
    if (lobbyDisconnectTimers.has(timerKey)) {
      clearTimeout(lobbyDisconnectTimers.get(timerKey)!);
    }

    const timer = setTimeout(async () => {
      lobbyDisconnectTimers.delete(timerKey);
      const currentLobby = await matchService.getLobby(lobbyId);
      if (!currentLobby) return;

      // Check if host reconnected by seeing if they have an active WS in the lobby
      const lobbyWsClients = lobbyConnections.get(lobbyId);
      let hostReconnected = false;
      if (lobbyWsClients) {
        for (const client of lobbyWsClients) {
          const info = clients.get(client);
          if (info?.userId === userId) {
            hostReconnected = true;
            break;
          }
        }
      }

      if (hostReconnected) {
        log(`[LobbyDisconnect] Host ${username} reconnected to lobby ${lobbyId}, skipping close`, "ws");
        return;
      }

      await matchService.leaveLobby(lobbyId, userId);
      broadcastToLobby(lobbyId, {
        type: "lobby_closed",
        payload: { reason: "Host disconnected" },
      });
      lobbyConnections.delete(lobbyId);
      log(`Host ${username} timed out from lobby ${lobbyId} after ${LOBBY_DISCONNECT_GRACE_PERIOD / 1000}s, lobby closed`, "ws");
    }, LOBBY_DISCONNECT_GRACE_PERIOD);

    lobbyDisconnectTimers.set(timerKey, timer);
  } else if (lobby.guestId === userId) {
    const updatedLobby = await matchService.leaveLobby(lobbyId, userId);
    if (updatedLobby) {
      broadcastToLobby(lobbyId, {
        type: "lobby_update",
        payload: updatedLobby,
      });
    }
    log(`Guest ${username} left lobby ${lobbyId}`, "ws");
  }
}

function cancelLobbyDisconnectTimer(lobbyId: string, userId: string): boolean {
  const timerKey = `${lobbyId}-${userId}`;
  const timer = lobbyDisconnectTimers.get(timerKey);
  if (timer) {
    clearTimeout(timer);
    lobbyDisconnectTimers.delete(timerKey);
    log(`[LobbyDisconnect] Cancelled grace timer for ${userId} in lobby ${lobbyId}`, "ws");
    return true;
  }
  return false;
}

async function handleDisconnectFromMatch(ws: WebSocket, client: ClientConnection) {
  const { matchId, userId, username } = client;
  if (!matchId || !userId) return;

  const matchClients = matchConnections.get(matchId);
  matchClients?.delete(ws);

  await matchEngine.markDisconnected(matchId, userId);

  broadcastToMatch(matchId, {
    type: "participant_disconnected",
    payload: { userId, username },
  });
  log(`Player ${username} disconnected from match ${matchId}, starting ${DISCONNECT_GRACE_PERIOD / 1000}s grace period`, "ws");

  // Auto-submit wrong answer for disconnected player after timeout
  scheduleAutoSubmit(matchId, userId, username);

  const timerKey = `${matchId}-${userId}`;

  if (disconnectTimers.has(timerKey)) {
    clearTimeout(disconnectTimers.get(timerKey)!);
  }

  const timer = setTimeout(async () => {
    disconnectTimers.delete(timerKey);

    const match = await matchEngine.getMatchFromDb(matchId);
    if (!match) {
      log(`[DisconnectTimer] Match ${matchId} not found, skipping cancel`, "ws");
      return;
    }

    if (match.status !== MatchStatus.ACTIVE) {
      log(`[DisconnectTimer] Match ${matchId} is ${match.status}, not ACTIVE. Skipping cancel.`, "ws");
      return;
    }

    const participants = await matchEngine.getParticipants(matchId);
    const participant = participants.find(p => p.userId === userId);

    if (participant?.isConnected) {
      log(`[DisconnectTimer] Player ${username} reconnected to match ${matchId}, skipping cancel`, "ws");
      return;
    }

    const matchEnd = await matchEngine.cancelMatchForDisconnect(matchId, userId);

    if (matchEnd) {
      broadcastToMatch(matchId, {
        type: "match_end",
        payload: matchEnd,
      });
      matchConnections.delete(matchId);
      log(`Player ${username} timed out from match ${matchId} after ${DISCONNECT_GRACE_PERIOD / 1000}s, match cancelled`, "ws");
    }
  }, DISCONNECT_GRACE_PERIOD);

  disconnectTimers.set(timerKey, timer);
}

function cancelDisconnectTimer(matchId: string, userId: string) {
  const timerKey = `${matchId}-${userId}`;
  const timer = disconnectTimers.get(timerKey);
  if (timer) {
    clearTimeout(timer);
    disconnectTimers.delete(timerKey);
    log(`[DisconnectTimer] Cancelled grace timer for ${userId} in match ${matchId}`, "ws");
  }
}

async function scheduleAutoSubmit(matchId: string, userId: string, username: string) {
  const timerKey = `${matchId}-${userId}`;

  if (autoSubmitTimers.has(timerKey)) {
    clearTimeout(autoSubmitTimers.get(timerKey)!);
  }

  const matchState = await matchEngine.buildMatchState(matchId);
  if (!matchState || matchState.status !== MatchStatus.ACTIVE) return;

  const participant = matchState.participants.find(p => p.userId === userId);
  if (!participant || participant.hasAnsweredCurrent) return;

  const currentIdx = matchState.currentQuestionIndex;
  log(`[AutoSubmit] Scheduling auto-submit for ${username} in match ${matchId} at idx=${currentIdx} in ${AUTO_SUBMIT_TIMEOUT / 1000}s`, "ws");

  const timer = setTimeout(async () => {
    autoSubmitTimers.delete(timerKey);

    try {
      const currentState = await matchEngine.buildMatchState(matchId);
      if (!currentState || currentState.status !== MatchStatus.ACTIVE) {
        log(`[AutoSubmit] Match ${matchId} no longer active, skipping auto-submit`, "ws");
        return;
      }

      if (currentState.currentQuestionIndex !== currentIdx) {
        log(`[AutoSubmit] Match ${matchId} already advanced past idx=${currentIdx}, skipping`, "ws");
        return;
      }

      const p = currentState.participants.find(p => p.userId === userId);
      if (p?.hasAnsweredCurrent) {
        log(`[AutoSubmit] Player ${username} already answered idx=${currentIdx}, skipping`, "ws");
        return;
      }

      // Check if player reconnected
      const participants = await matchEngine.getParticipants(matchId);
      const dbParticipant = participants.find(pp => pp.userId === userId);
      if (dbParticipant?.isConnected) {
        log(`[AutoSubmit] Player ${username} reconnected to match ${matchId}, skipping auto-submit`, "ws");
        return;
      }

      log(`[AutoSubmit] Auto-submitting wrong answer for ${username} in match ${matchId} at idx=${currentIdx}`, "ws");

      const result = await matchEngine.submitAnswer(matchId, userId, currentIdx, "__auto_timeout__", `auto_submit_${matchId}_${currentIdx}`);

      if (result.status === "REJECTED") {
        log(`[AutoSubmit] Auto-submit rejected for ${username}: ${result.reason}`, "ws");
        return;
      }

      // Broadcast answer status
      if (result.answerStatus) {
        broadcastToMatch(matchId, {
          type: "answer_status",
          payload: {
            matchId,
            idx: currentIdx,
            answeredCount: result.answerStatus.answeredCount,
            required: result.answerStatus.required,
          },
        });
      }

      // Broadcast participant_answered
      const updatedState = await matchEngine.buildMatchState(matchId);
      if (updatedState) {
        broadcastToMatch(matchId, {
          type: "participant_answered",
          payload: {
            matchId,
            userId,
            questionIndex: currentIdx,
            idx: currentIdx,
            autoSubmitted: true,
            participants: updatedState.participants.map(p => ({
              userId: p.userId,
              username: p.username,
              score: p.score,
              hasAnsweredCurrent: p.hasAnsweredCurrent,
            })),
          },
        });
      }

      // Handle advance if both answered
      if (result.advance) {
        if (result.advance.finished) {
          const allParticipants = await matchEngine.getParticipants(matchId);
          const match = await matchEngine.getMatchFromDb(matchId);
          const totalQuestions = match?.totalQuestions || 10;

          const matchEnd = await matchEngine.completeMatchFinish(matchId, allParticipants, totalQuestions);

          if (matchEnd) {
            for (const mp of matchEnd.participants) {
              try {
                await streakService.processMatchCompletion(mp.userId, matchId);
              } catch (e) {
                console.error("Failed to process streak:", e);
              }
            }
            broadcastToMatch(matchId, { type: "match_end", payload: matchEnd });
          }
        } else if (result.advance.nextQuestion) {
          const advancedState = await matchEngine.buildMatchState(matchId);
          if (advancedState) {
            const newIdx = result.advance.newIndex;
            const seedVer = await getSeedVersionForQuestion(matchId, newIdx);
            const clientMatchState = sanitizeMatchStateForClient(advancedState, seedVer);

            broadcastToMatch(matchId, {
              type: "next_question",
              payload: {
                ...clientMatchState,
                answerStatus: { idx: newIdx, answeredCount: 0, required: 2 },
              },
            });

            // Schedule another auto-submit for the next question if still disconnected
            scheduleAutoSubmit(matchId, userId, username);
          }
        }
      }
    } catch (error) {
      console.error(`[AutoSubmit] Error auto-submitting for ${username} in match ${matchId}:`, error);
    }
  }, AUTO_SUBMIT_TIMEOUT);

  autoSubmitTimers.set(timerKey, timer);
}

function cancelAutoSubmit(matchId: string, userId: string) {
  const timerKey = `${matchId}-${userId}`;
  const timer = autoSubmitTimers.get(timerKey);
  if (timer) {
    clearTimeout(timer);
    autoSubmitTimers.delete(timerKey);
    log(`[AutoSubmit] Cancelled auto-submit timer for ${userId} in match ${matchId}`, "ws");
  }
}

