import { useState, useEffect } from "react";
import { useLocation } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ChevronLeft, ChevronRight, Loader2 } from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { format } from "date-fns";

interface AuditEntry {
  id: number;
  adminUserId: string;
  action: string;
  targetUserId: string | null;
  metadata: Record<string, unknown> | null;
  createdAt: string;
}

interface AuditLogResponse {
  entries: AuditEntry[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

export default function AdminAuditLog() {
  const [, navigate] = useLocation();
  const { user, isLoading: authLoading, isAuthenticated } = useAuth();
  const [page, setPage] = useState(1);

  useEffect(() => {
    if (!authLoading && (!isAuthenticated || !user?.isAdmin)) {
      navigate("/admin");
    }
  }, [authLoading, isAuthenticated, user, navigate]);

  const { data, isLoading, error } = useQuery<AuditLogResponse>({
    queryKey: ["/api/admin/audit-log", page],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: page.toString(),
        limit: "20",
      });
      const response = await fetch(`/api/admin/audit-log?${params}`, {
        credentials: "include",
      });
      if (!response.ok) {
        throw new Error("Failed to fetch audit log");
      }
      return response.json();
    },
    enabled: isAuthenticated && user?.isAdmin,
  });

  if (authLoading || isLoading) {
    return (
      <div className="flex items-center justify-center h-full min-h-[400px]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center h-full">
        <Card className="w-full max-w-md">
          <CardContent className="pt-6 text-center text-destructive">
            <p>Failed to load audit log.</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  const getActionBadgeVariant = (action: string): "default" | "secondary" | "destructive" | "outline" => {
    if (action.includes("revoke") || action.includes("delete")) return "destructive";
    if (action.includes("grant") || action.includes("adjust")) return "default";
    if (action.includes("toggle")) return "secondary";
    return "outline";
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold" data-testid="text-admin-audit-title">Audit Log</h1>
        <p className="text-muted-foreground">Track all administrative actions</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Recent Actions</CardTitle>
        </CardHeader>
        <CardContent>
          {!data || data.entries.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">No audit entries found.</p>
          ) : (
            <>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Time</TableHead>
                    <TableHead>Admin</TableHead>
                    <TableHead>Action</TableHead>
                    <TableHead>Target User</TableHead>
                    <TableHead>Details</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {data.entries.map((entry) => (
                    <TableRow key={entry.id} data-testid={`row-audit-${entry.id}`}>
                      <TableCell className="font-mono text-sm">
                        {format(new Date(entry.createdAt), "MMM dd, HH:mm:ss")}
                      </TableCell>
                      <TableCell className="font-mono text-xs">
                        {entry.adminUserId.slice(0, 8)}...
                      </TableCell>
                      <TableCell>
                        <Badge variant={getActionBadgeVariant(entry.action)}>
                          {entry.action}
                        </Badge>
                      </TableCell>
                      <TableCell className="font-mono text-xs">
                        {entry.targetUserId ? `${entry.targetUserId.slice(0, 8)}...` : "-"}
                      </TableCell>
                      <TableCell className="max-w-[200px] truncate text-xs text-muted-foreground">
                        {entry.metadata ? JSON.stringify(entry.metadata) : "-"}
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>

              {data.pagination && data.pagination.totalPages > 1 && (
                <div className="flex items-center justify-between mt-4">
                  <p className="text-sm text-muted-foreground">
                    Page {data.pagination.page} of {data.pagination.totalPages} ({data.pagination.total} entries)
                  </p>
                  <div className="flex gap-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setPage(p => Math.max(1, p - 1))}
                      disabled={page === 1}
                      data-testid="button-prev-page"
                    >
                      <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setPage(p => Math.min(data.pagination.totalPages, p + 1))}
                      disabled={page === data.pagination.totalPages}
                      data-testid="button-next-page"
                    >
                      <ChevronRight className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              )}
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

server/vite.ts.content:
import { type Express } from "express";
import { createServer as createViteServer, createLogger } from "vite";
import { type Server } from "http";
import viteConfig from "../vite.config";
import fs from "fs";
import path from "path";
import { nanoid } from "nanoid";

const viteLogger = createLogger();

export async function setupVite(server: Server, app: Express) {
  const serverOptions = {
    middlewareMode: true,
    hmr: { server, path: "/vite-hmr" },
    allowedHosts: true as const,
  };

  const vite = await createViteServer({
    ...viteConfig,
    configFile: false,
    customLogger: {
      ...viteLogger,
      error: (msg, options) => {
        viteLogger.error(msg, options);
        process.exit(1);
      },
    },
    server: serverOptions,
    appType: "custom",
  });

  app.use(vite.middlewares);

  app.use("*", async (req, res, next) => {
    const url = req.originalUrl;

    try {
      const clientTemplate = path.resolve(
        import.meta.dirname,
        "..",
        "client",
        "index.html",
      );

      // always reload the index.html file from disk incase it changes
      let template = await fs.promises.readFile(clientTemplate, "utf-8");
      template = template.replace(
        `src="/src/main.tsx"`,
        `src="/src/main.tsx?v=${nanoid()}"`,
      );
      const page = await vite.transformIndexHtml(url, template);
      res.status(200).set({ "Content-Type": "text/html" }).end(page);
    } catch (e) {
      vite.ssrFixStacktrace(e as Error);
      next(e);
    }
  });
}

server/services/foundersPassService.ts.content:
import { db } from "../db";
import { foundersPass, foundersPassEvents, users, appConfig, activeUserCounter } from "@shared/schema";
import { eq, and, sql } from "drizzle-orm";
import crypto from "crypto";

const PEPPER = process.env.FOUNDERS_PASS_PEPPER || "default-pepper-change-in-production";

export function generatePassToken(): string {
  return crypto.randomBytes(32).toString("base64url");
}

export function hashToken(token: string): string {
  return crypto.createHash("sha256").update(token + PEPPER).digest("hex");
}

export interface PassWithToken {
  id: string;
  rawToken: string;
  tokenHash: string;
  issuedToUserId: string;
  status: string;
  createdAt: Date | null;
}

async function logPassEvent(
  passId: string,
  eventType: "ISSUED" | "LINK_VIEWED" | "REDEEM_ATTEMPT" | "REDEEM_SUCCESS" | "REDEEM_FAIL" | "DEACTIVATED_GLOBAL" | "DEACTIVATED_INDIVIDUAL",
  ip?: string | null,
  userAgent?: string | null,
  deviceFingerprint?: string | null,
  metadata?: Record<string, any>
) {
  await db.insert(foundersPassEvents).values({
    passId,
    eventType,
    ip: ip || null,
    userAgent: userAgent || null,
    deviceFingerprint: deviceFingerprint || null,
    metadata: metadata || null,
  });
}

export async function issuePassToUser(userId: string): Promise<PassWithToken | null> {
  const existingPass = await db.query.foundersPass.findFirst({
    where: and(
      eq(foundersPass.issuedToUserId, userId),
      eq(foundersPass.status, "ACTIVE")
    ),
  });

  if (existingPass) {
    return null;
  }

  const rawToken = generatePassToken();
  const tokenHash = hashToken(rawToken);

  const [pass] = await db.insert(foundersPass).values({
    tokenHash,
    issuedToUserId: userId,
    status: "ACTIVE",
  }).returning();

  await logPassEvent(pass.id, "ISSUED", null, null, null, { userId });

  return {
    id: pass.id,
    rawToken,
    tokenHash: pass.tokenHash,
    issuedToUserId: pass.issuedToUserId,
    status: pass.status,
    createdAt: pass.createdAt,
  };
}

export async function getActivePassForUser(userId: string): Promise<{ id: string; tokenHash: string; createdAt: Date | null } | null> {
  const pass = await db.query.foundersPass.findFirst({
    where: and(
      eq(foundersPass.issuedToUserId, userId),
      eq(foundersPass.status, "ACTIVE")
    ),
  });
  return pass ? { id: pass.id, tokenHash: pass.tokenHash, createdAt: pass.createdAt } : null;
}

export async function validatePassToken(tokenHash: string): Promise<{
  valid: boolean;
  passId?: string;
  reason?: string;
}> {
  const pass = await db.query.foundersPass.findFirst({
    where: eq(foundersPass.tokenHash, tokenHash),
  });

  if (!pass) {
    return { valid: false, reason: "Pass not found" };
  }

  if (pass.status !== "ACTIVE") {
    return { valid: false, reason: `Pass is ${pass.status.toLowerCase()}` };
  }

  const config = await db.query.appConfig.findFirst({
    where: eq(appConfig.key, "founders_cap"),
  });

  const gateConfig = config?.value as { enabled?: boolean; maxActiveUsers?: number } | null;
  if (!gateConfig?.enabled) {
    return { valid: false, reason: "Founders cap is disabled" };
  }

  const counter = await db.query.activeUserCounter.findFirst();
  if (counter && gateConfig.maxActiveUsers && counter.count >= gateConfig.maxActiveUsers) {
    return { valid: false, reason: "Founders cap reached" };
  }

  return { valid: true, passId: pass.id };
}

export async function recordLinkViewed(
  tokenHash: string,
  ip?: string,
  userAgent?: string,
  deviceFingerprint?: string
): Promise<void> {
  const pass = await db.query.foundersPass.findFirst({
    where: eq(foundersPass.tokenHash, tokenHash),
  });

  if (pass) {
    await logPassEvent(pass.id, "LINK_VIEWED", ip, userAgent, deviceFingerprint);
  }
}

export async function consumePassAtomic(
  tokenHash: string,
  consumedByUserId: string,
  consumedByIp?: string,
  consumedByDeviceFingerprint?: string
): Promise<{ success: boolean; error?: string }> {
  return await db.transaction(async (tx) => {
    const [pass] = await tx
      .select()
      .from(foundersPass)
      .where(eq(foundersPass.tokenHash, tokenHash))
      .for("update");

    if (!pass) {
      return { success: false, error: "Pass not found" };
    }

    if (pass.status !== "ACTIVE") {
      await tx.insert(foundersPassEvents).values({
        passId: pass.id,
        eventType: "REDEEM_FAIL",
        ip: consumedByIp || null,
        deviceFingerprint: consumedByDeviceFingerprint || null,
        metadata: { reason: `Pass status is ${pass.status}` },
      });
      return { success: false, error: `Pass is ${pass.status.toLowerCase()}` };
    }

    const config = await tx.query.appConfig.findFirst({
      where: eq(appConfig.key, "founders_cap"),
    });
    const gateConfig = config?.value as { enabled?: boolean; maxActiveUsers?: number } | null;

    if (!gateConfig?.enabled) {
      return { success: false, error: "Founders cap is disabled" };
    }

    const [counter] = await tx
      .select()
      .from(activeUserCounter)
      .for("update");

    if (counter && gateConfig.maxActiveUsers && counter.count >= gateConfig.maxActiveUsers) {
      await deactivateAllPassesInTx(tx);
      return { success: false, error: "Founders cap reached" };
    }

    await tx.update(foundersPass)
      .set({
        status: "CONSUMED",
        consumedAt: new Date(),
        consumedByUserId,
        consumedByIp: consumedByIp || null,
        consumedByDeviceFingerprint: consumedByDeviceFingerprint || null,
      })
      .where(eq(foundersPass.id, pass.id));

    await tx.insert(foundersPassEvents).values({
      passId: pass.id,
      eventType: "REDEEM_SUCCESS",
      ip: consumedByIp || null,
      deviceFingerprint: consumedByDeviceFingerprint || null,
      metadata: { consumedByUserId },
    });

    return { success: true };
  });
}

async function deactivateAllPassesInTx(tx: any): Promise<number> {
  const activePasses = await tx
    .select({ id: foundersPass.id })
    .from(foundersPass)
    .where(eq(foundersPass.status, "ACTIVE"));

  if (activePasses.length === 0) return 0;

  await tx.update(foundersPass)
    .set({
      status: "DEACTIVATED",
      deactivatedAt: new Date(),
    })
    .where(eq(foundersPass.status, "ACTIVE"));

  for (const pass of activePasses) {
    await tx.insert(foundersPassEvents).values({
      passId: pass.id,
      eventType: "DEACTIVATED_GLOBAL",
      metadata: { reason: "Founders cap reached" },
    });
  }

  return activePasses.length;
}

export async function deactivateAllPasses(): Promise<number> {
  return await db.transaction(async (tx) => {
    return await deactivateAllPassesInTx(tx);
  });
}

export async function deactivatePass(passId: string, reason?: string): Promise<boolean> {
  const [pass] = await db
    .update(foundersPass)
    .set({
      status: "DEACTIVATED",
      deactivatedAt: new Date(),
    })
    .where(and(
      eq(foundersPass.id, passId),
      eq(foundersPass.status, "ACTIVE")
    ))
    .returning();

  if (pass) {
    await logPassEvent(pass.id, "DEACTIVATED_INDIVIDUAL", null, null, null, { reason });
    return true;
  }
  return false;
}

export async function getPassesByStatus(status: "ACTIVE" | "CONSUMED" | "DEACTIVATED" | "EXPIRED"): Promise<Array<{
  id: string;
  issuedToUserId: string;
  status: string;
  createdAt: Date | null;
  consumedAt: Date | null;
  consumedByUserId: string | null;
}>> {
  return await db.query.foundersPass.findMany({
    where: eq(foundersPass.status, status),
    orderBy: (pass, { desc }) => [desc(pass.createdAt)],
  });
}

export async function getAllPasses(): Promise<Array<{
  id: string;
  issuedToUserId: string;
  status: string;
  createdAt: Date | null;
  consumedAt: Date | null;
  consumedByUserId: string | null;
}>> {
  return await db.query.foundersPass.findMany({
    orderBy: (pass, { desc }) => [desc(pass.createdAt)],
  });
}

export async function isFoundersGateClosed(): Promise<boolean> {
  const config = await db.query.appConfig.findFirst({
    where: eq(appConfig.key, "founders_cap"),
  });
  const gateConfig = config?.value as { enabled?: boolean; maxActiveUsers?: number } | null;

  if (!gateConfig?.enabled) {
    return true;
  }

  const counter = await db.query.activeUserCounter.findFirst();
  if (counter && gateConfig.maxActiveUsers && counter.count >= gateConfig.maxActiveUsers) {
    return true;
  }

  return false;
}

export async function checkDeviceFingerprintAbuse(deviceFingerprint: string): Promise<boolean> {
  const existingActiveUser = await db.query.users.findFirst({
    where: and(
      eq(users.deviceFingerprint, deviceFingerprint),
      eq(users.status, "ACTIVE")
    ),
  });
  return !!existingActiveUser;
}

server/services/adminService.ts.content:
import { db } from "../db";
import { 
  adminAuditLog, 
  users, 
  wallets, 
  ledgerEntries, 
  purchaseEvents, 
  userEntitlements, 
  featureFlags,
  eventLog,
  type InsertAdminAuditLog 
} from "@shared/schema";
import { eq, sql, desc, ilike, and, gte, lte, count } from "drizzle-orm";
import { walletService } from "./walletService";
import { storage } from "../storage";

interface AdminActionContext {
  adminUserId: string;
  targetUserId?: string;
  metadata?: Record<string, unknown>;
}

class AdminService {
  async logAction(
    adminUserId: string,
    action: string,
    targetUserId?: string | null,
    metadata?: Record<string, unknown>
  ): Promise<void> {
    await db.insert(adminAuditLog).values({
      adminUserId,
      action,
      targetUserId: targetUserId || null,
      metadata: metadata || null,
    });
  }

  async searchUsers(
    search: string,
    page: number = 1,
    limit: number = 20
  ): Promise<{ users: any[]; total: number; page: number; totalPages: number }> {
    const offset = (page - 1) * limit;

    const searchCondition = search 
      ? ilike(users.username, `%${search}%`)
      : undefined;

    const [userResults, countResult] = await Promise.all([
      db.select()
        .from(users)
        .where(searchCondition)
        .orderBy(desc(users.createdAt))
        .limit(limit)
        .offset(offset),
      db.select({ count: count() })
        .from(users)
        .where(searchCondition),
    ]);

    const total = countResult[0]?.count || 0;

    return {
      users: userResults,
      total,
      page,
      totalPages: Math.ceil(total / limit),
    };
  }

  async getUserWallet(userId: string): Promise<{
    wallet: any;
    ledger: any[];
  } | null> {
    const walletData = await walletService.getWalletWithHistory(userId, 50);
    if (!walletData) {
      return null;
    }
    return {
      wallet: walletData.wallet,
      ledger: walletData.recentEntries,
    };
  }

  async getPurchaseEvents(
    page: number = 1,
    limit: number = 20,
    status?: string,
    userId?: string
  ): Promise<{ events: any[]; total: number; page: number; totalPages: number }> {
    const offset = (page - 1) * limit;

    const conditions = [];
    if (status) conditions.push(eq(purchaseEvents.status, status));
    if (userId) conditions.push(eq(purchaseEvents.userId, userId));

    const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

    const [events, countResult] = await Promise.all([
      db.select()
        .from(purchaseEvents)
        .where(whereClause)
        .orderBy(desc(purchaseEvents.createdAt))
        .limit(limit)
        .offset(offset),
      db.select({ count: count() })
        .from(purchaseEvents)
        .where(whereClause),
    ]);

    const total = countResult[0]?.count || 0;

    return {
      events,
      total,
      page,
      totalPages: Math.ceil(total / limit),
    };
  }

  async getUserEntitlements(userId: string): Promise<any[]> {
    return db.select()
      .from(userEntitlements)
      .where(eq(userEntitlements.userId, userId))
      .orderBy(desc(userEntitlements.createdAt));
  }

  async grantEntitlement(
    ctx: AdminActionContext,
    entitlementKey: string,
    expiresAt?: Date | null
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    try {
      await storage.grantEntitlement({
        userId: ctx.targetUserId,
        entitlementKey,
        source: "admin_grant",
        sourceReference: `admin:${ctx.adminUserId}`,
        expiresAt: expiresAt || null,
      });

      await this.logAction(ctx.adminUserId, "grant_entitlement", ctx.targetUserId, {
        entitlementKey,
        expiresAt: expiresAt?.toISOString() || null,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to grant entitlement" 
      };
    }
  }

  async revokeEntitlement(
    ctx: AdminActionContext,
    entitlementKey: string,
    reason: string
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    try {
      await storage.revokeEntitlement(ctx.targetUserId, entitlementKey, reason);

      await this.logAction(ctx.adminUserId, "revoke_entitlement", ctx.targetUserId, {
        entitlementKey,
        reason,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to revoke entitlement" 
      };
    }
  }

  async adjustPackPTS(
    ctx: AdminActionContext,
    amount: number,
    reason: string
  ): Promise<{ success: boolean; error?: string; newBalance?: number }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    try {
      const adjustKey = `admin_adjust_${Date.now()}_${Math.random().toString(36).substring(7)}`;
      const result = await walletService.adjust(
        ctx.targetUserId,
        amount,
        reason,
        adjustKey,
        undefined,
        { source: "admin", eventType: "admin_adjustment", refType: "admin_action", refId: adjustKey }
      );

      if (!result.success) {
        return { success: false, error: result.error };
      }

      await this.logAction(ctx.adminUserId, "adjust_packpts", ctx.targetUserId, {
        amount,
        reason,
        newBalance: result.wallet?.balance,
      });

      return { success: true, newBalance: result.wallet?.balance };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to adjust PackPTS" 
      };
    }
  }

  async getFeatureFlags(): Promise<any[]> {
    return db.select()
      .from(featureFlags)
      .orderBy(featureFlags.key);
  }

  async toggleFeatureFlag(
    ctx: AdminActionContext,
    key: string,
    enabled: boolean
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const existing = await db.select()
        .from(featureFlags)
        .where(eq(featureFlags.key, key))
        .limit(1);

      if (existing.length === 0) {
        await db.insert(featureFlags).values({
          key,
          enabled,
        });
      } else {
        await db.update(featureFlags)
          .set({ enabled, updatedAt: new Date() })
          .where(eq(featureFlags.key, key));
      }

      await this.logAction(ctx.adminUserId, "toggle_feature_flag", null, {
        key,
        enabled,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to toggle feature flag" 
      };
    }
  }

  async updateFeatureFlagValue(
    ctx: AdminActionContext,
    key: string,
    value: unknown
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const existing = await db.select()
        .from(featureFlags)
        .where(eq(featureFlags.key, key))
        .limit(1);

      if (existing.length === 0) {
        await db.insert(featureFlags).values({
          key,
          enabled: true,
          value,
        });
      } else {
        await db.update(featureFlags)
          .set({ value, updatedAt: new Date() })
          .where(eq(featureFlags.key, key));
      }

      await this.logAction(ctx.adminUserId, "update_feature_flag_value", null, {
        key,
        value,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to update feature flag value" 
      };
    }
  }

  async getAuditLog(
    page: number = 1,
    limit: number = 50,
    adminUserId?: string
  ): Promise<{ entries: any[]; total: number; page: number; totalPages: number }> {
    const offset = (page - 1) * limit;

    const whereClause = adminUserId 
      ? eq(adminAuditLog.adminUserId, adminUserId)
      : undefined;

    const [entries, countResult] = await Promise.all([
      db.select()
        .from(adminAuditLog)
        .where(whereClause)
        .orderBy(desc(adminAuditLog.createdAt))
        .limit(limit)
        .offset(offset),
      db.select({ count: count() })
        .from(adminAuditLog)
        .where(whereClause),
    ]);

    const total = countResult[0]?.count || 0;

    return {
      entries,
      total,
      page,
      totalPages: Math.ceil(total / limit),
    };
  }

  async grantAdminAccess(
    ctx: AdminActionContext
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    try {
      // Check if target user exists
      const targetUser = await db.select()
        .from(users)
        .where(eq(users.id, ctx.targetUserId))
        .limit(1);

      if (targetUser.length === 0) {
        return { success: false, error: "User not found" };
      }

      if (targetUser[0].isAdmin) {
        return { success: false, error: "User is already an admin" };
      }

      // Grant admin access
      await db.update(users)
        .set({ isAdmin: true, updatedAt: new Date() })
        .where(eq(users.id, ctx.targetUserId));

      await this.logAction(ctx.adminUserId, "grant_admin", ctx.targetUserId, {
        action: "Granted admin privileges",
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to grant admin access" 
      };
    }
  }

  async revokeAdminAccess(
    ctx: AdminActionContext,
    reason: string
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    // Prevent self-revocation
    if (ctx.adminUserId === ctx.targetUserId) {
      return { success: false, error: "Cannot revoke your own admin access" };
    }

    try {
      // Check if target user exists and is admin
      const targetUser = await db.select()
        .from(users)
        .where(eq(users.id, ctx.targetUserId))
        .limit(1);

      if (targetUser.length === 0) {
        return { success: false, error: "User not found" };
      }

      if (!targetUser[0].isAdmin) {
        return { success: false, error: "User is not an admin" };
      }

      // Revoke admin access
      await db.update(users)
        .set({ isAdmin: false, updatedAt: new Date() })
        .where(eq(users.id, ctx.targetUserId));

      await this.logAction(ctx.adminUserId, "revoke_admin", ctx.targetUserId, {
        action: "Revoked admin privileges",
        reason,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to revoke admin access" 
      };
    }
  }

  async suspendUser(
    ctx: AdminActionContext,
    reason: string
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    // Prevent self-suspension
    if (ctx.adminUserId === ctx.targetUserId) {
      return { success: false, error: "Cannot suspend yourself" };
    }

    try {
      // Check if target user exists
      const targetUser = await db.select()
        .from(users)
        .where(eq(users.id, ctx.targetUserId))
        .limit(1);

      if (targetUser.length === 0) {
        return { success: false, error: "User not found" };
      }

      // Revoke admin if they have it
      if (targetUser[0].isAdmin) {
        await db.update(users)
          .set({ isAdmin: false, updatedAt: new Date() })
          .where(eq(users.id, ctx.targetUserId));
      }

      // Suspend wallet if exists
      await db.update(wallets)
        .set({ status: "suspended", updatedAt: new Date() })
        .where(eq(wallets.userId, ctx.targetUserId));

      await this.logAction(ctx.adminUserId, "suspend_user", ctx.targetUserId, {
        action: "Suspended user account",
        reason,
        hadAdmin: targetUser[0].isAdmin,
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to suspend user" 
      };
    }
  }

  async unsuspendUser(
    ctx: AdminActionContext
  ): Promise<{ success: boolean; error?: string }> {
    if (!ctx.targetUserId) {
      return { success: false, error: "Target user ID required" };
    }

    try {
      // Check if target user exists
      const targetUser = await db.select()
        .from(users)
        .where(eq(users.id, ctx.targetUserId))
        .limit(1);

      if (targetUser.length === 0) {
        return { success: false, error: "User not found" };
      }

      // Reactivate wallet
      await db.update(wallets)
        .set({ status: "active", updatedAt: new Date() })
        .where(eq(wallets.userId, ctx.targetUserId));

      await this.logAction(ctx.adminUserId, "unsuspend_user", ctx.targetUserId, {
        action: "Unsuspended user account",
      });

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error instanceof Error ? error.message : "Failed to unsuspend user" 
      };
    }
  }

  async getUserAdminStatus(userId: string): Promise<{
    isAdmin: boolean;
    isSuspended: boolean;
    username: string | null;
  } | null> {
    try {
      const user = await db.select({
        id: users.id,
        username: users.username,
        isAdmin: users.isAdmin,
      })
        .from(users)
        .where(eq(users.id, userId))
        .limit(1);

      if (user.length === 0) {
        return null;
      }

      // Check wallet suspension status
      const wallet = await db.select({ status: wallets.status })
        .from(wallets)
        .where(eq(wallets.userId, userId))
        .limit(1);

      return {
        isAdmin: user[0].isAdmin,
        isSuspended: wallet.length > 0 && wallet[0].status === "suspended",
        username: user[0].username,
      };
    } catch (error) {
      return null;
    }
  }

  async getAllAdmins(): Promise<any[]> {
    return db.select({
      id: users.id,
      username: users.username,
      email: users.email,
      createdAt: users.createdAt,
    })
      .from(users)
      .where(eq(users.isAdmin, true))
      .orderBy(desc(users.createdAt));
  }

  async getMetrics(date?: string): Promise<{
    dau: number;
    matchesPerUser: number;
    purchaseConversionRate: number;
    grossPurchaseCount: number;
    packptsLiability: number;
    redemptionRate: number;
  }> {
    const targetDate = date ? new Date(date) : new Date();
    const startOfDay = new Date(targetDate);
    startOfDay.setHours(0, 0, 0, 0);
    const endOfDay = new Date(targetDate);
    endOfDay.setHours(23, 59, 59, 999);

    const [
      dauResult,
      matchStartedResult,
      matchCompletedResult,
      purchaseStartedResult,
      purchaseCompletedResult,
      liabilityResult,
      redeemStartedResult,
      redeemCompletedResult,
    ] = await Promise.all([
      db.select({ count: sql<number>`COUNT(DISTINCT user_id)` })
        .from(eventLog)
        .where(and(
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "match_started"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "match_completed"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "purchase_started"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "purchase_completed"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ total: sql<number>`COALESCE(SUM(balance), 0)` })
        .from(wallets),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "redeem_started"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
      db.select({ count: count() })
        .from(eventLog)
        .where(and(
          eq(eventLog.eventType, "redeem_completed"),
          gte(eventLog.createdAt, startOfDay),
          lte(eventLog.createdAt, endOfDay)
        )),
    ]);

    const dau = Number(dauResult[0]?.count || 0);
    const matchesStarted = Number(matchStartedResult[0]?.count || 0);
    const matchesCompleted = Number(matchCompletedResult[0]?.count || 0);
    const purchasesStarted = Number(purchaseStartedResult[0]?.count || 0);
    const purchasesCompleted = Number(purchaseCompletedResult[0]?.count || 0);
    const liability = Number(liabilityResult[0]?.total || 0);
    const redeemsStarted = Number(redeemStartedResult[0]?.count || 0);
    const redeemsCompleted = Number(redeemCompletedResult[0]?.count || 0);

    return {
      dau,
      matchesPerUser: dau > 0 ? matchesCompleted / dau : 0,
      purchaseConversionRate: purchasesStarted > 0 ? purchasesCompleted / purchasesStarted : 0,
      grossPurchaseCount: purchasesCompleted,
      packptsLiability: liability,
      redemptionRate: redeemsStarted > 0 ? redeemsCompleted / redeemsStarted : 0,
    };
  }
}

export const adminService = new AdminService();

