client/src/pages/link-required.tsx.content:
import { useState, useEffect } from "react";
import { useLocation, Link } from "wouter";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Separator } from "@/components/ui/separator";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Loader2, Shield, Mail, Lock, User, CheckCircle, AlertTriangle, XCircle } from "lucide-react";

const loginSchema = z.object({
  usernameOrEmail: z.string().min(1, "Username or email is required"),
  password: z.string().min(1, "Password is required"),
});

type LoginFormData = z.infer<typeof loginSchema>;

interface LinkChallenge {
  id: string;
  provider: string;
  email: string | null;
  targetUsername: string | null;
  expiresAt: string;
  isHighValue: boolean;
}

export default function LinkRequiredPage() {
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState<"login" | "email">("login");
  const [magicLinkSent, setMagicLinkSent] = useState(false);

  const searchParams = new URLSearchParams(window.location.search);
  const provider = searchParams.get("provider") || "unknown";
  const maskedEmail = searchParams.get("email") || "";
  const verified = searchParams.get("verified") === "true";

  const { data: challenge, isLoading: challengeLoading, error: challengeError } = useQuery<LinkChallenge>({
    queryKey: ["/api/auth/link/challenge"],
    retry: false,
  });

  const loginForm = useForm<LoginFormData>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      usernameOrEmail: "",
      password: "",
    },
  });

  const loginMutation = useMutation({
    mutationFn: async (data: LoginFormData) => {
      const response = await apiRequest("POST", "/api/auth/local-login", data);
      return response.json();
    },
    onSuccess: async (data) => {
      if (data.user) {
        queryClient.setQueryData(["/api/auth/user"], data.user);
      }
      confirmMutation.mutate();
    },
    onError: (error: any) => {
      const message = error?.message || "Invalid username or password";
      toast({
        title: "Login failed",
        description: message,
        variant: "destructive",
      });
    },
  });

  const confirmMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/auth/link/confirm", {});
      return response.json();
    },
    onSuccess: async () => {
      queryClient.invalidateQueries({ queryKey: ["/api/auth/user"] });
      queryClient.invalidateQueries({ queryKey: ["/api/auth/identities"] });
      toast({
        title: "Account linked!",
        description: `Your ${provider} account has been successfully linked.`,
      });
      await new Promise(resolve => setTimeout(resolve, 150));
      setLocation("/");
    },
    onError: (error: any) => {
      const message = error?.message || "Failed to link account";
      const code = error?.code;

      if (code === "VERIFICATION_REQUIRED") {
        toast({
          title: "Email verification required",
          description: "This is a high-value account. Please verify via email first.",
          variant: "destructive",
        });
        setActiveTab("email");
      } else if (code === "WRONG_ACCOUNT") {
        toast({
          title: "Wrong account",
          description: "Please log in to the account that owns this email.",
          variant: "destructive",
        });
      } else {
        toast({
          title: "Link failed",
          description: message,
          variant: "destructive",
        });
      }
    },
  });

  const sendMagicLinkMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/auth/link/send-magic", {});
      return response.json();
    },
    onSuccess: () => {
      setMagicLinkSent(true);
      toast({
        title: "Email sent!",
        description: "Check your inbox for the verification link.",
      });
    },
    onError: (error: any) => {
      const message = error?.message || "Failed to send verification email";
      toast({
        title: "Failed to send email",
        description: message,
        variant: "destructive",
      });
    },
  });

  const cancelMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/auth/link/cancel", {});
      return response.json();
    },
    onSuccess: () => {
      setLocation("/");
    },
  });

  useEffect(() => {
    if (verified && challenge) {
      confirmMutation.mutate();
    }
  }, [verified, challenge]);

  if (challengeLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <Card className="max-w-md w-full">
          <CardContent className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </CardContent>
        </Card>
      </div>
    );
  }

  if (challengeError || !challenge) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <Card className="max-w-md w-full">
          <CardHeader className="text-center">
            <div className="mx-auto w-12 h-12 rounded-full bg-destructive/10 flex items-center justify-center mb-4">
              <XCircle className="h-6 w-6 text-destructive" />
            </div>
            <CardTitle>No Pending Link</CardTitle>
            <CardDescription>
              There's no account linking request in progress.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button asChild className="w-full">
              <Link href="/">Go to Home</Link>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  const providerName = provider === "workos" ? "WorkOS" : provider === "replit" ? "Replit" : provider;

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <Card className="max-w-md w-full">
        <CardHeader className="text-center">
          <div className="mx-auto w-12 h-12 rounded-full bg-amber-500/10 flex items-center justify-center mb-4">
            <Shield className="h-6 w-6 text-amber-500" />
          </div>
          <CardTitle>Account Protection</CardTitle>
          <CardDescription>
            We found an existing PackPTS account with the email{" "}
            <span className="font-mono text-foreground">{challenge.email || maskedEmail}</span>.
          </CardDescription>
        </CardHeader>

        <CardContent className="space-y-4">
          <Alert>
            <AlertTriangle className="h-4 w-4" />
            <AlertDescription>
              To protect your account, please verify you own this email before linking your {providerName} login.
            </AlertDescription>
          </Alert>

          {challenge.isHighValue && (
            <Alert className="border-amber-500/50 bg-amber-500/5">
              <Shield className="h-4 w-4 text-amber-500" />
              <AlertDescription className="text-amber-700 dark:text-amber-400">
                This is a high-value account. Email verification is required.
              </AlertDescription>
            </Alert>
          )}

          {verified && (
            <Alert className="border-green-500/50 bg-green-500/5">
              <CheckCircle className="h-4 w-4 text-green-500" />
              <AlertDescription className="text-green-700 dark:text-green-400">
                Email verified! Completing link...
              </AlertDescription>
            </Alert>
          )}

          {!verified && (
            <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as "login" | "email")} className="w-full">
              <TabsList className="grid w-full grid-cols-2">
                <TabsTrigger value="login" data-testid="tab-link-login">
                  Log In
                </TabsTrigger>
                <TabsTrigger value="email" data-testid="tab-link-email">
                  Email Verification
                </TabsTrigger>
              </TabsList>

              <TabsContent value="login" className="mt-4 space-y-4">
                <p className="text-sm text-muted-foreground">
                  Log in to your existing PackPTS account to link your {providerName} login.
                </p>

                <Form {...loginForm}>
                  <form onSubmit={loginForm.handleSubmit((data) => loginMutation.mutate(data))} className="space-y-4">
                    <FormField
                      control={loginForm.control}
                      name="usernameOrEmail"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Username or Email</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <User className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                              <Input
                                placeholder="Enter your username or email"
                                className="pl-10"
                                {...field}
                                disabled={loginMutation.isPending || confirmMutation.isPending}
                                data-testid="input-link-username"
                              />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={loginForm.control}
                      name="password"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Password</FormLabel>
                          <FormControl>
                            <div className="relative">
                              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                              <Input
                                type="password"
                                placeholder="Enter your password"
                                className="pl-10"
                                {...field}
                                disabled={loginMutation.isPending || confirmMutation.isPending}
                                data-testid="input-link-password"
                              />
                            </div>
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <Button
                      type="submit"
                      className="w-full"
                      disabled={loginMutation.isPending || confirmMutation.isPending}
                      data-testid="button-link-login"
                    >
                      {loginMutation.isPending || confirmMutation.isPending ? (
                        <>
                          <Loader2 className="h-4 w-4 animate-spin mr-2" />
                          Verifying...
                        </>
                      ) : (
                        "Log In & Link Account"
                      )}
                    </Button>
                  </form>
                </Form>

                <div className="text-center">
                  <Link href="/forgot-password" className="text-sm text-muted-foreground hover:text-foreground">
                    Forgot your password?
                  </Link>
                </div>
              </TabsContent>

              <TabsContent value="email" className="mt-4 space-y-4">
                {magicLinkSent ? (
                  <div className="text-center space-y-4">
                    <div className="mx-auto w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center">
                      <Mail className="h-8 w-8 text-green-500" />
                    </div>
                    <div>
                      <p className="font-medium">Check your email</p>
                      <p className="text-sm text-muted-foreground mt-1">
                        We sent a verification link to {challenge.email || maskedEmail}
                      </p>
                    </div>
                    <p className="text-xs text-muted-foreground">
                      The link expires in 15 minutes. Check your spam folder if you don't see it.
                    </p>
                    <Button
                      variant="outline"
                      onClick={() => sendMagicLinkMutation.mutate()}
                      disabled={sendMagicLinkMutation.isPending}
                      className="w-full"
                    >
                      Resend Email
                    </Button>
                  </div>
                ) : (
                  <>
                    <p className="text-sm text-muted-foreground">
                      We'll send a verification link to your email. Click it to verify ownership and link your account.
                    </p>

                    <div className="p-4 bg-muted/50 rounded-lg">
                      <div className="flex items-center gap-3">
                        <Mail className="h-5 w-5 text-muted-foreground" />
                        <span className="font-mono">{challenge.email || maskedEmail}</span>
                      </div>
                    </div>

                    <Button
                      onClick={() => sendMagicLinkMutation.mutate()}
                      disabled={sendMagicLinkMutation.isPending}
                      className="w-full"
                      data-testid="button-send-magic-link"
                    >
                      {sendMagicLinkMutation.isPending ? (
                        <>
                          <Loader2 className="h-4 w-4 animate-spin mr-2" />
                          Sending...
                        </>
                      ) : (
                        <>
                          <Mail className="h-4 w-4 mr-2" />
                          Send Verification Email
                        </>
                      )}
                    </Button>
                  </>
                )}
              </TabsContent>
            </Tabs>
          )}

          <Separator />

          <div className="flex gap-2">
            <Button
              variant="ghost"
              onClick={() => cancelMutation.mutate()}
              disabled={cancelMutation.isPending}
              className="flex-1"
              data-testid="button-cancel-link"
            >
              Cancel
            </Button>
            <Button asChild variant="outline" className="flex-1">
              <Link href="/">Continue as Guest</Link>
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

server/services/accessService.ts.content:
import { db } from "../db";
import { 
  users, 
  appConfig, 
  waitlistEntries, 
  inviteCodes, 
  accessAuditLog,
  activeUserCounter,
  foundersPass,
  foundersPassEvents,
  FOUNDERS_CAP_DEFAULT,
  type UserStatus,
  type WaitlistStatus,
  type AccessAuditAction,
  type InviteCode,
  type WaitlistEntry,
} from "@shared/schema";
import { eq, sql, and, gt } from "drizzle-orm";
import crypto from "crypto";
import * as foundersPassService from "./foundersPassService";

// Types for config values
interface FoundersCapConfig {
  maxActiveUsers: number;
  enabled: boolean;
  inviteBypass: boolean;
  reservedSeatsForInvites: number;
}

interface ActivationResult {
  activated: boolean;
  reason?: "CAP_REACHED" | "ALREADY_ACTIVE" | "BANNED" | "SUCCESS";
  waitlistPosition?: number;
}

interface InviteValidationResult {
  valid: boolean;
  reason?: "NOT_FOUND" | "EXPIRED" | "EXHAUSTED";
  invite?: InviteCode;
}

interface ActivationContext {
  ipAddress?: string;
  userAgent?: string;
  deviceFingerprint?: string;
  inviteCode?: string;
  foundersPassTokenHash?: string;
  foundersPassApproved?: boolean;
}

// Email normalization (removes dots from gmail, lowercases, etc.)
export function normalizeEmail(email: string): string {
  const [localPart, domain] = email.toLowerCase().split("@");
  if (!localPart || !domain) return email.toLowerCase();

  // For Gmail, remove dots and anything after + 
  if (domain === "gmail.com" || domain === "googlemail.com") {
    const cleanLocal = localPart.split("+")[0]?.replace(/\./g, "") || localPart;
    return `${cleanLocal}@${domain}`;
  }

  // For other providers, just lowercase and remove +alias
  const cleanLocal = localPart.split("+")[0] || localPart;
  return `${cleanLocal}@${domain}`;
}

// Generate a short referral code
export function generateReferralCode(): string {
  return crypto.randomBytes(4).toString("hex").toUpperCase();
}

// Generate an invite code
export function generateInviteCode(): string {
  return crypto.randomBytes(4).toString("hex").toUpperCase();
}

// Get founders cap config from database
export async function getFoundersCapConfig(): Promise<FoundersCapConfig> {
  const [config] = await db
    .select()
    .from(appConfig)
    .where(eq(appConfig.key, "founders_cap"));

  if (!config) {
    return FOUNDERS_CAP_DEFAULT;
  }

  return {
    ...FOUNDERS_CAP_DEFAULT,
    ...(config.value as Partial<FoundersCapConfig>),
  };
}

// Update founders cap config
export async function updateFoundersCapConfig(
  updates: Partial<FoundersCapConfig>,
  updatedBy?: string
): Promise<FoundersCapConfig> {
  const current = await getFoundersCapConfig();
  const newConfig = { ...current, ...updates };

  await db
    .insert(appConfig)
    .values({
      key: "founders_cap",
      value: newConfig,
      updatedBy,
      updatedAt: new Date(),
    })
    .onConflictDoUpdate({
      target: appConfig.key,
      set: {
        value: newConfig,
        updatedBy,
        updatedAt: new Date(),
      },
    });

  return newConfig;
}

// Log access audit event
export async function logAccessAudit(
  action: AccessAuditAction,
  context: {
    userId?: string;
    email?: string;
    ipAddress?: string;
    userAgent?: string;
    deviceFingerprint?: string;
    metadata?: Record<string, unknown>;
  }
): Promise<void> {
  await db.insert(accessAuditLog).values({
    action,
    userId: context.userId,
    email: context.email,
    ipAddress: context.ipAddress,
    userAgent: context.userAgent,
    deviceFingerprint: context.deviceFingerprint,
    metadata: context.metadata,
  });
}

// Get current access summary (active count, cap, etc.)
export async function getAccessSummary(): Promise<{
  activeCount: number;
  maxActiveUsers: number;
  enabled: boolean;
  remainingSeats: number;
  reservedSeatsUsed: number;
  reservedSeatsTotal: number;
  waitlistSize: number;
}> {
  const config = await getFoundersCapConfig();

  const [counter] = await db.select().from(activeUserCounter).where(eq(activeUserCounter.id, 1));
  const activeCount = counter?.count || 0;
  const reservedSeatsUsed = counter?.reservedSeatsUsed || 0;

  const [waitlistCount] = await db
    .select({ count: sql<number>`count(*)::int` })
    .from(waitlistEntries)
    .where(eq(waitlistEntries.status, "WAITING"));

  const remainingSeats = Math.max(0, config.maxActiveUsers - activeCount);

  return {
    activeCount,
    maxActiveUsers: config.maxActiveUsers,
    enabled: config.enabled,
    remainingSeats,
    reservedSeatsUsed,
    reservedSeatsTotal: config.reservedSeatsForInvites,
    waitlistSize: waitlistCount?.count || 0,
  };
}

// Atomic user activation with PostgreSQL row-level locking
export async function tryActivateUser(
  userId: string,
  context: ActivationContext = {}
): Promise<ActivationResult> {
  const config = await getFoundersCapConfig();

  // If cap is disabled, always activate
  if (!config.enabled) {
    await db.update(users).set({
      status: "ACTIVE" as UserStatus,
      activatedAt: new Date(),
      lastSignupIp: context.ipAddress,
      deviceFingerprint: context.deviceFingerprint,
    }).where(eq(users.id, userId));

    await logAccessAudit("ACTIVATION_SUCCESS", {
      userId,
      ipAddress: context.ipAddress,
      userAgent: context.userAgent,
      deviceFingerprint: context.deviceFingerprint,
      metadata: { reason: "cap_disabled" },
    });

    return { activated: true, reason: "SUCCESS" };
  }

  // Check if user already has a status
  const [user] = await db.select().from(users).where(eq(users.id, userId));
  if (!user) {
    return { activated: false, reason: "CAP_REACHED" };
  }

  if (user.status === "ACTIVE") {
    return { activated: true, reason: "ALREADY_ACTIVE" };
  }

  if (user.status === "BANNED") {
    return { activated: false, reason: "BANNED" };
  }

  // Check for invite code bypass
  let useReservedSeat = false;
  if (context.inviteCode && config.inviteBypass) {
    const inviteResult = await validateInviteCode(context.inviteCode);
    if (inviteResult.valid && inviteResult.invite) {
      useReservedSeat = inviteResult.invite.reservedSeat;
    }
  }

  // Check for founders pass approval
  let hasFoundersPass = false;
  if (context.foundersPassApproved && context.foundersPassTokenHash) {
    const passValidation = await foundersPassService.validatePassToken(context.foundersPassTokenHash);
    hasFoundersPass = passValidation.valid;
  }

  // Atomic activation using SELECT FOR UPDATE on the counter row
  return await db.transaction(async (tx) => {
    // Lock the counter row to prevent race conditions
    const [counter] = await tx
      .select()
      .from(activeUserCounter)
      .where(eq(activeUserCounter.id, 1))
      .for("update");

    if (!counter) {
      throw new Error("Active user counter not found");
    }

    const currentActive = counter.count;
    const currentReservedUsed = counter.reservedSeatsUsed;

    // Check if we can activate
    let canActivate = false;
    let shouldUseReservedSeat = false;
    let usedFoundersPass = false;

    if (currentActive < config.maxActiveUsers) {
      // Under cap, can activate normally
      canActivate = true;
    } else if (useReservedSeat && config.inviteBypass) {
      // Cap reached but have invite code with reserved seat
      if (currentReservedUsed < config.reservedSeatsForInvites) {
        canActivate = true;
        shouldUseReservedSeat = true;
      }
    }

    // Founders pass bypass: if user has approved pass, they can activate even if cap is reached
    // as long as the pass is still valid (consume it atomically)
    if (!canActivate && hasFoundersPass && context.foundersPassTokenHash) {
      const [pass] = await tx
        .select()
        .from(foundersPass)
        .where(eq(foundersPass.tokenHash, context.foundersPassTokenHash))
        .for("update");

      if (pass && pass.status === "ACTIVE") {
        canActivate = true;
        usedFoundersPass = true;

        // Consume the pass atomically
        await tx.update(foundersPass).set({
          status: "CONSUMED",
          consumedAt: new Date(),
          consumedByUserId: userId,
          consumedByIp: context.ipAddress || null,
          consumedByDeviceFingerprint: context.deviceFingerprint || null,
        }).where(eq(foundersPass.id, pass.id));

        await tx.insert(foundersPassEvents).values({
          passId: pass.id,
          eventType: "REDEEM_SUCCESS",
          ip: context.ipAddress || null,
          deviceFingerprint: context.deviceFingerprint || null,
          metadata: { consumedByUserId: userId },
        });
      }
    }

    if (!canActivate) {
      // If had a pass but it failed, log the failure
      if (hasFoundersPass && context.foundersPassTokenHash) {
        const [pass] = await tx
          .select()
          .from(foundersPass)
          .where(eq(foundersPass.tokenHash, context.foundersPassTokenHash));

        if (pass) {
          await tx.insert(foundersPassEvents).values({
            passId: pass.id,
            eventType: "REDEEM_FAIL",
            ip: context.ipAddress || null,
            deviceFingerprint: context.deviceFingerprint || null,
            metadata: { reason: "cap_reached_or_pass_invalid" },
          });
        }
      }

      // Cap reached, add to waitlist
      const maxPosition = await tx
        .select({ maxPos: sql<number>`COALESCE(MAX(position), 0)::int` })
        .from(waitlistEntries);

      const position = (maxPosition[0]?.maxPos || 0) + 1;

      // Update user status to waitlisted
      await tx.update(users).set({
        status: "WAITLISTED" as UserStatus,
        waitlistJoinedAt: new Date(),
        lastSignupIp: context.ipAddress,
        deviceFingerprint: context.deviceFingerprint,
      }).where(eq(users.id, userId));

      await logAccessAudit("ACTIVATION_WAITLISTED", {
        userId,
        ipAddress: context.ipAddress,
        userAgent: context.userAgent,
        deviceFingerprint: context.deviceFingerprint,
        metadata: { position, activeCount: currentActive, cap: config.maxActiveUsers },
      });

      return { activated: false, reason: "CAP_REACHED" as const, waitlistPosition: position };
    }

    // Activate the user
    await tx.update(users).set({
      status: "ACTIVE" as UserStatus,
      activatedAt: new Date(),
      lastSignupIp: context.ipAddress,
      deviceFingerprint: context.deviceFingerprint,
    }).where(eq(users.id, userId));

    // Increment the counter
    await tx
      .update(activeUserCounter)
      .set({
        count: sql`${activeUserCounter.count} + 1`,
        reservedSeatsUsed: shouldUseReservedSeat 
          ? sql`${activeUserCounter.reservedSeatsUsed} + 1`
          : activeUserCounter.reservedSeatsUsed,
        updatedAt: new Date(),
      })
      .where(eq(activeUserCounter.id, 1));

    // Check if this was the last activation (cap reached) - deactivate all remaining passes
    const newActiveCount = currentActive + 1;
    if (newActiveCount >= config.maxActiveUsers) {
      const activePasses = await tx
        .select({ id: foundersPass.id })
        .from(foundersPass)
        .where(eq(foundersPass.status, "ACTIVE"));

      if (activePasses.length > 0) {
        await tx.update(foundersPass).set({
          status: "DEACTIVATED",
          deactivatedAt: new Date(),
        }).where(eq(foundersPass.status, "ACTIVE"));

        for (const pass of activePasses) {
          await tx.insert(foundersPassEvents).values({
            passId: pass.id,
            eventType: "DEACTIVATED_GLOBAL",
            metadata: { reason: "cap_reached", activeCount: newActiveCount },
          });
        }
      }
    }

    // Consume invite code if used
    if (context.inviteCode) {
      await consumeInviteCodeInternal(tx, context.inviteCode);
    }

    await logAccessAudit("ACTIVATION_SUCCESS", {
      userId,
      ipAddress: context.ipAddress,
      userAgent: context.userAgent,
      deviceFingerprint: context.deviceFingerprint,
      metadata: { 
        usedReservedSeat: shouldUseReservedSeat,
        usedFoundersPass: usedFoundersPass,
        inviteCode: context.inviteCode,
      },
    });

    return { activated: true, reason: "SUCCESS" as const };
  });
}

// Validate an invite code
export async function validateInviteCode(code: string): Promise<InviteValidationResult> {
  const [invite] = await db
    .select()
    .from(inviteCodes)
    .where(eq(inviteCodes.code, code.toUpperCase()));

  if (!invite) {
    return { valid: false, reason: "NOT_FOUND" };
  }

  if (invite.expiresAt && new Date(invite.expiresAt) < new Date()) {
    return { valid: false, reason: "EXPIRED" };
  }

  if (invite.uses >= invite.maxUses) {
    return { valid: false, reason: "EXHAUSTED" };
  }

  return { valid: true, invite };
}

// Internal function to consume invite code (within transaction)
async function consumeInviteCodeInternal(tx: any, code: string): Promise<void> {
  await tx
    .update(inviteCodes)
    .set({
      uses: sql`${inviteCodes.uses} + 1`,
    })
    .where(eq(inviteCodes.code, code.toUpperCase()));
}

// Consume an invite code (for API use)
export async function consumeInviteCode(code: string): Promise<boolean> {
  const result = await validateInviteCode(code);
  if (!result.valid) {
    return false;
  }

  await db
    .update(inviteCodes)
    .set({
      uses: sql`${inviteCodes.uses} + 1`,
    })
    .where(eq(inviteCodes.code, code.toUpperCase()));

  return true;
}

// Create invite codes (admin function)
export async function createInviteCodes(
  count: number,
  options: {
    maxUses?: number;
    expiresAt?: Date;
    reservedSeat?: boolean;
    createdByAdminUserId?: string;
    note?: string;
  } = {}
): Promise<string[]> {
  const codes: string[] = [];

  for (let i = 0; i < count; i++) {
    const code = generateInviteCode();
    codes.push(code);

    await db.insert(inviteCodes).values({
      code,
      maxUses: options.maxUses || 1,
      expiresAt: options.expiresAt,
      reservedSeat: options.reservedSeat ?? true,
      createdByAdminUserId: options.createdByAdminUserId,
      note: options.note,
    });
  }

  await logAccessAudit("ADMIN_INVITE_CREATE", {
    userId: options.createdByAdminUserId,
    metadata: { count, codes, options },
  });

  return codes;
}

// Join waitlist
export async function joinWaitlist(
  email: string,
  options: {
    name?: string;
    referredByCode?: string;
    deviceFingerprint?: string;
    ipAddress?: string;
  } = {}
): Promise<{ success: boolean; position?: number; referralCode?: string; error?: string }> {
  const emailNormalized = normalizeEmail(email);

  // Check if already on waitlist
  const [existing] = await db
    .select()
    .from(waitlistEntries)
    .where(eq(waitlistEntries.emailNormalized, emailNormalized));

  if (existing) {
    return { 
      success: true, 
      position: existing.position, 
      referralCode: existing.referralCode || undefined 
    };
  }

  // Check if already a registered user
  const [existingUser] = await db
    .select()
    .from(users)
    .where(eq(users.emailNormalized, emailNormalized));

  if (existingUser) {
    return { success: false, error: "EMAIL_ALREADY_REGISTERED" };
  }

  // Get next position
  const [maxPos] = await db
    .select({ max: sql<number>`COALESCE(MAX(position), 0)::int` })
    .from(waitlistEntries);

  const position = (maxPos?.max || 0) + 1;
  const referralCode = generateReferralCode();

  // Validate and credit referrer
  if (options.referredByCode) {
    const [referrer] = await db
      .select()
      .from(waitlistEntries)
      .where(eq(waitlistEntries.referralCode, options.referredByCode.toUpperCase()));

    if (referrer) {
      await db
        .update(waitlistEntries)
        .set({
          referralsCount: sql`${waitlistEntries.referralsCount} + 1`,
          updatedAt: new Date(),
        })
        .where(eq(waitlistEntries.id, referrer.id));
    }
  }

  await db.insert(waitlistEntries).values({
    email,
    emailNormalized,
    name: options.name,
    status: "WAITING",
    position,
    referralCode,
    referredByCode: options.referredByCode?.toUpperCase(),
    deviceFingerprint: options.deviceFingerprint,
    signupIp: options.ipAddress,
  });

  await logAccessAudit("WAITLIST_JOIN", {
    email,
    ipAddress: options.ipAddress,
    deviceFingerprint: options.deviceFingerprint,
    metadata: { position, referredByCode: options.referredByCode },
  });

  return { success: true, position, referralCode };
}

// Get waitlist status for an email
export async function getWaitlistStatus(email: string): Promise<{
  found: boolean;
  position?: number;
  status?: WaitlistStatus;
  referralCode?: string;
  referralsCount?: number;
  inviteCode?: string;
}> {
  const emailNormalized = normalizeEmail(email);

  const [entry] = await db
    .select()
    .from(waitlistEntries)
    .where(eq(waitlistEntries.emailNormalized, emailNormalized));

  if (!entry) {
    return { found: false };
  }

  return {
    found: true,
    position: entry.position,
    status: entry.status as WaitlistStatus,
    referralCode: entry.referralCode || undefined,
    referralsCount: entry.referralsCount,
    inviteCode: entry.status === "INVITED" ? entry.inviteCodeSent || undefined : undefined,
  };
}

// Admin: Invite waitlist entry
export async function inviteWaitlistEntry(
  waitlistId: string,
  adminUserId: string
): Promise<{ success: boolean; inviteCode?: string; error?: string }> {
  const [entry] = await db
    .select()
    .from(waitlistEntries)
    .where(eq(waitlistEntries.id, waitlistId));

  if (!entry) {
    return { success: false, error: "NOT_FOUND" };
  }

  if (entry.status !== "WAITING") {
    return { success: false, error: "ALREADY_PROCESSED" };
  }

  // Create invite code for this entry
  const [inviteCode] = await createInviteCodes(1, {
    maxUses: 1,
    reservedSeat: true,
    createdByAdminUserId: adminUserId,
    note: `Waitlist invite for ${entry.email}`,
  });

  if (!inviteCode) {
    return { success: false, error: "FAILED_TO_CREATE_CODE" };
  }

  await db
    .update(waitlistEntries)
    .set({
      status: "INVITED",
      inviteCodeSent: inviteCode,
      invitedAt: new Date(),
      updatedAt: new Date(),
    })
    .where(eq(waitlistEntries.id, waitlistId));

  await logAccessAudit("WAITLIST_INVITED", {
    userId: adminUserId,
    email: entry.email,
    metadata: { waitlistId, inviteCode },
  });

  return { success: true, inviteCode };
}

// Admin: Approve a waitlisted user to become active
export async function approveWaitlistedUser(
  userId: string,
  adminUserId: string
): Promise<{ success: boolean; error?: string }> {
  const [user] = await db.select().from(users).where(eq(users.id, userId));

  if (!user) {
    return { success: false, error: "USER_NOT_FOUND" };
  }

  if (user.status !== "WAITLISTED") {
    return { success: false, error: "NOT_WAITLISTED" };
  }

  // Use reserved seat to activate
  const config = await getFoundersCapConfig();
  const [counter] = await db.select().from(activeUserCounter).where(eq(activeUserCounter.id, 1));

  if (!counter) {
    return { success: false, error: "COUNTER_ERROR" };
  }

  if (counter.reservedSeatsUsed >= config.reservedSeatsForInvites) {
    return { success: false, error: "NO_RESERVED_SEATS" };
  }

  await db.transaction(async (tx) => {
    await tx.update(users).set({
      status: "ACTIVE" as UserStatus,
      activatedAt: new Date(),
    }).where(eq(users.id, userId));

    await tx.update(activeUserCounter).set({
      count: sql`${activeUserCounter.count} + 1`,
      reservedSeatsUsed: sql`${activeUserCounter.reservedSeatsUsed} + 1`,
      updatedAt: new Date(),
    }).where(eq(activeUserCounter.id, 1));
  });

  await logAccessAudit("WAITLIST_ACCEPTED", {
    userId: adminUserId,
    metadata: { approvedUserId: userId },
  });

  return { success: true };
}

// Get waitlist entries for admin
export async function getWaitlistEntries(
  options: {
    status?: WaitlistStatus;
    limit?: number;
    offset?: number;
  } = {}
): Promise<{ entries: WaitlistEntry[]; total: number }> {
  const conditions = options.status 
    ? eq(waitlistEntries.status, options.status)
    : undefined;

  const [countResult] = await db
    .select({ count: sql<number>`count(*)::int` })
    .from(waitlistEntries)
    .where(conditions);

  const entries = await db
    .select()
    .from(waitlistEntries)
    .where(conditions)
    .orderBy(waitlistEntries.position)
    .limit(options.limit || 50)
    .offset(options.offset || 0);

  return {
    entries,
    total: countResult?.count || 0,
  };
}

// Get all invite codes for admin
export async function getInviteCodes(
  options: {
    includeExpired?: boolean;
    limit?: number;
    offset?: number;
  } = {}
): Promise<{ codes: InviteCode[]; total: number }> {
  const now = new Date();
  const conditions = options.includeExpired 
    ? undefined 
    : sql`expires_at IS NULL OR expires_at > ${now}`;

  const [countResult] = await db
    .select({ count: sql<number>`count(*)::int` })
    .from(inviteCodes)
    .where(conditions);

  const codes = await db
    .select()
    .from(inviteCodes)
    .where(conditions)
    .orderBy(sql`created_at DESC`)
    .limit(options.limit || 50)
    .offset(options.offset || 0);

  return {
    codes,
    total: countResult?.count || 0,
  };
}

