  <text x="${W / 2}" y="1565" font-family="sans-serif" font-weight="bold" font-size="40" fill="white" text-anchor="middle">Play at PackPTS.com</text>

  <text x="${W / 2}" y="1720" font-family="sans-serif" font-weight="bold" font-size="56" fill="${color}" text-anchor="middle">PACKPTS</text>
  <text x="${W / 2}" y="1850" font-family="sans-serif" font-size="22" fill="#444466" text-anchor="middle">packpts.com • The Baseball Card Challenge</text>
</svg>`;
}

function getOutputDir(date: string): string {
  const dir = path.join(OUTPUT_BASE, date);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  return dir;
}

export async function generateScoreCard(
  input: ScoreCardInput,
  assetId: string,
): Promise<ScoreCardOutput> {
  const svg = buildScoreCardSvg(input);
  const dir = getOutputDir(input.date);
  const filename = `${assetId}.png`;
  const imagePath = path.join(dir, filename);

  await sharp(Buffer.from(svg))
    .png({ quality: 90 })
    .toFile(imagePath);

  const imageUrl = `/generated/share/${input.date}/${filename}`;
  return { imagePath, imageUrl };
}

export async function generateStreakBadge(
  username: string,
  streak: number,
  date: string,
  assetId: string,
): Promise<ScoreCardOutput> {
  const svg = buildStreakBadgeSvg(username, streak, date);
  const dir = getOutputDir(date);
  const filename = `${assetId}.png`;
  const imagePath = path.join(dir, filename);

  await sharp(Buffer.from(svg))
    .png({ quality: 90 })
    .toFile(imagePath);

  const imageUrl = `/generated/share/${date}/${filename}`;
  return { imagePath, imageUrl };
}

server/videoFactory/index.ts.content:
import { db } from "../db";
import { growthContentItems, publishingQueue } from "@shared/schema";
import { eq } from "drizzle-orm";
import { validateAndPrepareImage, isPlaceholderUrl } from "./validate";
import { renderClassicCountdown, type RenderInput, type RenderOutput } from "./render";
import { getRendererForTemplate, type MultiCardRenderInput, type RenderOutput as MultiRenderOutput } from "./renderFormats";
import { generateVoiceover, buildVoiceoverText, isTTSEnabled } from "./tts";
import { getTemplate, getAvailableTemplates } from "./templates";
import fs from "fs";
import path from "path";
import { execSync } from "child_process";

const VIDEO_OUTPUT_BASE = path.resolve("public/generated/videos");

let ffmpegAvailable = false;
let ffmpegVersion = "unknown";

export function isVideoFactoryEnabled(): boolean {
  return process.env.VIDEO_FACTORY_ENABLED === "true";
}

export function isFFmpegAvailable(): boolean {
  return ffmpegAvailable;
}

export function getVideoFactoryConfig() {
  return {
    enabled: isVideoFactoryEnabled(),
    renderingAvailable: ffmpegAvailable,
    ffmpegVersion,
    ttsEnabled: isTTSEnabled(),
    availableTemplates: getAvailableTemplates(),
    outputDir: VIDEO_OUTPUT_BASE,
  };
}

export function verifyFFmpeg(): boolean {
  try {
    const result = execSync("ffmpeg -version", { encoding: "utf-8", timeout: 5000 });
    const version = result.split("\n")[0] || "unknown";
    console.log(`[VideoFactory] FFmpeg verified: ${version}`);
    ffmpegAvailable = true;
    ffmpegVersion = version;
    return true;
  } catch {
    console.error("[VideoFactory] FFmpeg not found in PATH");
    ffmpegAvailable = false;
    ffmpegVersion = "not installed";
    return false;
  }
}

function getOutputDir(date: string, contentItemId: string): string {
  const dir = path.join(VIDEO_OUTPUT_BASE, date, contentItemId);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
  return dir;
}

function resolveCardImageUrl(contentItem: any): string | null {
  const metadata = contentItem.metadata as Record<string, any> | null;
  if (!metadata) return null;

  if (metadata.asset_refs && Array.isArray(metadata.asset_refs)) {
    for (const ref of metadata.asset_refs) {
      if (ref.url && ref.type === "card_image") {
        return ref.url;
      }
    }
    for (const ref of metadata.asset_refs) {
      if (ref.url) return ref.url;
    }
  }

  if (metadata.cardImageUrl) return metadata.cardImageUrl;
  if (metadata.imageUrl) return metadata.imageUrl;

  return null;
}

export interface GenerateVideoResult {
  success: boolean;
  videoPath?: string;
  thumbnailPath?: string;
  videoUrl?: string;
  thumbnailUrl?: string;
  durationSec?: number;
  sizeBytes?: number;
  error?: string;
}

export async function generateVideoForContentItem(
  contentItemId: string,
  options?: {
    templateId?: string;
    forceRerender?: boolean;
    cardImageUrl?: string;
  }
): Promise<GenerateVideoResult> {
  if (!isVideoFactoryEnabled()) {
    return { success: false, error: "Video Factory is disabled (set VIDEO_FACTORY_ENABLED=true)" };
  }

  if (!ffmpegAvailable) {
    return { success: false, error: "FFmpeg is not available in this environment. Video rendering is disabled." };
  }

  const [contentItem] = await db.select().from(growthContentItems)
    .where(eq(growthContentItems.id, contentItemId))
    .limit(1);

  if (!contentItem) {
    return { success: false, error: `Content item ${contentItemId} not found` };
  }

  const metadata = (contentItem.metadata as Record<string, any>) || {};

  if (metadata.video_asset && !options?.forceRerender) {
    return {
      success: true,
      videoPath: metadata.video_asset.path,
      thumbnailPath: metadata.video_asset.thumbnailPath,
      videoUrl: metadata.video_asset.url,
      thumbnailUrl: metadata.video_asset.thumbnailUrl,
      durationSec: metadata.video_asset.durationSec,
      sizeBytes: metadata.video_asset.sizeBytes,
    };
  }

  const templateId = options?.templateId || metadata.render_template_id || metadata.format_id || "classic_countdown";
  const viralRenderer = getRendererForTemplate(templateId);

  const cardImageUrls = resolveAllCardImageUrls(contentItem, options?.cardImageUrl);

  if (cardImageUrls.length === 0) {
    const { url: fallbackUrl } = await findFallbackCardImage();
    if (!fallbackUrl) {
      return { success: false, error: "No card image URL found in content item metadata or fallback" };
    }
    cardImageUrls.push(fallbackUrl);
  }

  const date = new Date().toISOString().slice(0, 10);
  const outputDir = getOutputDir(date, contentItemId);

  try {
    console.log(`[VideoFactory] Starting video generation for ${contentItemId} (template: ${templateId})`);

    const maskedPaths: string[] = [];
    const tempPaths: string[] = [];

    for (let i = 0; i < cardImageUrls.length; i++) {
      const imgUrl = cardImageUrls[i];
      console.log(`[VideoFactory] Preparing card image ${i + 1}/${cardImageUrls.length}: ${imgUrl}`);
      const imageResult = await validateAndPrepareImage(imgUrl, outputDir);
      maskedPaths.push(imageResult.maskedImagePath);
      tempPaths.push(imageResult.originalPath, imageResult.maskedImagePath);
    }

    const hookText = metadata.hook || contentItem.title || "Can you name this player?";
    const answerTexts = extractAnswerTexts(metadata);
    const ctaText = metadata.cta || "Play PackPTS.com \u2022 Daily 5 Challenge";

    let voiceAudioPath: string | null = null;
    if (isTTSEnabled()) {
      const voiceText = buildVoiceoverText({ hookText, answerText: answerTexts[0] || "???", ctaText });
      voiceAudioPath = await generateVoiceover(voiceText, path.join(outputDir, "voice.mp3"));
    }

    const template = getTemplate(templateId);
    const durationSec = template?.durationSec || 12;

    let renderOutput: RenderOutput;

    if (viralRenderer) {
      const multiInput: MultiCardRenderInput = {
        cardImagePaths: maskedPaths,
        templateId,
        hookText,
        answerTexts,
        ctaText,
        outputDir,
        durationSec,
        voiceAudioPath,
        leaderboardLines: metadata.leaderboard_lines || undefined,
        eraLabel: metadata.era_label || undefined,
        extraOverlays: metadata.extra_overlays || undefined,
        width: 1080,
        height: 1920,
      };
      renderOutput = await viralRenderer(multiInput);
    } else {
      const renderInput: RenderInput = {
        cardImagePath: maskedPaths[0],
        hookText,
        answerText: answerTexts[0] || "???",
        ctaText,
        outputDir,
        templateId,
        durationSec,
        voiceAudioPath,
        width: 1080,
        height: 1920,
      };
      renderOutput = await renderClassicCountdown(renderInput);
    }

    console.log(`[VideoFactory] Render complete: ${renderOutput.videoPath} (${Math.round(renderOutput.sizeBytes / 1024)}KB)`);

    const videoUrl = `/generated/videos/${date}/${contentItemId}/output.mp4`;
    const thumbnailUrl = `/generated/videos/${date}/${contentItemId}/thumbnail.jpg`;

    const videoAsset = {
      path: renderOutput.videoPath,
      thumbnailPath: renderOutput.thumbnailPath,
      url: videoUrl,
      thumbnailUrl: thumbnailUrl,
      durationSec: renderOutput.durationSec,
      sizeBytes: renderOutput.sizeBytes,
      width: renderOutput.width,
      height: renderOutput.height,
      templateId: templateId,
      createdAt: new Date().toISOString(),
    };

    await db.update(growthContentItems).set({
      metadata: { ...metadata, video_asset: videoAsset },
      updatedAt: new Date(),
    }).where(eq(growthContentItems.id, contentItemId));

    const [queueItem] = await db.select().from(publishingQueue)
      .where(eq(publishingQueue.contentItemId, contentItemId))
      .limit(1);

    if (queueItem) {
      const queueAssets = (queueItem.assets as Record<string, any>) || {};
      await db.update(publishingQueue).set({
        assets: {
          ...queueAssets,
          video_asset: videoAsset,
        },
      }).where(eq(publishingQueue.id, queueItem.id));
    }

    try {
      for (const tp of tempPaths) {
        if (fs.existsSync(tp)) fs.unlinkSync(tp);
      }
    } catch {}

    return {
      success: true,
      videoPath: renderOutput.videoPath,
      thumbnailPath: renderOutput.thumbnailPath,
      videoUrl,
      thumbnailUrl,
      durationSec: renderOutput.durationSec,
      sizeBytes: renderOutput.sizeBytes,
    };
  } catch (err: any) {
    console.error(`[VideoFactory] Generation failed for ${contentItemId}:`, err?.message);

    const prevRetryCount = (metadata.video_error?.retry_count as number) || 0;

    await db.update(growthContentItems).set({
      metadata: {
        ...metadata,
        video_error: {
          message: err?.message,
          at: new Date().toISOString(),
          retry_count: prevRetryCount + (options?.forceRerender ? 1 : 0),
        },
      },
      updatedAt: new Date(),
    }).where(eq(growthContentItems.id, contentItemId));

    return { success: false, error: err?.message };
  }
}

function extractPlayerName(metadata: Record<string, any>): string | null {
  if (metadata.player_name) return metadata.player_name;
  if (metadata.answerText) return metadata.answerText;
  if (metadata.answer) return metadata.answer;
  return null;
}

function extractAnswerTexts(metadata: Record<string, any>): string[] {
  if (metadata.cards && Array.isArray(metadata.cards)) {
    return metadata.cards.map((c: any) => c.player || c.answer || "???");
  }
  const single = metadata.answer || extractPlayerName(metadata) || "???";
  return [single];
}

function resolveAllCardImageUrls(contentItem: any, overrideUrl?: string): string[] {
  const metadata = (contentItem.metadata as Record<string, any>) || {};

  if (overrideUrl) return [overrideUrl];

  if (metadata.cards && Array.isArray(metadata.cards)) {
    const urls = metadata.cards
      .map((c: any) => c.imageUrl || c.image_url || c.url)
      .filter((u: string) => u && !isPlaceholderUrl(u));
    if (urls.length > 0) return urls;
  }

  const singleUrl = resolveCardImageUrl(contentItem);
  if (singleUrl) return [singleUrl];

  return [];
}

async function findFallbackCardImage(): Promise<{ url: string } | { url: null }> {
  try {
    const { playableCards } = await import("@shared/schema");
    const cards = await db.select({
      id: playableCards.id,
      imageUrl: playableCards.imageUrl,
    })
      .from(playableCards)
      .where(eq(playableCards.isPlayable, true))
      .limit(10);

    for (const card of cards) {
      if (card.imageUrl && !isPlaceholderUrl(card.imageUrl)) {
        return { url: card.imageUrl };
      }
    }
  } catch {}
  return { url: null };
}

server/routes/referrals.ts.content:
import { Router, Request, Response } from "express";
import { db } from "../db";
import { referralLinks, referralAttributions, shareEvents, users, contentAssets } from "@shared/schema";
import { eq, and, sql, desc, gte } from "drizzle-orm";
import crypto from "crypto";

const router = Router();

function generateShortCode(): string {
  return crypto.randomBytes(5).toString("base64url").slice(0, 8);
}

function isAuthenticated(req: Request): boolean {
  return !!(req.session as any)?.localUserId || !!(req.session as any)?.userId;
}

function getUserId(req: Request): string | null {
  return (req.session as any)?.localUserId || (req.session as any)?.userId || null;
}

router.post("/api/referrals/create", async (req: Request, res: Response) => {
  try {
    if (!isAuthenticated(req)) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const userId = getUserId(req)!;
    const { purpose, destinationPath } = req.body;

    if (!purpose || !destinationPath) {
      return res.status(400).json({ message: "purpose and destinationPath are required" });
    }

    const validPurposes = ["INVITE", "DAILY5_CHALLENGE", "SCORE_SHARE"];
    if (!validPurposes.includes(purpose)) {
      return res.status(400).json({ message: "Invalid purpose" });
    }

    let code = generateShortCode();
    let attempts = 0;
    while (attempts < 5) {
      const existing = await db.select({ id: referralLinks.id })
        .from(referralLinks)
        .where(eq(referralLinks.code, code))
        .limit(1);
      if (existing.length === 0) break;
      code = generateShortCode();
      attempts++;
    }

    const [link] = await db.insert(referralLinks).values({
      code,
      createdByUserId: userId,
      purpose: purpose as any,
      destinationPath,
      isActive: true,
    }).returning();

    const baseUrl = `${req.protocol}://${req.get("host")}`;
    const url = `${baseUrl}/r/${link.code}`;

    return res.json({ id: link.id, code: link.code, url });
  } catch (err: any) {
    console.error("[Referral] Create error:", err?.message);
    return res.status(500).json({ message: "Failed to create referral link" });
  }
});

router.get("/r/:code", async (req: Request, res: Response) => {
  try {
    const { code } = req.params;

    const [link] = await db.select()
      .from(referralLinks)
      .where(and(eq(referralLinks.code, code), eq(referralLinks.isActive, true)))
      .limit(1);

    if (!link) {
      return res.redirect("/");
    }

    if (link.expiresAt && new Date(link.expiresAt) < new Date()) {
      return res.redirect("/");
    }

    await db.update(referralLinks)
      .set({ clickCount: sql`${referralLinks.clickCount} + 1` })
      .where(eq(referralLinks.id, link.id));

    const destination = link.destinationPath.includes("?")
      ? `${link.destinationPath}&ref=${code}`
      : `${link.destinationPath}?ref=${code}`;

    return res.redirect(destination);
  } catch (err: any) {
    console.error("[Referral] Redirect error:", err?.message);
    return res.redirect("/");
  }
});

router.post("/api/referrals/attribute", async (req: Request, res: Response) => {
  try {
    if (!isAuthenticated(req)) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const userId = getUserId(req)!;
    const { refCode, eventType } = req.body;

    if (!refCode || !eventType) {
      return res.status(400).json({ message: "refCode and eventType required" });
    }

    const validEvents = ["SIGNUP", "FIRST_MATCH", "FIRST_PURCHASE"];
    if (!validEvents.includes(eventType)) {
      return res.status(400).json({ message: "Invalid event type" });
    }

    const [link] = await db.select()
      .from(referralLinks)
      .where(and(eq(referralLinks.code, refCode), eq(referralLinks.isActive, true)))
      .limit(1);

    if (!link) {
      return res.json({ attributed: false, reason: "Link not found" });
    }

    if (link.createdByUserId === userId) {
      return res.json({ attributed: false, reason: "Cannot self-refer" });
    }

    try {
      await db.insert(referralAttributions).values({
        referralLinkId: link.id,
        invitedUserId: userId,
        eventType: eventType as any,
      });

      if (eventType === "FIRST_MATCH") {
        import("../services/referralRewards").then(({ grantReferralBonus }) => {
          grantReferralBonus(userId, "FIRST_MATCH").catch(err =>
            console.error("[Referral] Bonus grant error:", err?.message)
          );
        }).catch(() => {});
      }

      return res.json({ attributed: true });
    } catch (err: any) {
      if (err?.message?.includes("uq_referral_attribution") || err?.code === "23505") {
        return res.json({ attributed: false, reason: "Already attributed" });
      }
      throw err;
    }
  } catch (err: any) {
    console.error("[Referral] Attribution error:", err?.message);
    return res.status(500).json({ message: "Attribution failed" });
  }
});

router.get("/api/referrals/my-stats", async (req: Request, res: Response) => {
  try {
    if (!isAuthenticated(req)) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const userId = getUserId(req)!;

    const links = await db.select()
      .from(referralLinks)
      .where(eq(referralLinks.createdByUserId, userId))
      .orderBy(desc(referralLinks.createdAt));

    const totalClicks = links.reduce((sum, l) => sum + l.clickCount, 0);

    const attributions = await db.select()
      .from(referralAttributions)
      .innerJoin(referralLinks, eq(referralAttributions.referralLinkId, referralLinks.id))
      .where(eq(referralLinks.createdByUserId, userId));

    const signups = attributions.filter(a => a.referral_attributions.eventType === "SIGNUP").length;
    const firstMatches = attributions.filter(a => a.referral_attributions.eventType === "FIRST_MATCH").length;

    return res.json({
      totalLinks: links.length,
      totalClicks,
      signups,
      firstMatches,
    });
  } catch (err: any) {
    console.error("[Referral] Stats error:", err?.message);
    return res.status(500).json({ message: "Failed to get referral stats" });
  }
});

router.post("/api/share-events", async (req: Request, res: Response) => {
  try {
    if (!isAuthenticated(req)) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const userId = getUserId(req)!;
    const { shareType, target, contentAssetId, shareLinkId } = req.body;

    const validShareTypes = ["SCORE_CARD", "LEADERBOARD_CARD", "STREAK_CARD", "CHALLENGE_INVITE"];
    const validTargets = ["TIKTOK", "INSTAGRAM", "X", "DISCORD", "COPY_LINK", "NATIVE_SHARE"];

    if (!validShareTypes.includes(shareType) || !validTargets.includes(target)) {
      return res.status(400).json({ message: "Invalid shareType or target" });
    }

    const today = new Date().toISOString().slice(0, 10);
    const todayStart = new Date(today + "T00:00:00Z");
    const [countResult] = await db.select({ count: sql<number>`count(*)` })
      .from(shareEvents)
      .where(and(
        eq(shareEvents.userId, userId),
        sql`${shareEvents.createdAt} >= ${todayStart}`
      ));

    if ((countResult?.count || 0) >= 10) {
      return res.json({ logged: false, reason: "Daily share limit reached (10/day)" });
    }

    await db.insert(shareEvents).values({
      userId,
      shareType: shareType as any,
      target: target as any,
      contentAssetId,
      shareLinkId,
    });

    return res.json({ logged: true });
  } catch (err: any) {
    console.error("[ShareEvent] Error:", err?.message);
    return res.status(500).json({ message: "Failed to log share event" });
  }
});

router.get("/api/content-assets/latest", async (req: Request, res: Response) => {
  try {
    if (!isAuthenticated(req)) {
      return res.status(401).json({ message: "Unauthorized" });
    }
    const userId = getUserId(req)!;
    const { matchId, challengeId } = req.query;

    let sourceEventId: string | undefined;
    if (matchId) sourceEventId = `match_${matchId}`;
    if (challengeId) sourceEventId = `daily5_${challengeId}`;

    if (sourceEventId) {
      const assets = await db.select()
        .from(contentAssets)
        .where(and(
          eq(contentAssets.userId, userId),
          eq(contentAssets.sourceEventId, sourceEventId),
        ))
        .orderBy(desc(contentAssets.createdAt))
        .limit(5);
      return res.json({ assets });
    }

    const assets = await db.select()
      .from(contentAssets)
      .where(eq(contentAssets.userId, userId))
      .orderBy(desc(contentAssets.createdAt))
      .limit(10);

    return res.json({ assets });
  } catch (err: any) {
    console.error("[ContentAssets] Error:", err?.message);
    return res.status(500).json({ message: "Failed to get content assets" });
  }
});

export default router;

server/videoFactory/workerJob.ts.content:
import { db } from "../db";
import { growthContentItems, publishingQueue } from "@shared/schema";
import { eq, and, isNull, sql } from "drizzle-orm";
import { registerJob, type JobContext } from "../services/growth/jobRunner";
import { generateVideoForContentItem, isVideoFactoryEnabled, isFFmpegAvailable, verifyFFmpeg } from "./index";

const MAX_RENDERS_PER_RUN = 3;
const CONCURRENCY = 1;

registerJob("render_tiktok_videos", async (ctx: JobContext) => {
  if (!isVideoFactoryEnabled()) {
    return { skipped: true, reason: "Video Factory disabled (set VIDEO_FACTORY_ENABLED=true)" };
  }

  if (!isFFmpegAvailable()) {
    console.warn("[VideoFactory/Worker] FFmpeg not available at job start, re-checking...");
    const nowAvailable = verifyFFmpeg();
    if (!nowAvailable) {
      console.error("[VideoFactory/Worker] FFmpeg still unavailable. Skipping render job to prevent ENOENT failures.");
      return { skipped: true, reason: "FFmpeg is not available in this environment. Install FFmpeg to enable video rendering." };
    }
    console.log("[VideoFactory/Worker] FFmpeg recovered and available again.");
  }

  const ONE_HOUR_AGO = new Date(Date.now() - 3600000).toISOString();

  const readyItems = await db.select({
    queueId: publishingQueue.id,
    contentItemId: publishingQueue.contentItemId,
    metadata: growthContentItems.metadata,
  })
    .from(publishingQueue)
    .innerJoin(growthContentItems, eq(publishingQueue.contentItemId, growthContentItems.id))
    .where(
      and(
        eq(publishingQueue.platform, "tiktok"),
        eq(publishingQueue.status, "READY"),
        sql`(${growthContentItems.metadata}->>'video_asset') IS NULL`,
        sql`(${growthContentItems.metadata}->>'video_error') IS NULL OR
            (
              (${growthContentItems.metadata}->'video_error'->>'message') ILIKE '%enoent%'
              OR (${growthContentItems.metadata}->'video_error'->>'message') ILIKE '%ffmpeg%not%available%'
            ) OR (
              (${growthContentItems.metadata}->'video_error'->>'at') IS NOT NULL
              AND (${growthContentItems.metadata}->'video_error'->>'at') < ${ONE_HOUR_AGO}
              AND COALESCE(((${growthContentItems.metadata}->'video_error'->>'retry_count')::int), 0) < 3
            )`
      )
    )
    .limit(MAX_RENDERS_PER_RUN);

  if (readyItems.length === 0) {
    return { skipped: true, reason: "No TikTok items need rendering" };
  }

  const results: Array<{ id: string; success: boolean; error?: string; retried?: boolean; retryReason?: string }> = [];

  for (const item of readyItems) {
    if (!item.contentItemId) continue;

    try {
      const metadata = (item.metadata as Record<string, any>) || {};
      const prevError = metadata.video_error;
      const isEnoentRetry = prevError?.message?.includes("ENOENT");
      const isStaleRetry = prevError && !isEnoentRetry;
      const isRetry = !!prevError;

      if (isEnoentRetry) {
        console.log(`[VideoFactory/Worker] Auto-retrying ENOENT failure for ${item.contentItemId}`);
      } else if (isStaleRetry) {
        console.log(`[VideoFactory/Worker] Retrying stale error (>1h) for ${item.contentItemId}: ${prevError?.message}`);
      }

      console.log(`[VideoFactory/Worker] Rendering video for content item ${item.contentItemId}`);
      const result = await generateVideoForContentItem(item.contentItemId, { forceRerender: isRetry });
      results.push({
        id: item.contentItemId,
        success: result.success,
        error: result.error,
        retried: isRetry,
        retryReason: isEnoentRetry ? "ffmpeg_enoent" : isStaleRetry ? "stale_error" : undefined,
      });

      if (!result.success) {
        console.warn(`[VideoFactory/Worker] Failed: ${result.error}`);
      } else if (isRetry) {
        console.log(`[VideoFactory/Worker] Retry succeeded for ${item.contentItemId} (reason: ${isEnoentRetry ? "ffmpeg_enoent" : "stale_error"})`);
      }
    } catch (err: any) {
      console.error(`[VideoFactory/Worker] Error rendering ${item.contentItemId}:`, err?.message);
      results.push({ id: item.contentItemId, success: false, error: err?.message });
    }
  }

  const succeeded = results.filter(r => r.success).length;
  const failed = results.filter(r => !r.success).length;
  const retried = results.filter(r => r.retried).length;

  return {
    processed: results.length,
    succeeded,
    failed,
    retried,
    results,
  };
});

