import { db } from "../../db";
import { playableCards, gameSets } from "@shared/schema";
import { eq, and, sql, isNull, not } from "drizzle-orm";
import { isPlaceholderUrl, quickValidateImageUrl } from "../../videoFactory/validate";
import crypto from "crypto";

export type DifficultyTag = "easy" | "medium" | "hard";
export type EraTag = "70s" | "80s" | "90s" | "00s" | "10s" | "20s";

export interface SelectedCard {
  id: string;
  player: string;
  set: string;
  year: number;
  imageUrl: string;
  difficulty: DifficultyTag;
  era: EraTag;
  gameSetId: string;
}

const FAMOUS_PLAYERS = new Set([
  "ken griffey jr", "cal ripken jr", "nolan ryan", "derek jeter",
  "barry bonds", "mark mcgwire", "sammy sosa", "mike piazza",
  "roger clemens", "greg maddux", "tom seaver", "hank aaron",
  "willie mays", "babe ruth", "mickey mantle", "sandy koufax",
  "roberto clemente", "johnny bench", "pete rose", "mike schmidt",
  "tony gwynn", "kirby puckett", "wade boggs", "ryne sandberg",
  "jose canseco", "rickey henderson", "ozzie smith", "don mattingly",
  "darryl strawberry", "dwight gooden", "bo jackson", "frank thomas",
  "chipper jones", "randy johnson", "pedro martinez", "ivan rodriguez",
  "vladimir guerrero", "albert pujols", "ichiro suzuki", "alex rodriguez",
  "david ortiz", "mariano rivera", "mike trout", "bryce harper",
  "mookie betts", "shohei ohtani", "juan soto", "ronald acuna jr",
]);

const WELL_KNOWN_PLAYERS = new Set([
  "jose canseco", "bo jackson", "will clark", "don mattingly",
  "darryl strawberry", "dwight gooden", "orel hershiser",
  "robin yount", "paul molitor", "dave winfield", "eddie murray",
  "jack clark", "kevin mitchell", "benito santiago", "matt williams",
  "cecil fielder", "juan gonzalez", "jeff bagwell", "craig biggio",
  "john smoltz", "kenny lofton", "bernie williams", "tim salmon",
  "jay buhner", "tino martinez", "larry walker", "dante bichette",
  "andres galarraga", "moises alou", "gary sheffield",
]);

function seededRng(seed: string): () => number {
  let hash = crypto.createHash("sha256").update(seed).digest();
  let offset = 0;
  return () => {
    if (offset + 4 > hash.length) {
      hash = crypto.createHash("sha256").update(hash).digest();
      offset = 0;
    }
    const val = hash.readUInt32BE(offset) / 0xFFFFFFFF;
    offset += 4;
    return val;
  };
}

function seededShuffle<T>(arr: T[], rng: () => number): T[] {
  const shuffled = [...arr];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

export function detectEra(year: number): EraTag {
  if (year < 1980) return "70s";
  if (year < 1990) return "80s";
  if (year < 2000) return "90s";
  if (year < 2010) return "00s";
  if (year < 2020) return "10s";
  return "20s";
}

export function classifyDifficulty(playerName: string, isRookie: boolean): DifficultyTag {
  const normalized = playerName.toLowerCase().trim();
  if (FAMOUS_PLAYERS.has(normalized)) return "easy";
  if (WELL_KNOWN_PLAYERS.has(normalized) || isRookie) return "medium";
  return "hard";
}

function parseYearFromSetName(setName: string): number | null {
  const match = setName.match(/\b(19[5-9]\d|20[0-2]\d)\b/);
  return match ? parseInt(match[1], 10) : null;
}

interface CardRow {
  id: string;
  player: string | null;
  set: string | null;
  imageUrl: string | null;
  rookie: boolean | null;
  gameSetId: string;
  isPlayable: boolean;
  quarantineStatus: string;
  proposedUnplayable: boolean;
  setYear: number;
}

async function fetchEligibleCards(options?: {
  setId?: string;
  era?: EraTag;
  limit?: number;
}): Promise<CardRow[]> {
  const conditions = [
    eq(playableCards.isPlayable, true),
    eq(playableCards.quarantineStatus, "OK"),
    eq(playableCards.proposedUnplayable, false),
    not(isNull(playableCards.player)),
    not(isNull(playableCards.imageUrl)),
  ];

  if (options?.setId) {
    conditions.push(eq(playableCards.gameSetId, options.setId));
  }

  const rows = await db.select({
    id: playableCards.id,
    player: playableCards.player,
    set: playableCards.set,
    imageUrl: playableCards.imageUrl,
    rookie: playableCards.rookie,
    gameSetId: playableCards.gameSetId,
    isPlayable: playableCards.isPlayable,
    quarantineStatus: playableCards.quarantineStatus,
    proposedUnplayable: playableCards.proposedUnplayable,
    setYear: gameSets.year,
  })
    .from(playableCards)
    .innerJoin(gameSets, eq(playableCards.gameSetId, gameSets.id))
    .where(and(...conditions))
    .limit(options?.limit || 500);

  return rows.filter(r => r.imageUrl && !isPlaceholderUrl(r.imageUrl)) as CardRow[];
}

function toSelectedCard(row: CardRow): SelectedCard {
  const year = row.setYear;
  return {
    id: row.id,
    player: row.player!,
    set: row.set || "Unknown Set",
    year,
    imageUrl: row.imageUrl!,
    difficulty: classifyDifficulty(row.player!, row.rookie === true),
    era: detectEra(year),
    gameSetId: row.gameSetId,
  };
}

async function validateCardImages(cards: SelectedCard[]): Promise<SelectedCard[]> {
  const validated: SelectedCard[] = [];
  for (const card of cards) {
    const check = await quickValidateImageUrl(card.imageUrl);
    if (check.valid) {
      validated.push(card);
    } else {
      console.warn(`[CardSelector] Rejected card ${card.id} (${card.player}): ${check.error}`);
    }
  }
  return validated;
}

export async function selectCardsForFormat(
  formatId: string,
  date: string,
  options?: { setId?: string }
): Promise<SelectedCard[]> {
  const salt = process.env.GROWTH_CARD_SALT || "packpts-growth-2025";
  const seed = `${date}:${formatId}:${options?.setId || "any"}:${salt}`;
  const rng = seededRng(seed);

  const rows = await fetchEligibleCards({ setId: options?.setId, limit: 500 });
  if (rows.length === 0) return [];

  const shuffled = seededShuffle(rows, rng);
  const cards = shuffled.map(toSelectedCard);

  if (cards.length === 0) {
    console.warn(`[CardSelector] No eligible cards for format ${formatId}`);
    return [];
  }

  let selected: SelectedCard[];
  switch (formatId) {
    case "only_real_fans":
      selected = pickByDifficulty(cards, ["medium", "hard"], 1, rng);
      break;
    case "difficulty_ladder":
      selected = pickDifficultyLadder(cards, rng);
      break;
    case "memory_shock":
      selected = pickMemoryShock(cards, rng);
      break;
    case "pack_pull_drama":
      selected = pickByDifficulty(cards, ["medium", "hard"], 1, rng);
      break;
    case "leaderboard_flex":
      selected = pickByDifficulty(cards, ["easy", "medium"], 1, rng);
      break;
    case "era_wars":
      selected = pickEraWars(cards, rng);
      break;
    default:
      selected = pickByDifficulty(cards, ["medium"], 1, rng);
      break;
  }

  const validated = await validateCardImages(selected);
  if (validated.length === 0 && selected.length > 0) {
    console.warn(`[CardSelector] All ${selected.length} selected cards failed image validation for format ${formatId}`);
  }
  return validated;
}

function pickByDifficulty(
  cards: SelectedCard[],
  preferredDifficulties: DifficultyTag[],
  count: number,
  _rng: () => number
): SelectedCard[] {
  const preferred = cards.filter(c => preferredDifficulties.includes(c.difficulty));
  if (preferred.length >= count) return preferred.slice(0, count);
  return cards.slice(0, count);
}

function pickDifficultyLadder(cards: SelectedCard[], _rng: () => number): SelectedCard[] {
  const easy = cards.find(c => c.difficulty === "easy");
  const medium = cards.find(c => c.difficulty === "medium");
  const hard = cards.find(c => c.difficulty === "hard");

  const result: SelectedCard[] = [];
  if (easy) result.push(easy);
  else if (cards.length > 0) result.push(cards[0]);

  if (medium && medium.id !== result[0]?.id) result.push(medium);
  else {
    const fallback = cards.find(c => !result.find(r => r.id === c.id));
    if (fallback) result.push(fallback);
  }

  if (hard && !result.find(r => r.id === hard.id)) result.push(hard);
  else {
    const fallback = cards.find(c => !result.find(r => r.id === c.id));
    if (fallback) result.push(fallback);
  }

  return result.slice(0, 3);
}

function pickMemoryShock(cards: SelectedCard[], _rng: () => number): SelectedCard[] {
  const midTier = cards.filter(c => c.difficulty === "medium");
  if (midTier.length > 0) return [midTier[0]];
  const nonFamous = cards.filter(c => c.difficulty !== "easy");
  if (nonFamous.length > 0) return [nonFamous[0]];
  return cards.slice(0, 1);
}

function pickEraWars(cards: SelectedCard[], _rng: () => number): SelectedCard[] {
  const eras = new Map<EraTag, SelectedCard[]>();
  for (const c of cards) {
    if (!eras.has(c.era)) eras.set(c.era, []);
    eras.get(c.era)!.push(c);
  }

  const eraKeys = Array.from(eras.keys());
  if (eraKeys.length < 2) {
    return cards.slice(0, 2);
  }

  const era1 = eraKeys[0];
  const era2 = eraKeys.find(e => e !== era1)!;

  return [eras.get(era1)![0], eras.get(era2)![0]];
}

export async function getAvailableEras(): Promise<{ era: EraTag; count: number }[]> {
  const sets = await db.select({
    year: gameSets.year,
    count: sql<number>`count(*)::int`,
  })
    .from(gameSets)
    .where(eq(gameSets.isActive, true))
    .groupBy(gameSets.year);

  const eraCounts = new Map<EraTag, number>();
  for (const s of sets) {
    const era = detectEra(s.year);
    eraCounts.set(era, (eraCounts.get(era) || 0) + s.count);
  }

  return Array.from(eraCounts.entries())
    .map(([era, count]) => ({ era, count }))
    .sort((a, b) => a.era.localeCompare(b.era));
}

server/contentFactory/index.ts.content:
import { db } from "../db";
import { contentAssets, users } from "@shared/schema";
import { eq, and } from "drizzle-orm";
import { generateScoreCard, generateStreakBadge, type ScoreCardInput } from "./generateScoreCard";

const STREAK_MILESTONES = [3, 7, 14, 30];

export interface MatchFinishedEvent {
  matchId: string;
  userId: string;
  score: number;
  correctCount: number;
  totalQuestions: number;
  mode: string;
  setName?: string;
  streak?: number;
}

export interface Daily5FinishedEvent {
  challengeId: string;
  userId: string;
  score: number;
  correctCount: number;
  totalQuestions: number;
  rank?: number;
  streak?: number;
  date: string;
}

async function getUsername(userId: string): Promise<string> {
  try {
    const [user] = await db.select({ username: users.username })
      .from(users).where(eq(users.id, userId)).limit(1);
    return user?.username || "Player";
  } catch {
    return "Player";
  }
}

export async function onMatchFinished(event: MatchFinishedEvent): Promise<{ assetId: string; imageUrl: string } | null> {
  try {
    const sourceEventId = `match_${event.matchId}`;
    const date = new Date().toISOString().slice(0, 10);

    const existing = await db.select({ id: contentAssets.id })
      .from(contentAssets)
      .where(and(
        eq(contentAssets.assetType, "SCORE_CARD"),
        eq(contentAssets.userId, event.userId),
        eq(contentAssets.sourceEventId, sourceEventId),
      )).limit(1);

    if (existing.length > 0) {
      const meta = await db.select({ metadata: contentAssets.metadata, imagePath: contentAssets.imagePath })
        .from(contentAssets).where(eq(contentAssets.id, existing[0].id)).limit(1);
      return { assetId: existing[0].id, imageUrl: (meta[0]?.metadata as any)?.imageUrl || "" };
    }

    const username = await getUsername(event.userId);
    const [asset] = await db.insert(contentAssets).values({
      assetType: "SCORE_CARD",
      userId: event.userId,
      sourceEventId,
      metadata: {
        score: event.score,
        correctCount: event.correctCount,
        totalQuestions: event.totalQuestions,
        mode: event.mode,
        setName: event.setName,
        streak: event.streak,
        date,
      },
    }).returning();

    const input: ScoreCardInput = {
      username,
      score: event.score,
      correctCount: event.correctCount,
      totalQuestions: event.totalQuestions,
      mode: event.mode,
      streak: event.streak,
      setName: event.setName,
      date,
    };

    const result = await generateScoreCard(input, asset.id);

    await db.update(contentAssets).set({
      imagePath: result.imagePath,
      metadata: { ...(asset.metadata as any), imageUrl: result.imageUrl },
    }).where(eq(contentAssets.id, asset.id));

    console.log(`[ContentFactory] Score card generated: ${asset.id} for user ${event.userId}`);

    if (event.streak && STREAK_MILESTONES.includes(event.streak)) {
      await generateStreakMilestone(event.userId, event.streak, date, `match_streak_${event.matchId}`);
    }

    return { assetId: asset.id, imageUrl: result.imageUrl };
  } catch (err: any) {
    console.error("[ContentFactory] onMatchFinished error:", err?.message);
    return null;
  }
}

export async function onDaily5Finished(event: Daily5FinishedEvent): Promise<{ assetId: string; imageUrl: string } | null> {
  try {
    const sourceEventId = `daily5_${event.challengeId}`;

    const existing = await db.select({ id: contentAssets.id })
      .from(contentAssets)
      .where(and(
        eq(contentAssets.assetType, "DAILY5_RANK_CARD"),
        eq(contentAssets.userId, event.userId),
        eq(contentAssets.sourceEventId, sourceEventId),
      )).limit(1);

    if (existing.length > 0) {
      const meta = await db.select({ metadata: contentAssets.metadata })
        .from(contentAssets).where(eq(contentAssets.id, existing[0].id)).limit(1);
      return { assetId: existing[0].id, imageUrl: (meta[0]?.metadata as any)?.imageUrl || "" };
    }

    const username = await getUsername(event.userId);
    const [asset] = await db.insert(contentAssets).values({
      assetType: "DAILY5_RANK_CARD",
      userId: event.userId,
      sourceEventId,
      metadata: {
        score: event.score,
        correctCount: event.correctCount,
        totalQuestions: event.totalQuestions,
        rank: event.rank,
        streak: event.streak,
        date: event.date,
      },
    }).returning();

    const input: ScoreCardInput = {
      username,
      score: event.score,
      correctCount: event.correctCount,
      totalQuestions: event.totalQuestions,
      mode: "daily5",
      streak: event.streak,
      rank: event.rank,
      date: event.date,
    };

    const result = await generateScoreCard(input, asset.id);

    await db.update(contentAssets).set({
      imagePath: result.imagePath,
      metadata: { ...(asset.metadata as any), imageUrl: result.imageUrl },
    }).where(eq(contentAssets.id, asset.id));

    console.log(`[ContentFactory] Daily 5 rank card generated: ${asset.id} for user ${event.userId}`);

    if (event.streak && STREAK_MILESTONES.includes(event.streak)) {
      await generateStreakMilestone(event.userId, event.streak, event.date, `daily5_streak_${event.challengeId}`);
    }

    return { assetId: asset.id, imageUrl: result.imageUrl };
  } catch (err: any) {
    console.error("[ContentFactory] onDaily5Finished error:", err?.message);
    return null;
  }
}

async function generateStreakMilestone(userId: string, streak: number, date: string, sourceEventId: string): Promise<void> {
  try {
    const existing = await db.select({ id: contentAssets.id })
      .from(contentAssets)
      .where(and(
        eq(contentAssets.assetType, "STREAK_BADGE"),
        eq(contentAssets.userId, userId),
        eq(contentAssets.sourceEventId, sourceEventId),
      )).limit(1);

    if (existing.length > 0) return;

    const username = await getUsername(userId);
    const [asset] = await db.insert(contentAssets).values({
      assetType: "STREAK_BADGE",
      userId,
      sourceEventId,
      metadata: { streak, date },
    }).returning();

    const result = await generateStreakBadge(username, streak, date, asset.id);

    await db.update(contentAssets).set({
      imagePath: result.imagePath,
      metadata: { streak, date, imageUrl: result.imageUrl },
    }).where(eq(contentAssets.id, asset.id));

    console.log(`[ContentFactory] Streak badge generated: ${asset.id} for user ${userId} (${streak}-day)`);
  } catch (err: any) {
    console.error("[ContentFactory] Streak badge error:", err?.message);
  }
}

server/videoFactory/render.ts.content:
import { spawn } from "child_process";
import path from "path";
import fs from "fs";
import os from "os";
import sharp from "sharp";

const FONT_PATH = path.resolve("assets/fonts/DejaVuSans-Bold.ttf");
const FONT_REGULAR_PATH = path.resolve("assets/fonts/DejaVuSans.ttf");

export interface RenderInput {
  cardImagePath: string;
  hookText: string;
  answerText: string;
  ctaText: string;
  outputDir: string;
  templateId?: string;
  durationSec?: number;
  voiceAudioPath?: string | null;
  width?: number;
  height?: number;
}

export interface RenderOutput {
  videoPath: string;
  thumbnailPath: string;
  durationSec: number;
  width: number;
  height: number;
  sizeBytes: number;
}

function escapeDrawText(text: string): string {
  return text
    .replace(/\\/g, "\\\\\\\\")
    .replace(/'/g, "\u2019")
    .replace(/:/g, "\\\\:")
    .replace(/%/g, "\\\\%")
    .replace(/\n/g, " ");
}

async function generateBlurredBackground(
  cardImagePath: string,
  outputPath: string,
  width: number,
  height: number
): Promise<string> {
  await sharp(cardImagePath)
    .resize(width, height, { fit: "cover" })
    .blur(40)
    .modulate({ brightness: 0.4 })
    .toFile(outputPath);
  return outputPath;
}

async function resizeCardForOverlay(
  cardImagePath: string,
  outputPath: string,
  targetWidth: number,
  targetHeight: number
): Promise<{ width: number; height: number }> {
  const cardW = Math.round(targetWidth * 0.7);
  const cardH = Math.round(targetHeight * 0.6);

  const resized = await sharp(cardImagePath)
    .resize(cardW, cardH, { fit: "inside", withoutEnlargement: false })
    .png()
    .toFile(outputPath);

  return { width: resized.width || cardW, height: resized.height || cardH };
}

function runFFmpeg(args: string[]): Promise<{ stdout: string; stderr: string }> {
  return new Promise((resolve, reject) => {
    const proc = spawn("ffmpeg", args, { stdio: ["pipe", "pipe", "pipe"] });
    let stdout = "";
    let stderr = "";

    proc.stdout.on("data", (d: Buffer) => { stdout += d.toString(); });
    proc.stderr.on("data", (d: Buffer) => { stderr += d.toString(); });

    const timeout = setTimeout(() => {
      proc.kill("SIGKILL");
      reject(new Error("FFmpeg timed out after 120s"));
    }, 120000);

    proc.on("close", (code) => {
      clearTimeout(timeout);
      if (code === 0) resolve({ stdout, stderr });
      else reject(new Error(`FFmpeg exited with code ${code}: ${stderr.slice(-500)}`));
    });

    proc.on("error", (err) => {
      clearTimeout(timeout);
      reject(err);
    });
  });
}

export async function renderClassicCountdown(input: RenderInput): Promise<RenderOutput> {
  const W = input.width || 1080;
  const H = input.height || 1920;
  const duration = input.durationSec || 12;
  const outputDir = input.outputDir;

  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  const bgPath = path.join(outputDir, "bg_blurred.png");
  const cardOverlayPath = path.join(outputDir, "card_overlay.png");
  const videoPath = path.join(outputDir, "output.mp4");
  const thumbnailPath = path.join(outputDir, "thumbnail.jpg");

  await generateBlurredBackground(input.cardImagePath, bgPath, W, H);
  const cardSize = await resizeCardForOverlay(input.cardImagePath, cardOverlayPath, W, H);

  const cardX = Math.round((W - cardSize.width) / 2);
  const cardY = Math.round((H - cardSize.height) / 2) - Math.round(H * 0.02);

  const hookEsc = escapeDrawText(input.hookText);
  const answerEsc = escapeDrawText(`Answer: ${input.answerText}`);
  const ctaEsc = escapeDrawText(input.ctaText);
  const whoEsc = escapeDrawText("Who is this player?");

  const fontFile = FONT_PATH.replace(/:/g, "\\:");
  const fontRegular = FONT_REGULAR_PATH.replace(/:/g, "\\:");

  const filterParts: string[] = [];

  filterParts.push(`[0:v]loop=loop=${duration * 25}:size=1:start=0,setpts=N/25/TB,scale=${W}:${H},format=yuv420p[bg]`);
  filterParts.push(`[1:v]scale=${cardSize.width}:${cardSize.height},format=yuva420p[card]`);
  filterParts.push(`[bg][card]overlay=${cardX}:${cardY}[composed]`);

  const drawTextFilters: string[] = [];

  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='${hookEsc}':fontcolor=white:fontsize=56:` +
    `x=(w-text_w)/2:y=h*0.15:enable='between(t,0,2)':` +
    `borderw=3:bordercolor=black@0.7`
  );

  drawTextFilters.push(
    `drawtext=fontfile='${fontRegular}':text='${whoEsc}':fontcolor=white:fontsize=44:` +
    `x=(w-text_w)/2:y=h*0.12:enable='between(t,2,6)':` +
    `borderw=2:bordercolor=black@0.7`
  );

  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='3':fontcolor=#FFD700:fontsize=140:` +
    `x=(w-text_w)/2:y=(h-text_h)/2:enable='between(t,2,3)':` +
    `borderw=4:bordercolor=black@0.8`
  );
  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='2':fontcolor=#FFD700:fontsize=140:` +
    `x=(w-text_w)/2:y=(h-text_h)/2:enable='between(t,3,4)':` +
    `borderw=4:bordercolor=black@0.8`
  );
  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='1':fontcolor=#FFD700:fontsize=140:` +
    `x=(w-text_w)/2:y=(h-text_h)/2:enable='between(t,4,5)':` +
    `borderw=4:bordercolor=black@0.8`
  );

  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='${answerEsc}':fontcolor=#00FF88:fontsize=52:` +
    `x=(w-text_w)/2:y=h*0.82:enable='between(t,6,10)':` +
    `borderw=3:bordercolor=black@0.8`
  );

  drawTextFilters.push(
    `drawtext=fontfile='${fontFile}':text='${ctaEsc}':fontcolor=white:fontsize=42:` +
    `x=(w-text_w)/2:y=(h-text_h)/2:enable='between(t,10,${duration})':` +
    `borderw=3:bordercolor=black@0.7`
  );

  filterParts.push(`[composed]${drawTextFilters.join(",")}[textout]`);

  let finalLabel = "textout";

  if (input.voiceAudioPath && fs.existsSync(input.voiceAudioPath)) {
    filterParts.push(`[2:a]apad,atrim=0:${duration}[voice]`);
    finalLabel = "textout";
  }

  const filterComplex = filterParts.join(";");

  const hasVoice = !!(input.voiceAudioPath && fs.existsSync(input.voiceAudioPath));

  const ffmpegArgs: string[] = [
    "-y",
    "-i", bgPath,
    "-i", cardOverlayPath,
  ];

  if (hasVoice) {
    ffmpegArgs.push("-i", input.voiceAudioPath!);
  } else {
    ffmpegArgs.push("-f", "lavfi", "-i", "anullsrc=channel_layout=stereo:sample_rate=44100");
  }

  ffmpegArgs.push(
    "-filter_complex", filterComplex,
    "-map", `[${finalLabel}]`,
  );

  if (hasVoice) {
    ffmpegArgs.push("-map", "[voice]");
  } else {
    ffmpegArgs.push("-map", "2:a", "-shortest");
  }

  ffmpegArgs.push(
    "-c:v", "libx264",
    "-preset", "fast",
    "-crf", "23",
    "-c:a", "aac",
    "-b:a", "128k",
    "-pix_fmt", "yuv420p",
    "-t", String(duration),
    "-movflags", "+faststart",
    videoPath
  );

  console.log(`[VideoFactory/Render] Starting FFmpeg render: ${W}x${H}, ${duration}s`);
  const startTime = Date.now();

  try {
    await runFFmpeg(ffmpegArgs);
  } catch (err: any) {
    console.error(`[VideoFactory/Render] FFmpeg failed:`, err?.message);
    throw new Error(`FFmpeg render failed: ${err?.message}`);
  }

  const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
  console.log(`[VideoFactory/Render] Render complete in ${elapsed}s`);

  await runFFmpeg([
    "-y",
    "-i", videoPath,
    "-ss", "1",
    "-vframes", "1",
    "-q:v", "2",
    thumbnailPath,
  ]);

  const stats = fs.statSync(videoPath);

  try {
    if (fs.existsSync(bgPath)) fs.unlinkSync(bgPath);
    if (fs.existsSync(cardOverlayPath)) fs.unlinkSync(cardOverlayPath);
  } catch {}

  return {
    videoPath,
    thumbnailPath,
    durationSec: duration,
    width: W,
    height: H,
    sizeBytes: stats.size,
  };
}

server/jobs/computeFlywheelRollups.ts.content:
import { db } from "../db";
import { 
  gameSessionsTable, shareEvents, referralLinks, referralAttributions,
  userGrowthRollups, globalGrowthRollups, users, ledgerEntries
} from "@shared/schema";
import { eq, and, sql, gte, lt, count } from "drizzle-orm";

export async function computeFlywheelRollups(dateStr?: string): Promise<{
  date: string;
  dau: number;
  matches: number;
  daily5Entries: number;
  shares: number;
  invites: number;
  signupsFromInvites: number;
  kFactor: number;
  userRollups: number;
}> {
  const date = dateStr || (() => {
    const d = new Date();
    d.setUTCDate(d.getUTCDate() - 1);
    return d.toISOString().slice(0, 10);
  })();

  const dayStart = new Date(`${date}T00:00:00Z`);
  const dayEnd = new Date(`${date}T23:59:59.999Z`);

  console.log(`[FlywheelRollup] Computing rollups for ${date}`);

  const dayStartStr = dayStart.toISOString();
  const dayEndStr = new Date(dayEnd.getTime() + 1).toISOString();

  const matchesResult = await db.select({
    userId: gameSessionsTable.userId,
    matchCount: sql<number>`count(*)`,
  })
    .from(gameSessionsTable)
    .where(and(
      gte(gameSessionsTable.completedAt, dayStartStr),
      lt(gameSessionsTable.completedAt, dayEndStr),
      eq(gameSessionsTable.status, "completed"),
    ))
    .groupBy(gameSessionsTable.userId);

  const sharesResult = await db.select({
    userId: shareEvents.userId,
    shareCount: sql<number>`count(*)`,
  })
    .from(shareEvents)
    .where(and(
      gte(shareEvents.createdAt, dayStart),
      lt(shareEvents.createdAt, new Date(dayEnd.getTime() + 1)),
    ))
    .groupBy(shareEvents.userId);

  const invitesResult = await db.select({
    userId: referralLinks.createdByUserId,
    inviteCount: sql<number>`count(distinct ${referralAttributions.invitedUserId})`,
  })
    .from(referralAttributions)
    .innerJoin(referralLinks, eq(referralAttributions.referralLinkId, referralLinks.id))
    .where(and(
      gte(referralAttributions.createdAt, dayStart),
      lt(referralAttributions.createdAt, new Date(dayEnd.getTime() + 1)),
    ))
    .groupBy(referralLinks.createdByUserId);

  const signupInvites = await db.select({
    cnt: sql<number>`count(*)`,
  })
    .from(referralAttributions)
    .where(and(
      eq(referralAttributions.eventType, "SIGNUP"),
      gte(referralAttributions.createdAt, dayStart),
      lt(referralAttributions.createdAt, new Date(dayEnd.getTime() + 1)),
    ));

  const activeUsers = new Set<string>();
  matchesResult.forEach(r => { if (r.userId) activeUsers.add(r.userId); });
  sharesResult.forEach(r => activeUsers.add(r.userId));

  const matchMap = new Map(matchesResult.map(r => [r.userId, Number(r.matchCount)]));
  const shareMap = new Map(sharesResult.map(r => [r.userId, Number(r.shareCount)]));
  const inviteMap = new Map(invitesResult.map(r => [r.userId, Number(r.inviteCount)]));

  const allUserIds = new Set(
    Array.from(matchMap.keys())
      .concat(Array.from(shareMap.keys()))
      .concat(Array.from(inviteMap.keys()))
  );

  let userRollupCount = 0;
  for (const userId of Array.from(allUserIds)) {
    if (!userId) continue;
    const values = {
      userId,
      date,
      matchesPlayed: matchMap.get(userId) || 0,
      daily5Played: 0,
      correctAnswers: 0,
      packptsEarned: 0,
      packptsSpent: 0,
      sharesCount: shareMap.get(userId) || 0,
      referralsSent: inviteMap.get(userId) || 0,
      invitedSignups: 0,
    };

    await db.insert(userGrowthRollups)
      .values(values)
      .onConflictDoUpdate({
        target: [userGrowthRollups.userId, userGrowthRollups.date],
        set: {
          matchesPlayed: sql`excluded.matches_played`,
          sharesCount: sql`excluded.shares_count`,
          referralsSent: sql`excluded.referrals_sent`,
        },
      });
    userRollupCount++;
  }

  const totalMatches = Array.from(matchMap.values()).reduce((s, v) => s + v, 0);
  const totalShares = Array.from(shareMap.values()).reduce((s, v) => s + v, 0);
  const totalInvites = Array.from(inviteMap.values()).reduce((s, v) => s + v, 0);
  const totalSignupsFromInvites = Number(signupInvites[0]?.cnt || 0);

  const dau = activeUsers.size;
  const kFactor = dau > 0 && totalInvites > 0
    ? (totalInvites / dau) * (totalSignupsFromInvites / Math.max(totalInvites, 1))
    : 0;

  await db.insert(globalGrowthRollups)
    .values({
      date,
      dau,
      matches: totalMatches,
      daily5Entries: 0,
      shares: totalShares,
      invites: totalInvites,
      signupsFromInvites: totalSignupsFromInvites,
      kFactorEstimate: Math.round(kFactor * 1000) / 1000,
    })
    .onConflictDoUpdate({
      target: [globalGrowthRollups.date],
      set: {
        dau: sql`excluded.dau`,
        matches: sql`excluded.matches`,
        shares: sql`excluded.shares`,
        invites: sql`excluded.invites`,
        signupsFromInvites: sql`excluded.signups_from_invites`,
        kFactorEstimate: sql`excluded.k_factor_estimate`,
      },
    });

  console.log(`[FlywheelRollup] Done for ${date}: DAU=${dau}, matches=${totalMatches}, shares=${totalShares}, invites=${totalInvites}, K=${kFactor.toFixed(3)}, userRollups=${userRollupCount}`);

  return {
    date,
    dau,
    matches: totalMatches,
    daily5Entries: 0,
    shares: totalShares,
    invites: totalInvites,
    signupsFromInvites: totalSignupsFromInvites,
    kFactor,
    userRollups: userRollupCount,
  };
}

server/videoFactory/validate.ts.content:
import sharp from "sharp";
import fs from "fs";
import path from "path";
import os from "os";
import https from "https";
import http from "http";

const PLACEHOLDER_PATTERNS = [
  /silhouette/i,
  /placeholder/i,
  /default\.(jpg|png|gif|webp)/i,
  /example\.(jpg|png|gif|webp)/i,
  /no[_-]?image/i,
  /missing/i,
  /blank\.(jpg|png)/i,
];

const MIN_IMAGE_SIZE_BYTES = 8 * 1024;
const MAX_IMAGE_SIZE_BYTES = 10 * 1024 * 1024;
const MIN_IMAGE_WIDTH = 200;
const MIN_IMAGE_HEIGHT = 200;
const DOWNLOAD_TIMEOUT_MS = 15000;

export interface ValidationResult {
  valid: boolean;
  error?: string;
}

export function isPlaceholderUrl(url: string): boolean {
  for (const pattern of PLACEHOLDER_PATTERNS) {
    if (pattern.test(url)) return true;
  }
  return false;
}

export async function quickValidateImageUrl(url: string): Promise<ValidationResult> {
  if (!url || typeof url !== "string") {
    return { valid: false, error: "No image URL provided" };
  }

  if (isPlaceholderUrl(url)) {
    return { valid: false, error: `Rejected placeholder/silhouette URL: ${url}` };
  }

  try {
    const parsedUrl = new URL(url);
    if (!["http:", "https:"].includes(parsedUrl.protocol)) {
      return { valid: false, error: `Invalid protocol: ${parsedUrl.protocol}` };
    }
  } catch {
    return { valid: false, error: `Invalid URL: ${url}` };
  }

  return doHeadCheck(url, 3);
}

function doHeadCheck(url: string, maxRedirects: number): Promise<ValidationResult> {
  return new Promise((resolve) => {
    const timeout = setTimeout(() => {
      resolve({ valid: false, error: "Image URL check timed out (10s)" });
    }, 10000);

    const protocol = url.startsWith("https") ? https : http;
    const req = protocol.request(url, { method: "HEAD", timeout: 10000 }, (res) => {
      clearTimeout(timeout);

      if (res.statusCode && res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        if (maxRedirects <= 0) {
          resolve({ valid: false, error: "Too many redirects" });
          return;
        }
        const redirectUrl = res.headers.location;
        if (isPlaceholderUrl(redirectUrl)) {
          resolve({ valid: false, error: `Redirect leads to placeholder: ${redirectUrl}` });
          return;
        }
        doHeadCheck(redirectUrl, maxRedirects - 1).then(resolve);
        return;
      }

      if (res.statusCode !== 200) {
        resolve({ valid: false, error: `Image returned HTTP ${res.statusCode}` });
        return;
      }

      const contentType = res.headers["content-type"] || "";
      if (!contentType.startsWith("image/")) {
        resolve({ valid: false, error: `Not an image (content-type: ${contentType})` });
        return;
      }

      const contentLength = parseInt(res.headers["content-length"] || "0", 10);
      if (contentLength > 0 && contentLength < MIN_IMAGE_SIZE_BYTES) {
        resolve({ valid: false, error: `Image too small (${contentLength} bytes) -- likely a placeholder/silhouette` });
        return;
      }

      resolve({ valid: true });
    });

    req.on("error", (err) => {
      clearTimeout(timeout);
      resolve({ valid: false, error: `Image URL check failed: ${err.message}` });
    });

    req.on("timeout", () => {
      clearTimeout(timeout);
      req.destroy();
      resolve({ valid: false, error: "Image URL check timed out" });
    });

    req.end();
  });
}

export async function deepValidateImageUrl(url: string): Promise<ValidationResult> {
  const quickResult = await quickValidateImageUrl(url);
  if (!quickResult.valid) return quickResult;

  try {
    const response = await new Promise<Buffer>((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error("Download timed out")), 15000);
      const protocol = url.startsWith("https") ? https : http;

      const makeRequest = (reqUrl: string, redirectsLeft: number) => {
        protocol.get(reqUrl, (res) => {
          if (res.statusCode && res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
            if (redirectsLeft <= 0) { reject(new Error("Too many redirects")); return; }
            makeRequest(res.headers.location, redirectsLeft - 1);
            return;
          }
          if (res.statusCode !== 200) { reject(new Error(`HTTP ${res.statusCode}`)); return; }
          const chunks: Buffer[] = [];
          res.on("data", (chunk) => chunks.push(chunk));
          res.on("end", () => { clearTimeout(timeout); resolve(Buffer.concat(chunks)); });
          res.on("error", (err) => { clearTimeout(timeout); reject(err); });
        }).on("error", (err) => { clearTimeout(timeout); reject(err); });
      };

      makeRequest(url, 3);
    });

    if (response.length < MIN_IMAGE_SIZE_BYTES) {
      return { valid: false, error: `Image too small (${response.length} bytes)` };
    }

    const metadata = await sharp(response).metadata();
    if (!metadata.width || !metadata.height) {
      return { valid: false, error: "Could not read image dimensions" };
    }
    if (metadata.width < MIN_IMAGE_WIDTH || metadata.height < MIN_IMAGE_HEIGHT) {
      return { valid: false, error: `Image too small (${metadata.width}x${metadata.height}), minimum ${MIN_IMAGE_WIDTH}x${MIN_IMAGE_HEIGHT}` };
    }

    return { valid: true };
  } catch (err: any) {
    return { valid: false, error: `Deep image validation failed: ${err.message}` };
  }
}

export async function downloadImageToTemp(url: string): Promise<{ path: string; sizeBytes: number }> {
  const ext = path.extname(new URL(url).pathname) || ".jpg";
  const tmpPath = path.join(os.tmpdir(), `vf_${Date.now()}_${Math.random().toString(36).slice(2)}${ext}`);

  return new Promise((resolve, reject) => {
    const protocol = url.startsWith("https") ? https : http;
    const timeout = setTimeout(() => {
      reject(new Error(`Image download timed out after ${DOWNLOAD_TIMEOUT_MS}ms`));
    }, DOWNLOAD_TIMEOUT_MS);

    const req = protocol.get(url, { timeout: DOWNLOAD_TIMEOUT_MS }, (res) => {
      if (res.statusCode && res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        clearTimeout(timeout);
        downloadImageToTemp(res.headers.location).then(resolve).catch(reject);
        return;
      }

      if (res.statusCode !== 200) {
        clearTimeout(timeout);
        reject(new Error(`HTTP ${res.statusCode} downloading image`));
        return;
      }

      const file = fs.createWriteStream(tmpPath);
      let totalBytes = 0;

      res.on("data", (chunk: Buffer) => {
        totalBytes += chunk.length;
        if (totalBytes > MAX_IMAGE_SIZE_BYTES) {
          clearTimeout(timeout);
          file.destroy();
          fs.unlinkSync(tmpPath);
          reject(new Error(`Image too large (>${MAX_IMAGE_SIZE_BYTES / 1024 / 1024}MB)`));
        }
      });

      res.pipe(file);

      file.on("finish", () => {
        clearTimeout(timeout);
        file.close(() => resolve({ path: tmpPath, sizeBytes: totalBytes }));
      });

      file.on("error", (err) => {
        clearTimeout(timeout);
        fs.unlinkSync(tmpPath);
        reject(err);
      });
    });

    req.on("error", (err) => {
      clearTimeout(timeout);
      reject(err);
    });

    req.on("timeout", () => {
      clearTimeout(timeout);
      req.destroy();
      reject(new Error("Request timed out"));
    });
  });
}

export async function verifyImageDimensions(imagePath: string): Promise<{ width: number; height: number }> {
  const meta = await sharp(imagePath).metadata();
  if (!meta.width || !meta.height) {
    throw new Error("Cannot read image dimensions");
  }
  if (meta.width < MIN_IMAGE_WIDTH || meta.height < MIN_IMAGE_HEIGHT) {
    throw new Error(`Image too small: ${meta.width}x${meta.height} (min ${MIN_IMAGE_WIDTH}x${MIN_IMAGE_HEIGHT})`);
  }
  return { width: meta.width, height: meta.height };
}

export async function maskCardImage(
  inputPath: string,
  outputPath: string,
  options?: { topBandPercent?: number; bottomBandPercent?: number }
): Promise<string> {
  const topPct = options?.topBandPercent ?? 18;
  const bottomPct = options?.bottomBandPercent ?? 22;

  const meta = await sharp(inputPath).metadata();
  if (!meta.width || !meta.height) {
    throw new Error("Cannot read image dimensions for masking");
  }

  const topBandHeight = Math.round(meta.height * (topPct / 100));
  const bottomBandHeight = Math.round(meta.height * (bottomPct / 100));

  const topOverlay = Buffer.from(
    `<svg width="${meta.width}" height="${topBandHeight}">
      <defs>
        <linearGradient id="topGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" style="stop-color:black;stop-opacity:0.95"/>
          <stop offset="100%" style="stop-color:black;stop-opacity:0.7"/>
        </linearGradient>
      </defs>
      <rect width="${meta.width}" height="${topBandHeight}" fill="url(#topGrad)"/>
    </svg>`
  );

  const bottomOverlay = Buffer.from(
    `<svg width="${meta.width}" height="${bottomBandHeight}">
      <defs>
        <linearGradient id="botGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" style="stop-color:black;stop-opacity:0.7"/>
          <stop offset="100%" style="stop-color:black;stop-opacity:0.95"/>
        </linearGradient>
      </defs>
      <rect width="${meta.width}" height="${bottomBandHeight}" fill="url(#botGrad)"/>
    </svg>`
  );

  await sharp(inputPath)
    .composite([
      { input: topOverlay, top: 0, left: 0 },
      { input: bottomOverlay, top: meta.height - bottomBandHeight, left: 0 },
    ])
    .toFile(outputPath);

  return outputPath;
}

export async function validateAndPrepareImage(
  imageUrl: string,
  outputDir: string
): Promise<{ maskedImagePath: string; originalPath: string; width: number; height: number }> {
  if (isPlaceholderUrl(imageUrl)) {
    throw new Error(`Rejected placeholder image URL: ${imageUrl}`);
  }

  const { path: downloadedPath, sizeBytes } = await downloadImageToTemp(imageUrl);

  try {
    if (sizeBytes < MIN_IMAGE_SIZE_BYTES) {
      throw new Error(`Image too small (${sizeBytes} bytes, min ${MIN_IMAGE_SIZE_BYTES} bytes) — likely a placeholder`);
    }

    const { width, height } = await verifyImageDimensions(downloadedPath);

    const maskedPath = path.join(outputDir, `maskedCard_${Date.now()}.png`);
    await maskCardImage(downloadedPath, maskedPath);

    return { maskedImagePath: maskedPath, originalPath: downloadedPath, width, height };
  } catch (err) {
    try { fs.unlinkSync(downloadedPath); } catch {}
    throw err;
  }
}

server/services/referralRewards.ts.content:
import { db } from "../db";
import { wallets, ledgerEntries, referralAttributions, referralLinks } from "@shared/schema";
import { eq, and, sql, gte } from "drizzle-orm";
import { bucketService } from "./bucketService";

const REFERRAL_BONUS_POINTS = 50;
const DAILY_REFERRAL_BONUS_CAP = 500;

export async function grantReferralBonus(invitedUserId: string, eventType: "FIRST_MATCH"): Promise<{ granted: boolean; reason?: string }> {
  try {
    const [attribution] = await db.select()
      .from(referralAttributions)
      .where(and(
        eq(referralAttributions.invitedUserId, invitedUserId),
        eq(referralAttributions.eventType, eventType),
      ))
      .limit(1);

    if (!attribution) {
      return { granted: false, reason: "no_attribution" };
    }

    const [link] = await db.select()
      .from(referralLinks)
      .where(eq(referralLinks.id, attribution.referralLinkId))
      .limit(1);

    if (!link) {
      return { granted: false, reason: "no_link" };
    }

    const referrerId = link.createdByUserId;
    const idempotencyKey = `referral_bonus:${referrerId}:${invitedUserId}:${eventType}`;

    return await db.transaction(async (tx) => {
      const existing = await tx.select({ id: ledgerEntries.id })
        .from(ledgerEntries)
        .where(eq(ledgerEntries.idempotencyKey, idempotencyKey))
        .limit(1);

      if (existing.length > 0) {
        return { granted: false, reason: "already_granted" };
      }

      const todayStart = new Date();
      todayStart.setUTCHours(0, 0, 0, 0);

      let [wallet] = await tx.select()
        .from(wallets)
        .where(eq(wallets.userId, referrerId))
        .for("update")
        .limit(1);

      if (!wallet) {
        const [newWallet] = await tx.insert(wallets).values({
          userId: referrerId,
          balance: 0,
          lifetimeEarned: 0,
          lifetimeSpent: 0,
          status: "active",
        }).returning();
        wallet = newWallet;
      }

      if (wallet.status !== "active") {
        return { granted: false, reason: "wallet_inactive" };
      }

      const todayBonuses = await tx.select({
        total: sql<number>`COALESCE(SUM(${ledgerEntries.amount}), 0)`,
      })
        .from(ledgerEntries)
        .where(and(
          eq(ledgerEntries.walletId, wallet.id),
          eq(ledgerEntries.source, "referral"),
          gte(ledgerEntries.createdAt, todayStart),
        ));

      const todayTotal = Number(todayBonuses[0]?.total || 0);
      if (todayTotal >= DAILY_REFERRAL_BONUS_CAP) {
        return { granted: false, reason: "daily_cap_reached" };
      }

      const newBalance = wallet.balance + REFERRAL_BONUS_POINTS;

      const [entry] = await tx.insert(ledgerEntries).values({
        walletId: wallet.id,
        entryType: "EARN",
        amount: REFERRAL_BONUS_POINTS,
        balanceAfter: newBalance,
        reason: `Referral bonus: invited user completed first match`,
        source: "referral",
        eventType: "referral_first_match",
        refType: "referral",
        refId: invitedUserId,
        metadata: {
          invitedUserId,
          attributionId: attribution.id,
          referralLinkId: link.id,
        },
        idempotencyKey,
      }).returning();

      await tx.update(wallets).set({
        balance: newBalance,
        lifetimeEarned: wallet.lifetimeEarned + REFERRAL_BONUS_POINTS,
        updatedAt: new Date(),
      }).where(eq(wallets.id, wallet.id));

      await bucketService.createBucket(
        referrerId,
        REFERRAL_BONUS_POINTS,
        "BONUS",
        entry.id,
        {
          source: "referral_bonus",
          invitedUserId,
          eventType,
        },
        undefined,
        tx,
      );

      console.log(`[ReferralRewards] Granted ${REFERRAL_BONUS_POINTS} pts to ${referrerId} for referring ${invitedUserId}`);
      return { granted: true };
    });
  } catch (err: any) {
    console.error("[ReferralRewards] Error:", err?.message);
    return { granted: false, reason: "error" };
  }
}
